// questions_extra.js — 追加問題 g1048–g1107 (60問)
// 時制・冠詞・前置詞・関係詞・比較・仮定法・動名詞・受動態・使役・分詞など
DATA.push(
  { id: "g1048", diff: "lv2", axis: "tense", tags: ["eiken3", "present_perfect"], stem: "She ___ to Paris twice.", ja: "彼女はパリに2回行ったことがある。", answer: "has been", choices: ["has been", "went", "goes", "had been", "was"], expl: "「2回行ったことがある」は経験を表す現在完了形。have been to + 場所＝〜へ行ったことがある。", rule: "現在完了（経験）have + 過去分詞", kp: ["経験のhave been to", "twiceなどの経験回数と現在完了"] },
  { id: "g1049", diff: "lv2", axis: "form", tags: ["eiken3", "articles"], stem: "I saw ___ elephant at the zoo yesterday.", ja: "昨日、動物園でゾウを1頭見た。", answer: "an", choices: ["an", "a", "the", "one", "some"], expl: "elephantは母音（e）で始まるので不定冠詞はan。初出の単数可算名詞には不定冠詞をつける。", rule: "不定冠詞 a / an の使い分け（母音・子音）", kp: ["母音で始まる語の前はan", "子音で始まる語の前はa"] },
  { id: "g1050", diff: "lv2", axis: "vocab", tags: ["eiken3", "preposition"], stem: "He arrived ___ the airport two hours before departure.", ja: "彼は出発の2時間前に空港に到着した。", answer: "at", choices: ["at", "in", "to", "on", "into"], expl: "arriveの後の前置詞は地点にはat、広い場所（国・都市）にはin。airportは特定の地点なのでat。", rule: "arrive at（地点）vs arrive in（広い場所）", kp: ["arrive at + 特定の場所", "arrive in + 都市・国"] },
  { id: "g1051", diff: "lv2", axis: "form", tags: ["eiken3", "relative"], stem: "The woman ___ lives next door is a nurse.", ja: "隣に住んでいる女性は看護師です。", answer: "who", choices: ["who", "which", "whose", "whom", "what"], expl: "先行詞がthe woman（人）で、関係節内で主語の役割をするのでwho。", rule: "主格の関係代名詞 who（人）/ which（物）", kp: ["先行詞が人 → who", "先行詞が物 → which"] },
  { id: "g1052", diff: "lv2", axis: "tense", tags: ["eiken3", "past_progressive"], stem: "I ___ TV when she called me.", ja: "彼女が電話してきたとき、私はテレビを見ていた。", answer: "was watching", choices: ["was watching", "watched", "watch", "am watching", "had watched"], expl: "when she calledが過去の一時点。そのとき進行中だった動作には過去進行形（was + -ing）を使う。", rule: "過去進行形 was/were + -ing", kp: ["whenで始まる過去の一時点と進行形", "過去の継続中の動作はwas/were + -ing"] },
  { id: "g1053", diff: "lv2", axis: "form", tags: ["eiken3", "comparison"], stem: "Mt. Fuji is ___ mountain in Japan.", ja: "富士山は日本で最も高い山です。", answer: "the highest", choices: ["the highest", "higher", "high", "most high", "the most high"], expl: "3つ以上の比較でthe + 最上級（-est）を使う。tallやhighのように短い形容詞は-estで最上級を作る。", rule: "最上級 the + -est（短い形容詞）", kp: ["最上級はtheをつける", "1・2音節の形容詞は-est形"] },
  { id: "g1054", diff: "lv3", axis: "form", tags: ["eiken2", "subjunctive"], stem: "If I ___ you, I would study harder.", ja: "もし私があなたなら、もっと一生懸命勉強するのに。", answer: "were", choices: ["were", "was", "am", "be", "would be"], expl: "現実に反する仮定（仮定法過去）では、be動詞はすべての人称でwereを使う。", rule: "仮定法過去 If + S + were / 動詞の過去形", kp: ["仮定法過去のbe動詞はwere（全人称）", "現在の事実に反する仮定"] },
  { id: "g1055", diff: "lv3", axis: "form", tags: ["eiken2", "gerund"], stem: "She enjoys ___ classical music in the evening.", ja: "彼女は夜にクラシック音楽を聴くのを楽しんでいる。", answer: "listening to", choices: ["listening to", "to listen to", "listen to", "listened to", "to listening"], expl: "enjoyの後には動名詞（-ing形）が続く。enjoyの後に不定詞は来ない。", rule: "動名詞のみを目的語にとる動詞（enjoy, finish, mind など）", kp: ["enjoy + 動名詞（-ing）", "enjoyの後にto不定詞は不可"] },
  { id: "g1056", diff: "lv3", axis: "form", tags: ["eiken2", "passive"], stem: "This novel ___ by millions of readers around the world.", ja: "この小説は世界中で何百万もの読者に読まれている。", answer: "is read", choices: ["is read", "reads", "is reading", "read", "has read"], expl: "主語This novelは読む側でなく読まれる側。現在の事実を表す受動態はis + 過去分詞。", rule: "受動態 be動詞 + 過去分詞", kp: ["受動態はbe + 過去分詞", "主語が動作を受ける立場"] },
  { id: "g1057", diff: "lv3", axis: "tense", tags: ["eiken2", "past_perfect"], stem: "By the time he arrived, she ___ already left.", ja: "彼が到着したとき、彼女はすでに出発していた。", answer: "had", choices: ["had", "has", "have", "was", "did"], expl: "by the timeの節（彼が到着した）よりもさらに前の出来事には過去完了形（had + 過去分詞）を使う。", rule: "過去完了 had + 過去分詞（過去のある時点より前の出来事）", kp: ["by the time + 過去形 → 過去完了", "過去完了は過去のある時点より前を表す"] },
  { id: "g1058", diff: "lv3", axis: "vocab", tags: ["eiken2", "preposition", "fixed_phrase"], stem: "She is very interested ___ learning Japanese culture.", ja: "彼女は日本文化を学ぶことに非常に興味がある。", answer: "in", choices: ["in", "at", "for", "about", "on"], expl: "be interested in〜で「〜に興味がある」という固定表現。前置詞inの後は名詞または動名詞。", rule: "be interested in + 名詞 / 動名詞", kp: ["be interested in は固定表現", "inの後は名詞か動名詞"] },
  { id: "g1059", diff: "lv3", axis: "form", tags: ["eiken2", "causative"], stem: "She had the mechanic ___ her car before the trip.", ja: "彼女は旅行前に整備士に車を点検させた。", answer: "check", choices: ["check", "to check", "checking", "checked", "to checking"], expl: "have + O + 動詞の原形（使役）で「Oに〜させる」。目的語が人の場合は動詞の原形が続く。", rule: "使役動詞 have + O + 原形（人に〜させる）", kp: ["have + 人 + 原形 = 〜させる", "目的語が物の場合はhave + 物 + 過去分詞"] },
  { id: "g1060", diff: "lv3", axis: "logic", tags: ["eiken2", "conjunction"], stem: "___ he was tired, he continued working until midnight.", ja: "疲れていたにもかかわらず、彼は深夜まで働き続けた。", answer: "Although", choices: ["Although", "Because", "If", "Since", "Unless"], expl: "前半（疲れていた）と後半（働き続けた）は逆接の関係。逆接の接続詞はAlthough（〜にもかかわらず）。", rule: "逆接の接続詞 although / even though", kp: ["although＝〜にもかかわらず（逆接）", "because＝〜なので（理由）との混同に注意"] },
  { id: "g1061", diff: "lv3", axis: "form", tags: ["eiken2", "modal"], stem: "You ___ not smoke inside the building. It is strictly prohibited.", ja: "建物内での喫煙は禁止されています。", answer: "must", choices: ["must", "should", "might", "can", "would"], expl: "must not は強い禁止を表す。should notは「すべきでない」という助言。strictly prohibitedとの文脈からmust notが適切。", rule: "must not（禁止）vs should not（助言）", kp: ["must not = 禁止（〜してはならない）", "should not = 〜すべきでない"] },
  { id: "g1062", diff: "lv4", axis: "form", tags: ["eikenpre1", "inversion"], stem: "Not only ___ the first prize, but he also received a special award.", ja: "彼は1位を獲得しただけでなく、特別賞も受賞した。", answer: "did he win", choices: ["did he win", "he won", "he did win", "won he", "has he win"], expl: "Not onlyが文頭に来るとき、主語と助動詞は倒置（did he win）する。", rule: "否定副詞句が文頭に来ると主語・助動詞が倒置される", kp: ["Not only...but also の倒置形", "否定表現が文頭 → 疑問文の語順"] },
  { id: "g1063", diff: "lv4", axis: "tense", tags: ["eikenpre1", "future_perfect"], stem: "By next April, she ___ at this company for ten years.", ja: "来年4月までに、彼女はこの会社に10年間勤めたことになる。", answer: "will have worked", choices: ["will have worked", "will work", "has worked", "will be working", "would work"], expl: "by next Aprilは未来の期限。その時点で完了している動作には未来完了形（will have + 過去分詞）を使う。", rule: "未来完了 will have + 過去分詞（未来の時点での完了）", kp: ["by + 未来の時点 → 未来完了", "will have + 過去分詞"] },
  { id: "g1064", diff: "lv4", axis: "form", tags: ["eikenpre1", "subjunctive_present"], stem: "It is essential that every employee ___ the safety manual.", ja: "すべての従業員が安全マニュアルを読むことが不可欠だ。", answer: "read", choices: ["read", "reads", "reading", "to read", "should reads"], expl: "It is essential that節（要求・主張・提案・義務を示す形容詞に続くthat節）では、動詞は主語に関わらず原形（仮定法現在）を使う。", rule: "that節の仮定法現在（要求・義務を示す形容詞 + that + S + 動詞の原形）", kp: ["essential / necessary / important + that + 動詞の原形", "三単現のsは不要"] },
  { id: "g1065", diff: "lv4", axis: "logic", tags: ["eikenpre1", "participle"], stem: "___ from above, the ancient ruins formed a perfect circle.", ja: "上から見ると、その古代遺跡は完全な円を形成していた。", answer: "Seen", choices: ["Seen", "Seeing", "To see", "Having seen", "See"], expl: "主語the ancient ruinsは「見られる」立場（受動）。受動の意味を持つ分詞構文は過去分詞（Seen）で始まる。", rule: "受動の分詞構文は過去分詞で始まる", kp: ["主語が〜される関係 → 過去分詞で分詞構文", "Seen from... = 〜から見ると"] },
  { id: "g1066", diff: "lv2", axis: "vocab", tags: ["eiken3", "preposition", "time"], stem: "She has been studying English ___ she was in elementary school.", ja: "彼女は小学生のころからずっと英語を勉強している。", answer: "since", choices: ["since", "for", "during", "from", "while"], expl: "「〜からずっと」は起点を示すsince + 過去の時点。forは「〜の間」という期間の長さを表す。", rule: "since + 起点（時点）vs for + 期間の長さ", kp: ["since + 過去の時点（いつから）", "for + 数字/期間（どれだけの間）"] },
  { id: "g1067", diff: "lv3", axis: "form", tags: ["eiken2", "relative", "whose"], stem: "I helped a woman ___ car had broken down on the highway.", ja: "高速道路で車が故障した女性を助けた。", answer: "whose", choices: ["whose", "who", "which", "that", "whom"], expl: "先行詞a womanと、関係節内のcar（名詞）の所有関係を示すには所有格の関係代名詞whoseを使う。", rule: "所有格の関係代名詞 whose（人・物の所有を表す）", kp: ["whose + 名詞 = 〜の（所有）", "人・物どちらの先行詞にも使える"] },
  { id: "g1068", diff: "lv2", axis: "form", tags: ["eiken3", "conditional", "if"], stem: "If it ___ tomorrow, we will cancel the picnic.", ja: "もし明日雨が降れば、ピクニックを中止します。", answer: "rains", choices: ["rains", "will rain", "rained", "would rain", "is raining"], expl: "時・条件を表すif節では未来のことでも現在形を使う。will rainは誤り。", rule: "条件節（if節）では未来でも現在形を使う", kp: ["If + 現在形 → 主節は will + 動詞の原形", "if節にwillは使わない"] },
  { id: "g1069", diff: "lv2", axis: "form", tags: ["eiken3", "passive"], stem: "The new library ___ by the city government last year.", ja: "新しい図書館は昨年、市によって建設された。", answer: "was built", choices: ["was built", "built", "has built", "is built", "had built"], expl: "last yearという過去の時点を示す副詞があり、受動態（was + 過去分詞）が正しい。", rule: "受動態: be動詞 + 過去分詞", kp: ["過去の受動態 = was/were + 過去分詞", "動作の受け手が主語になる"] },
  { id: "g1070", diff: "lv2", axis: "vocab", tags: ["eiken3", "gerund", "infinitive"], stem: "She enjoys ___ to classical music before bed.", ja: "彼女は寝る前にクラシック音楽を聴くのを楽しんでいる。", answer: "listening", choices: ["listening", "to listen", "listened", "listen", "listens"], expl: "enjoyは動名詞（〜ing形）を目的語にとる動詞。to不定詞は使えない。", rule: "enjoy + 動名詞（enjoy to-Vは不可）", kp: ["enjoyの後は〜ing形", "enjoy / finish / avoid / mind などは動名詞のみ"] },
  { id: "g1071", diff: "lv2", axis: "form", tags: ["eiken3", "comparison"], stem: "This bag is ___ than the one I bought last week.", ja: "このバッグは先週買ったものより軽い。", answer: "lighter", choices: ["lighter", "more light", "lightest", "most light", "light"], expl: "2つを比較するときは比較級を使う。lightは短い形容詞なので-erを付けてlighter。", rule: "比較級：短い形容詞は -er、長い形容詞は more + 原級", kp: ["2者比較 = 比較級 + than", "light → lighter（短い形容詞は-er）"] },
  { id: "g1072", diff: "lv3", axis: "form", tags: ["eiken2", "reported_speech"], stem: "She said that she ___ tired after the long journey.", ja: "彼女は長旅の後、疲れたと言った。", answer: "was", choices: ["was", "is", "will be", "has been", "were"], expl: "間接話法では、主節の動詞（said）が過去形なら、従属節の動詞も過去形に時制の一致をする。", rule: "時制の一致：主節が過去形 → 従属節も過去形に", kp: ["said → was（時制の一致）", "直接話法→間接話法で動詞を1時制ずつ後退させる"] },
  { id: "g1073", diff: "lv2", axis: "vocab", tags: ["eiken3", "preposition", "place"], stem: "The cat is hiding ___ the sofa.", ja: "猫はソファの下に隠れている。", answer: "under", choices: ["under", "between", "above", "down", "inside"], expl: "物の真下に接触・近接している状態はunder。belowは位置が下（必ずしも真下でない）を意味する。", rule: "under（〜の真下・接触）vs below（〜の下方）", kp: ["under = 真下・覆われた下", "below = 水平より下（接触不要）"] },
  { id: "g1074", diff: "lv3", axis: "form", tags: ["eiken2", "subjunctive", "wish"], stem: "I wish I ___ taller. Basketball would be easier.", ja: "もっと背が高ければいいのに。バスケがもっと楽になるのに。", answer: "were", choices: ["were", "am", "was", "will be", "would be"], expl: "wishの後の仮定法では、主語に関わらずbe動詞はwereを使う（仮定法過去）。wereが標準形。", rule: "I wish + 仮定法過去（現在の事実に反する願望）", kp: ["wish + 仮定法過去 = 今と違う状況への願望", "be動詞は主語に関わらずwere"] },
  { id: "g1075", diff: "lv2", axis: "form", tags: ["eiken3", "articles", "the"], stem: "___ sun rises in the east and sets in the west.", ja: "太陽は東から昇り、西に沈む。", answer: "The", choices: ["The", "A", "An", "One", "（不要）"], expl: "世界に1つしか存在しない唯一のものには定冠詞theを使う。the sun, the moon, the earthなど。", rule: "唯一の存在には定冠詞 the を使う", kp: ["the sun / the moon / the earth = 唯一の存在", "常識的に特定できるものにはthe"] },
  { id: "g1076", diff: "lv3", axis: "logic", tags: ["eiken2", "conjunction", "contrast"], stem: "___ the price is high, many people still buy it.", ja: "値段が高いにもかかわらず、多くの人がそれを買う。", answer: "Although", choices: ["Although", "Because", "Since", "As", "So"], expl: "前半（値段が高い）と後半（多くの人が買う）は逆接の関係。althoughは「〜にもかかわらず」。", rule: "逆接の接続詞 although / even though / though", kp: ["although = 〜にもかかわらず（逆接）", "because/since/as = 〜だから（理由）"] },
  { id: "g1077", diff: "lv3", axis: "form", tags: ["eiken2", "present_perfect_continuous"], stem: "He ___ for this company for five years.", ja: "彼は5年間この会社で働いている。", answer: "has been working", choices: ["has been working", "is working", "worked", "had worked", "works"], expl: "5年間という継続期間を強調する場合、現在完了進行形（have been + -ing）が適切。今も続いていることが含意される。", rule: "現在完了進行形: have been + -ing（過去から今まで継続）", kp: ["for + 期間 + 今も続いている → 現在完了進行形", "has been working = ずっと働いている（今も）"] },
  { id: "g1078", diff: "lv2", axis: "vocab", tags: ["eiken3", "modal", "obligation"], stem: "You ___ wear a seatbelt when driving. It's the law.", ja: "運転中はシートベルトを着用しなければならない。法律で決まっている。", answer: "must", choices: ["must", "should", "may", "might", "could"], expl: "法律に基づく義務（〜しなければならない）はmust。shouldは助言・推奨（〜すべき）でニュアンスが弱い。", rule: "must（義務・必要）vs should（助言・推奨）", kp: ["must = 義務・強制（〜しなければならない）", "should = 助言・推奨（〜すべきだ）"] },
  { id: "g1079", diff: "lv3", axis: "form", tags: ["eiken2", "infinitive_purpose"], stem: "She went to the library ___ study for her exam.", ja: "彼女は試験勉強のために図書館へ行った。", answer: "to", choices: ["to", "for", "in order for", "so as for", "that"], expl: "目的を表すには不定詞（to + 動詞の原形）を使う。「図書館へ行った目的 = 試験勉強」という関係。", rule: "目的を表す不定詞: to + 動詞の原形（〜するために）", kp: ["to + 動詞の原形 = 〜するために（目的）", "in order to でも同じ意味"] },
  { id: "g1080", diff: "lv2", axis: "form", tags: ["eiken3", "question_tag"], stem: "You have met her before, ___ you?", ja: "あなたは以前、彼女に会ったことがありますよね？", answer: "haven't", choices: ["haven't", "have", "didn't", "don't", "weren't"], expl: "肯定の主節（You have met〜）に対する付加疑問文は否定形（haven't）＋主語（you）。", rule: "付加疑問文: 肯定文 + 否定の疑問形", kp: ["肯定文 → 否定の付加疑問（〜, haven't you?）", "主節の動詞・助動詞に合わせる"] },
  { id: "g1081", diff: "lv4", axis: "form", tags: ["eikenpre1", "relative_clause_non-defining"], stem: "My sister, ___ lives in Kyoto, is a doctor.", ja: "私の姉は京都に住んでいて、医師をしている。", answer: "who", choices: ["who", "which", "that", "whose", "whom"], expl: "先行詞My sisterは人。非制限的関係詞節（カンマあり）では人にはwhoを使う。thatは非制限用法不可。", rule: "非制限的関係詞節（カンマあり）: 人には who（that は不可）", kp: ["カンマ付き関係詞節 = 非制限的用法", "非制限用法でthatは使えない"] },
  { id: "g1082", diff: "lv3", axis: "logic", tags: ["eiken2", "conditional_second"], stem: "If I ___ a million dollars, I would travel the world.", ja: "100万ドルあれば、世界中を旅するのに。", answer: "had", choices: ["had", "have", "would have", "will have", "has"], expl: "現在の事実に反する仮定（仮定法過去）。if節の動詞は過去形（had）を使う。", rule: "仮定法過去: If + 過去形 〜, would + 動詞の原形", kp: ["仮定法過去 = 現在の事実と反対の仮定", "If I had... = 実際には持っていない"] },
  { id: "g1083", diff: "lv2", axis: "vocab", tags: ["eiken3", "preposition", "time"], stem: "The meeting is scheduled ___ Monday morning.", ja: "会議は月曜の朝に予定されている。", answer: "for", choices: ["for", "from", "at", "in", "by"], expl: "予定・計画をスケジュールする文脈では「scheduled for〜」が定型表現。onは曜日単独に使うが、scheduled forが自然。", rule: "be scheduled for + 日時（〜に予定されている）", kp: ["scheduled for = 〜に予定される", "on Monday / at noon / in the morning（単独では）"] },
  { id: "g1084", diff: "lv3", axis: "form", tags: ["eiken2", "passive_perfect"], stem: "By the time she arrived, all the tickets ___ sold out.", ja: "彼女が到着した時には、チケットはすべて売り切れていた。", answer: "had been", choices: ["had been", "have been", "were", "had", "would be"], expl: "彼女が到着した時点（過去）より前に完了していた受動態 = 過去完了受動態（had been + 過去分詞）。", rule: "過去完了受動態: had been + 過去分詞（過去のある時点より前に完了した受動）", kp: ["had been + 過去分詞 = 過去完了受動態", "By the time + 過去 → 過去完了が使われやすい"] },
  { id: "g1085", diff: "lv2", axis: "form", tags: ["eiken3", "superlative"], stem: "Mount Fuji is ___ mountain in Japan.", ja: "富士山は日本で最も高い山だ。", answer: "the highest", choices: ["the highest", "the most high", "higher", "most highest", "highest"], expl: "3つ以上の中での最高を表す最上級は the + 形容詞-est。highは短い形容詞なのでhighest。the が必要。", rule: "最上級: the + 形容詞-est（短い形容詞）/ the most + 形容詞（長い形容詞）", kp: ["最上級にはtheが必要", "high → the highest"] },
  { id: "g1086", diff: "lv3", axis: "logic", tags: ["eiken2", "so_that"], stem: "She spoke slowly ___ everyone could understand her.", ja: "みんなが理解できるように、彼女はゆっくり話した。", answer: "so that", choices: ["so that", "such that", "in order", "because", "therefore"], expl: "「〜できるように」という目的を表す接続詞はso that。後ろにS + can/couldが続く形が典型。", rule: "so that + S + can/could〜（〜できるように・目的）", kp: ["so that = 〜できるように（目的）", "so that S can/could V の語順"] },
  { id: "g1087", diff: "lv4", axis: "form", tags: ["eikenpre1", "cleft_sentence"], stem: "___ Tom who broke the window, not Mike.", ja: "窓を割ったのはトムで、マイクではない。", answer: "It was", choices: ["It was", "There was", "He was", "That was", "It is"], expl: "強調構文（It is/was + 強調する要素 + that/who〜）。過去の出来事なのでIt wasを使う。", rule: "強調構文: It is/was + 強調要素 + that/who〜（〜したのは…だ）", kp: ["It was + 人 + who〜（強調構文）", "過去の強調はIt was、現在はIt is"] },
  // ── g1088–g1107: 推量・数量詞・間接疑問・動名詞vs不定詞・前置詞・使役・比較など ──
  { id: "g1088", diff: "lv3", axis: "logic", tags: ["eiken2", "modal_perfect"], stem: "She looks pale. She ___ sick last night.", ja: "顔色が悪い。昨夜、体調が悪かったのかもしれない。", answer: "must have been", choices: ["must have been", "must be", "should be", "might be", "had to be"], expl: "過去の出来事に対する強い推量は「must have + 過去分詞」。現在の推量にmust beは使えるが「昨夜」という過去には不可。", rule: "過去の強い推量: must have + 過去分詞（〜したに違いない）", kp: ["must have + pp = 〜したに違いない（過去の推量）", "must be = 現在の推量"] },
  { id: "g1089", diff: "lv2", axis: "vocab", tags: ["eiken3", "quantifier"], stem: "Only ___ students passed the difficult exam.", ja: "その難しい試験に合格したのはほんの少しの生徒だけだった。", answer: "a few", choices: ["a few", "few", "a little", "little", "some"], expl: "a fewは可算名詞の複数形と使い「少しはある（ポジティブ）」。fewは「ほとんどない（ネガティブ）」。studentsは可算名詞。文脈から合格者が存在することが分かるのでa few。", rule: "a few（少しある・肯定的）vs few（ほとんどない・否定的）※可算名詞に使う", kp: ["a few + 可算名詞 = 少しある（肯定）", "few + 可算名詞 = ほとんどない（否定）"] },
  { id: "g1090", diff: "lv2", axis: "logic", tags: ["eiken3", "indirect_question"], stem: "Could you tell me ___ the next train leaves?", ja: "次の電車がいつ出発するか教えていただけますか？", answer: "when", choices: ["when", "that", "if", "which", "how"], expl: "間接疑問文では「疑問詞 + 主語 + 動詞」の語順。「いつ出発するか」という内容を尋ねているのでwhen。", rule: "間接疑問文: 疑問詞 + S + V の語順（疑問文の語順にしない）", kp: ["tell me + 疑問詞 + S + V（間接疑問文）", "直接疑問の語順にしないこと"] },
  { id: "g1091", diff: "lv3", axis: "form", tags: ["eiken2", "remember_gerund_infinitive"], stem: "I remember ___ her at the conference last year.", ja: "昨年の会議で彼女に会ったことを覚えている。", answer: "meeting", choices: ["meeting", "to meet", "met", "to meeting", "have met"], expl: "remember + 動名詞（〜したことを覚えている：過去の記憶）。remember + 不定詞（〜することを覚えている：未来への記憶）。「昨年会った」という過去の記憶なので動名詞。", rule: "remember + 動名詞（過去の記憶）vs remember + to-V（未来の行動を忘れない）", kp: ["remember + -ing = 過去のことを覚えている", "remember to + V = 〜することを忘れずに覚えておく"] },
  { id: "g1092", diff: "lv2", axis: "vocab", tags: ["eiken3", "preposition", "between_among"], stem: "The secret was shared ___ the three friends.", ja: "その秘密は3人の友人の間で共有された。", answer: "among", choices: ["among", "between", "within", "around", "with"], expl: "betweenは2者間、amongは3者以上の間に使う。3人の友人なのでamong。", rule: "between（2者）vs among（3者以上）", kp: ["between A and B = 2つ・2者の間", "among + 複数（3以上）の間"] },
  { id: "g1093", diff: "lv3", axis: "form", tags: ["eiken2", "have_something_done"], stem: "She ___ her hair cut at the new salon.", ja: "彼女は新しいサロンで髪を切ってもらった。", answer: "had", choices: ["had", "took", "made", "let", "did"], expl: "「〜してもらう（第三者に依頼）」はhave + 目的語 + 過去分詞。had her hair cut = 美容師に切ってもらった（自分で切ったのではない）。", rule: "have + O + 過去分詞（〜してもらう・第三者依頼の使役）", kp: ["have + 目的語 + 過去分詞 = してもらう", "get + 目的語 + 過去分詞も同じ意味"] },
  { id: "g1094", diff: "lv2", axis: "vocab", tags: ["eiken3", "preposition", "time_at_in_on"], stem: "The concert starts ___ 7 o'clock.", ja: "コンサートは7時に始まる。", answer: "at", choices: ["at", "in", "on", "by", "for"], expl: "具体的な時刻の前にはatを使う。inは月・年・季節・時間帯（午前・午後）、onは曜日・日付に使う。", rule: "時の前置詞: at（時刻）/ on（曜日・日付）/ in（月・年・時間帯）", kp: ["at + 時刻（at 7 o'clock）", "on + 曜日・日付 / in + 月・年"] },
  { id: "g1095", diff: "lv3", axis: "logic", tags: ["eiken2", "too_to"], stem: "She was ___ tired ___ continue working.", ja: "彼女はあまりに疲れていて、仕事を続けることができなかった。", answer: "too ... to", choices: ["too ... to", "so ... that", "enough ... to", "very ... to", "such ... that"], expl: "too + 形容詞 + to + 動詞の原形 = 〜するには〜すぎる（否定の意味）。「疲れすぎていて続けられなかった」という文脈に合う。", rule: "too + 形容詞/副詞 + to-V（〜するには〜すぎる）", kp: ["too ... to ... = 〜すぎて〜できない（否定の含意）", "so ... that S can't V でも同じ意味"] },
  { id: "g1096", diff: "lv2", axis: "form", tags: ["eiken3", "quantifier_much_many"], stem: "There isn't ___ information about this topic online.", ja: "このトピックに関するオンライン上の情報はあまりない。", answer: "much", choices: ["much", "many", "few", "a few", "several"], expl: "informationは不可算名詞なのでmuchを使う。manyは可算名詞の複数形と使う。fewは可算名詞用。", rule: "much + 不可算名詞 / many + 可算名詞複数", kp: ["much + 不可算名詞（情報・水・時間など）", "many + 可算名詞の複数形"] },
  { id: "g1097", diff: "lv3", axis: "tense", tags: ["eiken2", "used_to"], stem: "She ___ play the piano when she was young.", ja: "彼女は若い頃、ピアノを弾いていた（今はもう弾かない）。", answer: "used to", choices: ["used to", "will", "was used to", "is used to", "has used to"], expl: "used to + 動詞の原形は「以前は〜だった（今はもうしない）」という過去の状態・習慣を表す。wouldも過去の習慣に使えるが状態動詞には使えない（ここではplayなので可）。used to は「今はもうしない」のニュアンスを含む。", rule: "used to + 動詞の原形（過去の習慣・状態：今はもうしない）", kp: ["used to + V = 以前は〜していた（今はもうしない）", "be used to + -ing = 〜に慣れている（混同注意）"] },
  { id: "g1098", diff: "lv2", axis: "form", tags: ["eiken3", "it_takes"], stem: "It ___ about two hours to drive to the airport.", ja: "空港まで車で約2時間かかる。", answer: "takes", choices: ["takes", "spends", "costs", "lasts", "needs"], expl: "時間がかかることを表すのはIt takes + 時間 + to-V。spendは「人が時間を使う」、costは「お金がかかる」。", rule: "It takes + 時間 + to-V（〜するのに…かかる）", kp: ["It takes + 時間 + to do = 〜するのに時間がかかる", "spend（人が時間を費やす）との混同に注意"] },
  { id: "g1099", diff: "lv3", axis: "vocab", tags: ["eiken2", "preposition", "depend_on"], stem: "Whether we go on the trip ___ the weather.", ja: "旅行に行くかどうかは天気次第だ。", answer: "depends on", choices: ["depends on", "depends of", "depends to", "relies to", "counts to"], expl: "depend on〜で「〜に依存する・〜次第だ」。前置詞はonが固定。depend of/toは誤り。", rule: "depend on〜（〜に依存する・〜次第だ）", kp: ["depend on = 〜次第だ・〜に依存する", "前置詞はon（ofやtoではない）"] },
  { id: "g1100", diff: "lv3", axis: "form", tags: ["eiken2", "stop_gerund_infinitive"], stem: "She stopped ___ when she heard the noise.", ja: "物音がしたとき、彼女は読むのをやめた。", answer: "reading", choices: ["reading", "to read", "read", "to reading", "reads"], expl: "stop + 動名詞（-ing）= 〜するのをやめる。stop + 不定詞（to V）= 〜するために立ち止まる（止まって〜する）。物音がして読むのをやめたので動名詞。", rule: "stop + -ing（〜するのをやめる）vs stop + to-V（〜するために立ち止まる）", kp: ["stop reading = 読むのをやめる", "stop to read = 読むために立ち止まる"] },
  { id: "g1101", diff: "lv2", axis: "vocab", tags: ["eiken3", "preposition", "during_for_while"], stem: "___ the summer vacation, I visited my grandparents.", ja: "夏休みの間、祖父母の家を訪れた。", answer: "During", choices: ["During", "For", "While", "In", "Through"], expl: "duringは「〜の期間中」という特定の期間を示す前置詞。forは期間の長さ（for 3 days）。whileは接続詞でS+Vが続く。the summer vacationは名詞句なのでduringが適切。", rule: "during + 名詞句（〜の間）/ while + S + V（〜している間）/ for + 数字の期間", kp: ["during + 名詞（期間）= 〜の間に", "while + S + V（接続詞）/ for + 数字の期間と区別"] },
  { id: "g1102", diff: "lv4", axis: "logic", tags: ["eikenpre1", "modal_perfect_negative"], stem: "He ___ missed the meeting. His name was on the attendance list.", ja: "彼が会議を欠席したはずがない。出席リストに名前が載っていた。", answer: "can't have", choices: ["can't have", "mustn't have", "shouldn't have", "wouldn't have", "needn't have"], expl: "過去の出来事に対する強い否定的推量は「can't have + 過去分詞（〜したはずがない）」。出席リストにあるので欠席は不可能。", rule: "can't have + 過去分詞（〜したはずがない：過去の否定的推量）", kp: ["can't have + pp = 〜したはずがない", "must have + pp（〜したに違いない）の否定版"] },
  { id: "g1103", diff: "lv2", axis: "form", tags: ["eiken3", "as_as"], stem: "This room is ___ large ___ our living room.", ja: "この部屋は私たちのリビングと同じくらい広い。", answer: "as ... as", choices: ["as ... as", "so ... as", "more ... than", "the same ... that", "too ... to"], expl: "同等比較は「as + 形容詞/副詞の原級 + as」の形。so...asは否定文（not so...as）で使う。", rule: "同等比較: as + 形容詞/副詞の原級 + as（〜と同じくらい）", kp: ["as ... as = 〜と同じくらい（同等比較）", "否定文ではnot as/so ... as"] },
  { id: "g1104", diff: "lv3", axis: "logic", tags: ["eiken2", "reported_question"], stem: "He asked me ___ I had finished the project.", ja: "彼は私にプロジェクトを終えたかどうかを尋ねた。", answer: "whether", choices: ["whether", "that", "which", "what", "if not"], expl: "askに続く間接疑問文でyes/noの疑問内容を表すにはwhether（またはif）を使う。whetherの後は間接疑問文の語順（S+V）。", rule: "間接疑問（yes/no型）: ask/wonder + whether/if + S + V", kp: ["whether / if + S + V = 〜かどうか（yes/no疑問の間接話法）", "whether or notとも言う"] },
  { id: "g1105", diff: "lv3", axis: "logic", tags: ["eiken2", "both_either_neither"], stem: "___ of the two candidates impressed the committee.", ja: "2人の候補者のどちらも委員会を感動させなかった。", answer: "Neither", choices: ["Neither", "Both", "Either", "None", "All"], expl: "neitherは2つのものが「どちらも〜ない」という否定を表す。both（両方とも〜）、either（どちらか一方）、none（3つ以上でどれも〜ない）と区別する。", rule: "neither（2者がどちらも〜ない）/ both（2者が両方〜）/ either（2者のどちらか一方）", kp: ["neither of the two = どちらも〜ない（2者の否定）", "none = 3つ以上でどれも〜ない"] },
  { id: "g1106", diff: "lv2", axis: "form", tags: ["eiken3", "causative_let"], stem: "My parents ___ me stay up late on weekends.", ja: "両親は週末に夜更かしを許してくれた。", answer: "let", choices: ["let", "made", "had", "got", "caused"], expl: "let + O + 動詞の原形 = O が〜するのを許可する。makeは強制（〜させる）、haveは手配（〜してもらう）と意味が異なる。", rule: "使役動詞 let + O + 原形（〜するのを許可する・させておく）", kp: ["let + O + 原形 = 許可（〜させておく）", "make（強制）/ have（手配）/ let（許可）の違い"] },
  { id: "g1107", diff: "lv3", axis: "form", tags: ["eiken2", "negative_prefix"], stem: "His explanation was completely ___. Nobody understood a word.", ja: "彼の説明は全く理解不能だった。誰一人一言も理解できなかった。", answer: "incomprehensible", choices: ["incomprehensible", "uncomprensible", "discomprehensible", "noncomprehensible", "miscomprehensible"], expl: "comprehensible（理解できる）の否定はin-をつけてincomprehensible。in-は形容詞の否定接頭辞として広く使われる（incomplete, incorrect, impossibleなど）。", rule: "否定接頭辞 in-（un-, dis-, non- などとの使い分け）", kp: ["in- + 形容詞 = 否定（in-comprehensible = 理解できない）", "incorrect / impossible / invisible / incomprehensible など"] },
  { id: "g1108", diff: "lv2", axis: "tense", tags: ["eiken3", "present_perfect"], stem: "She ___ in Tokyo for ten years.", ja: "彼女は10年間東京に住んでいる。", answer: "has lived", choices: ["has lived", "lived", "is living", "lives", "had lived"], expl: "for ten yearsは期間を表す表現。現在まで継続している状態には現在完了形（has/have + 過去分詞）を使う。", rule: "現在完了形の継続用法: have/has + 過去分詞 + for/since", kp: ["for + 期間 → 現在完了の継続", "since + 起点 → 現在完了の継続"] },
  { id: "g1109", diff: "lv2", axis: "form", tags: ["eiken3", "infinitive_purpose"], stem: "She went to the library ___ some books.", ja: "彼女は本を何冊か借りるために図書館へ行った。", answer: "to borrow", choices: ["to borrow", "for borrow", "borrowing", "borrow", "for borrowing"], expl: "目的（〜するために）を表すにはto不定詞を使う。forの後には動名詞ではなく名詞がくる（for + 名詞）。", rule: "目的を表すto不定詞（〜するために）", kp: ["目的のto不定詞 = in order to + 動詞原形", "for + 名詞（目的） vs to + 動詞原形（目的）"] },
  { id: "g1110", diff: "lv2", axis: "vocab", tags: ["eiken3", "conjunction"], stem: "___ it was raining, we decided to go hiking.", ja: "雨が降っていたにもかかわらず、私たちはハイキングに行くことにした。", answer: "Although", choices: ["Although", "Because", "Since", "So", "Therefore"], expl: "「にもかかわらず」という逆接を表すにはAlthough / Though / Even thoughを使う。Becauseは理由、Sinceは理由または時、Soは結果を表す。", rule: "逆接の接続詞: although / though / even though（〜だけれども）", kp: ["although/though = 〜にもかかわらず（逆接）", "because/since = 〜なので（理由）"] },
  { id: "g1111", diff: "lv2", axis: "form", tags: ["eiken3", "passive"], stem: "This novel ___ by millions of readers worldwide.", ja: "この小説は世界中で何百万人もの読者に読まれている。", answer: "is read", choices: ["is read", "reads", "read", "is reading", "has read"], expl: "主語が動作を受ける側（受動）のときはbe動詞 + 過去分詞を使う。This novelが読まれる側なので受動態。現在の習慣的な事実なので現在形is read。", rule: "受動態: be動詞 + 過去分詞（〜される）", kp: ["受動態 = be + 過去分詞", "by + 行為者（省略可能）"] },
  { id: "g1112", diff: "lv3", axis: "form", tags: ["eiken2", "perfect_infinitive"], stem: "She seems ___ the news already.", ja: "彼女はすでにそのニュースを聞いたようだ。", answer: "to have heard", choices: ["to have heard", "to hear", "hearing", "to be hearing", "have heard"], expl: "seem to + 動詞原形は現在の状態を表すが、主節より前の時点を表すには完了不定詞（to have + 過去分詞）を使う。", rule: "完了不定詞 to have + 過去分詞（主節より前の時点を表す）", kp: ["to have + 過去分詞 = （主節より）以前のこと", "seem to have done = 〜したようだ"] },
  { id: "g1113", diff: "lv2", axis: "vocab", tags: ["eiken3", "preposition_time"], stem: "The store opens ___ 9 a.m. ___ 6 p.m.", ja: "その店は午前9時から午後6時まで開いている。", answer: "from / to", choices: ["from / to", "since / until", "at / at", "from / until", "between / and"], expl: "「〜から〜まで」という時間の範囲を表すにはfrom A to B。since A until Bは「〜以来ずっと〜まで」で継続の意味が強い。between A and Bは2点の間。", rule: "時間の範囲: from A to B（〜から〜まで）", kp: ["from A to B = 〜から〜まで（範囲）", "since（継続の起点）vs from（単なる起点）"] },
  { id: "g1114", diff: "lv3", axis: "logic", tags: ["eiken2", "inversion"], stem: "___ did I realize that I had left my wallet at home.", ja: "家に財布を忘れてきたと気づいたのはその時だった。", answer: "Not until then", choices: ["Not until then", "Until then not", "Not then until", "Then not until", "Only until then"], expl: "「〜して初めて気づいた」を強調するにはNot until ...を文頭に置き、倒置（did I realize）が起こる。否定語句が文頭に来ると主語と助動詞が倒置する。", rule: "否定語句の文頭倒置: Not until ... + 助動詞 + S + V", kp: ["Not until ... → 倒置（did/have/wasなど）", "強調倒置は否定・制限表現（only, never, seldom）でも起きる"] },
  { id: "g1115", diff: "lv2", axis: "form", tags: ["eiken3", "comparative"], stem: "The more you practice, ___ you become.", ja: "練習すればするほど、上手くなる。", answer: "the better", choices: ["the better", "better", "the best", "more better", "the more better"], expl: "「〜すればするほど〜」はthe + 比較級, the + 比較級の構文。The more you practice, the better you become.のように使う。", rule: "比例表現: The + 比較級 ..., the + 比較級 ...（〜すればするほど〜）", kp: ["The more ..., the + 比較級 = 〜するほど〜", "the betterのtheは接続詞的な働き"] },
  { id: "g1116", diff: "lv2", axis: "form", tags: ["eiken3", "gerund_object"], stem: "I enjoy ___ to music in the morning.", ja: "私は朝、音楽を聴くのが好きだ。", answer: "listening", choices: ["listening", "to listen", "listen", "listened", "to listening"], expl: "enjoyの後には動名詞（-ing形）がくる。enjoy to不定詞は誤り。他にもfinish, mind, avoid, practiceなど動名詞のみを目的語にとる動詞がある。", rule: "動名詞のみを目的語にとる動詞: enjoy, finish, mind, avoid, practice など", kp: ["enjoy + -ing（〜するのを楽しむ）", "動名詞 vs 不定詞の選択は動詞によって決まる"] },
  { id: "g1117", diff: "lv3", axis: "form", tags: ["eiken2", "relative_what"], stem: "___ surprised me most was his calm reaction.", ja: "私が最も驚いたのは彼の冷静な反応だった。", answer: "What", choices: ["What", "That", "Which", "The thing which", "How"], expl: "「〜ということ（もの）」という意味の名詞節を導くのはwhat。whichやthatは先行詞が必要だが、whatはそれ自体が先行詞を含む関係代名詞。", rule: "名詞節を導くwhat（先行詞を含む関係代名詞）", kp: ["what = the thing(s) that（先行詞を含む）", "What surprised me = 私を驚かせたこと"] },
  { id: "g1118", diff: "lv2", axis: "vocab", tags: ["eiken3", "modal_should"], stem: "You ___ see a doctor if you feel that bad.", ja: "そんなに具合が悪いなら、医者に診てもらうべきだ。", answer: "should", choices: ["should", "must", "can", "might", "would"], expl: "shouldは「〜すべきだ」という義務・アドバイスを表す。mustより柔らかい提案・勧告のニュアンス。mustは強い義務や禁止に使う。", rule: "助動詞 should（〜すべきだ：アドバイス・義務）", kp: ["should = 〜すべきだ（アドバイス・義務・推量）", "must（強い義務）vs should（アドバイス）"] },
  { id: "g1119", diff: "lv3", axis: "form", tags: ["eiken2", "subjunctive_wish"], stem: "I wish I ___ speak French fluently.", ja: "フランス語を流暢に話せたらいいのに。", answer: "could", choices: ["could", "can", "will", "would", "should"], expl: "I wish + 仮定法過去で「今〜だったらいいのに」という現在の事実に反する願望を表す。wishの後では現在の願望にcouldやwereなどの過去形（仮定法）を使う。", rule: "I wish + 仮定法過去（現在の事実に反する願望）", kp: ["I wish + 過去形/could = 今〜ならいいのに", "I wish I could = can の仮定法過去"] },
  { id: "g1120", diff: "lv2", axis: "form", tags: ["eiken3", "article_the"], stem: "Can you play ___ piano?", ja: "ピアノが弾けますか？", answer: "the", choices: ["the", "a", "an", "some", "（不要）"], expl: "楽器名の前には定冠詞theをつける。play the piano / play the guitar / play the violinのように使う。スポーツには冠詞をつけないこと（play tennis, play soccer）と区別する。", rule: "楽器名の前にthe（play the + 楽器名）", kp: ["楽器にはthe（play the piano）", "スポーツには冠詞なし（play tennis）"] },
  { id: "g1121", diff: "lv3", axis: "logic", tags: ["eiken2", "cleft_sentence"], stem: "It was ___ that broke the window.", ja: "窓を割ったのはボールだった。", answer: "the ball", choices: ["the ball", "a ball", "that ball", "balls", "the balls"], expl: "It is/was ... that 〜の強調構文（分裂文）で、強調したい要素をIt is/wasとthatの間に置く。ここではthe ball（特定のボール）を強調している。", rule: "強調構文: It is/was + 強調要素 + that + 残りの文", kp: ["強調構文でthatの前に置かれた要素が強調される", "人の場合はthatの代わりにwhoも使える"] },
  { id: "g1122", diff: "lv2", axis: "vocab", tags: ["eiken3", "preposition_by"], stem: "The letter must be submitted ___ Friday.", ja: "その手紙は金曜日までに提出しなければならない。", answer: "by", choices: ["by", "until", "before", "to", "on"], expl: "byは「〜までに（期限）」を表す。untilは「〜までずっと（継続）」を表す。by Fridayは金曜日が締め切りで、until Fridayは金曜日まで継続する動作に使う。", rule: "期限のby（〜までに）vs 継続のuntil（〜までずっと）", kp: ["by = 〜までに（期限・締め切り）", "until = 〜まで（継続）"] },
  { id: "g1123", diff: "lv3", axis: "form", tags: ["eiken2", "participial_phrase"], stem: "___ from the top of the hill, the city looked beautiful.", ja: "丘の頂上から見ると、都市はきれいだった。", answer: "Seen", choices: ["Seen", "Seeing", "To see", "Having seen", "Being seen"], expl: "分詞構文で、主節の主語（the city）と分詞の関係が受動（都市が見られる）の場合は過去分詞（Seen）を使う。SeenはBeing seenの省略形。", rule: "受動の分詞構文: 過去分詞（Being + 過去分詞の省略）", kp: ["主節の主語が受動 → 過去分詞で分詞構文", "Seen from ... = 〜から見ると（受動の分詞構文）"] },
  { id: "g1124", diff: "lv2", axis: "form", tags: ["eiken3", "so_that"], stem: "He spoke slowly ___ everyone could understand him.", ja: "皆が理解できるように、彼はゆっくりと話した。", answer: "so that", choices: ["so that", "such that", "in order", "so as", "because"], expl: "「〜できるように（目的）」を表すにはso that + S + can/couldを使う。in orderはin order toの形で使い後ろに主語を置けない。so as toも同様に主語を置けない。", rule: "目的の接続詞: so that + S + can/could（〜できるように）", kp: ["so that + S + can/could = 〜できるように（目的）", "in order to / so as to（主語なし）との違い"] },
  { id: "g1125", diff: "lv3", axis: "logic", tags: ["eiken2", "had_better"], stem: "You ___ leave now or you'll miss the last train.", ja: "今すぐ出発した方がいい、さもないと終電に乗り遅れるよ。", answer: "had better", choices: ["had better", "would rather", "had rather", "should better", "must better"], expl: "had betterは「〜した方がよい（しないと困る）」という強めのアドバイス・警告を表す。would ratherは「どちらかといえば〜したい」という好みを表す。", rule: "had better + 動詞原形（〜した方がよい：強めの警告・アドバイス）", kp: ["had better = 〜した方がよい（否定: had better not）", "would rather（好み）vs had better（警告・アドバイス）"] },
  { id: "g1126", diff: "lv2", axis: "form", tags: ["eiken3", "question_tag"], stem: "You haven't met her before, ___?", ja: "あなたは以前、彼女に会ったことがないですよね？", answer: "have you", choices: ["have you", "haven't you", "did you", "didn't you", "do you"], expl: "付加疑問文は前の文が肯定なら否定形、否定なら肯定形で作る。You haven't met（否定）なので、付加疑問はhave you（肯定）。時制と助動詞も揃える。", rule: "付加疑問文: 肯定文 + 否定形?, 否定文 + 肯定形?", kp: ["否定文 + 肯定の付加疑問（〜ですよね？）", "助動詞・時制を前の文に合わせる"] },
  { id: "g1127", diff: "lv3", axis: "form", tags: ["eiken2", "future_perfect"], stem: "By the time she arrives, we ___ dinner.", ja: "彼女が着くころには、私たちは夕食を終えているだろう。", answer: "will have finished", choices: ["will have finished", "will finish", "have finished", "had finished", "will be finishing"], expl: "by the time S + V（現在形）は未来の時点を表し、その時点までに完了している動作には未来完了形（will have + 過去分詞）を使う。", rule: "未来完了形: will have + 過去分詞（未来のある時点までに完了）", kp: ["by the time + 現在形 → 未来完了（will have + 過去分詞）", "未来完了 = 未来の時点での完了・経験・継続"] },
  { id: "g1128", diff: "lv2", axis: "form", tags: ["eiken3", "stative_verb"], stem: "I ___ this song very much. It reminds me of my childhood.", ja: "この曲がとても好きです。子どもの頃を思い出します。", answer: "love", choices: ["love", "am loving", "have loved", "was loving", "do love"], expl: "loveは状態動詞なので進行形にしない。状態動詞（love, like, know, have, believe など）は現在形で「今の状態」を表す。", rule: "状態動詞は進行形不可（love / know / like / have など）", kp: ["状態動詞 = 進行形にしない", "love / like / know / believe / own → 現在形で状態を表す"] },
  { id: "g1129", diff: "lv3", axis: "form", tags: ["eiken2", "relative_whose"], stem: "The student ___ father is a doctor wants to study medicine.", ja: "父親が医者である生徒は医学を学びたいと思っています。", answer: "whose", choices: ["whose", "who", "which", "of whom", "that"], expl: "関係代名詞whoseは「〜の」という所有関係を表す。whose father = the student's father。先行詞が人でも物でも使える。", rule: "関係代名詞whose：先行詞の所有（〜の〜）", kp: ["whose + 名詞 = 先行詞 + 's + 名詞", "whoseは人・物どちらの先行詞にも使える"] },
  { id: "g1130", diff: "lv2", axis: "logic", tags: ["eiken3", "infinitive_adjective"], stem: "I need something ___ . I'm very thirsty.", ja: "何か飲むものが必要です。とても喉が渇いています。", answer: "to drink", choices: ["to drink", "drinking", "drunk", "for drinking", "drank"], expl: "something / anything / nothing などを後ろから修飾する不定詞の形容詞的用法。something to drink = 飲むための何か。", rule: "不定詞の形容詞的用法: 名詞 + to-V（〜するための・〜すべき）", kp: ["something to eat / drink / do などの形でよく使う", "不定詞が名詞を後ろから修飾"] },
  { id: "g1131", diff: "lv2", axis: "form", tags: ["eiken3", "too_to"], stem: "The box is ___ heavy for me to carry alone.", ja: "その箱は一人では運べないほど重い。", answer: "too", choices: ["too", "so", "very", "enough", "quite"], expl: "too ... to-V 構文で「〜すぎて…できない」という意味。too + 形容詞 + for + 人 + to-V の形をとる。", rule: "too + 形容詞 + (for 人) + to-V：〜すぎて…できない", kp: ["too heavy to carry = 重すぎて運べない", "for meで「私には」という意味を加える"] },
  { id: "g1132", diff: "lv2", axis: "form", tags: ["eiken3", "enough_to"], stem: "She is old ___ to drive a car.", ja: "彼女は車を運転できる年齢だ。", answer: "enough", choices: ["enough", "too", "so", "very", "quite"], expl: "enough to-V 構文で「〜するのに十分…」という意味。形容詞の後にenoughを置く点に注意（形容詞 + enough）。very / too は enough to 構文にならない。", rule: "形容詞 + enough + to-V：〜するのに十分〜だ", kp: ["old enough to drive = 運転できるほど年齢がいっている", "enoughは形容詞・副詞の後に置く"] },
  { id: "g1133", diff: "lv2", axis: "form", tags: ["eiken3", "present_perfect_just"], stem: "I ___ just finished my homework.", ja: "ちょうど宿題が終わりました。", answer: "have", choices: ["have", "had", "am", "was", "did"], expl: "justと共に使うhave + just + 過去分詞は「ちょうど〜したところだ」という完了を表す現在完了形。justは have と過去分詞の間に置く。", rule: "現在完了形 + just：have just + 過去分詞（ちょうど〜した）", kp: ["have just + 過去分詞 = ちょうど〜したところ", "justはhaveと過去分詞の間に挿入"] },
  { id: "g1134", diff: "lv3", axis: "logic", tags: ["eiken2", "modal_might"], stem: "It ___ rain this afternoon. The clouds look quite dark.", ja: "今午後は雨が降るかもしれない。雲がかなり暗く見える。", answer: "might", choices: ["might", "must", "can", "will", "shall"], expl: "mightは「〜かもしれない」という弱い可能性（50%以下）を表す。mustは確信（〜に違いない）、shouldは義務・当然（〜すべき・〜のはずだ）、willは意志・予測。", rule: "might：弱い可能性（〜かもしれない、50%以下）", kp: ["might = 〜かもしれない（弱い推量）", "must（確信）> should（当然）> might（弱い可能性）"] },
  { id: "g1135", diff: "lv4", axis: "form", tags: ["eiken1", "past_perfect_subjunctive"], stem: "If I ___ studied harder, I would have passed the exam.", ja: "もっと一生懸命勉強していたら、試験に合格していただろうに。", answer: "had", choices: ["had", "have", "would have", "could have", "should have"], expl: "仮定法過去完了は「過去の事実に反する仮定」を表す。If + 主語 + had + 過去分詞, 主語 + would have + 過去分詞の形。If I had studied = 実際は勉強しなかった。", rule: "仮定法過去完了: If + S + had + 過去分詞, S + would have + 過去分詞", kp: ["仮定法過去完了 = 過去の事実に反する仮定", "If I had studied harder = 実際は勉強しなかった"] },
  { id: "g1136", diff: "lv3", axis: "logic", tags: ["eiken2", "infinitive_result"], stem: "She grew up ___ become a famous pianist.", ja: "彼女は成長して有名なピアニストになった。", answer: "to", choices: ["to", "and", "so as to", "in order to", "for"], expl: "grow up to-V で「成長して〜になった」という結果を表す不定詞の副詞的用法（結果）。live to-V（生きて〜する）などと同じパターン。", rule: "不定詞の副詞的用法（結果）: grow up to-V, live to-V など", kp: ["grew up to become = 成長した結果〜になった", "結果の不定詞: only to fail（〜したがそれだけだった）なども"] },
  { id: "g1137", diff: "lv3", axis: "form", tags: ["eiken2", "suggest_that"], stem: "The doctor suggested that he ___ more rest.", ja: "医者は彼にもっと休むように提案した。", answer: "get", choices: ["get", "gets", "getting", "to get", "got"], expl: "suggest / recommend / insist + that節では動詞の原形（仮定法現在）を使う。主語が何であれ動詞は原形のまま。この用法は英米で一般的。", rule: "提案・要求動詞 + that + S + 動詞の原形（仮定法現在）", kp: ["suggest / recommend / insist that + S + 原形", "主語・時制に関わらず that節内は原形"] },
  { id: "g1138", diff: "lv2", axis: "form", tags: ["eiken3", "relative_where"], stem: "This is the town ___ I was born.", ja: "ここが私が生まれた町です。", answer: "where", choices: ["where", "which", "that", "what", "when"], expl: "場所を表す先行詞（town, place, country など）の後に場所の関係副詞whereを使う。whereはin which に言い換え可能。", rule: "関係副詞where：場所を表す先行詞の後（= in/at which）", kp: ["場所 + where = the town where I was born", "where = in which（前置詞 + 関係代名詞）"] },
  { id: "g1139", diff: "lv2", axis: "logic", tags: ["eiken3", "either_or"], stem: "___ you or I have to stay and finish the project.", ja: "あなたか私のどちらかがプロジェクトを終わらせるために残らなければならない。", answer: "Either", choices: ["Either", "Neither", "Both", "Whether", "Not only"], expl: "either A or B は「AかBのどちらか一方」を意味する。neither A nor B は「AもBも〜ない」、both A and B は「AとBの両方」。", rule: "either A or B：AかBのどちらか一方", kp: ["either...or = どちらか一方（肯定）", "neither...nor = どちらも〜ない（否定）"] },
  { id: "g1140", diff: "lv2", axis: "form", tags: ["eiken3", "participle_emotion"], stem: "The movie was very ___. I couldn't stop crying.", ja: "その映画はとても感動的でした。泣き止めませんでした。", answer: "moving", choices: ["moving", "moved", "move", "movement", "movingly"], expl: "感情を引き起こすものを修飾するときは現在分詞（〜ing形）の形容詞を使う。movingは「感動させる（もの）」、movedは「感動した（人）」を表す。", rule: "現在分詞の形容詞：-ing（感動させる）vs 過去分詞：-ed（感動した）", kp: ["exciting（興奮させる）vs excited（興奮した）", "boring / bored, interesting / interested など"] },
  { id: "g1141", diff: "lv3", axis: "vocab", tags: ["eiken2", "preposition_despite"], stem: "___ the heavy rain, the game continued.", ja: "大雨にもかかわらず、試合は続いた。", answer: "Despite", choices: ["Despite", "Although", "However", "Even", "While"], expl: "despiteは前置詞なので後ろに名詞（句）を続ける。althoughは接続詞なので後ろにS+Vの節を続ける。Despite the rain = Although it rained heavily.", rule: "Despite + 名詞（句）：〜にもかかわらず（前置詞）", kp: ["despite + 名詞 vs although + S + V", "in spite of もdespiteと同じ意味で使える"] },
  { id: "g1142", diff: "lv2", axis: "form", tags: ["eiken3", "used_to"], stem: "There ___ a cinema here, but it closed years ago.", ja: "以前ここに映画館があったが、何年も前に閉鎖された。", answer: "used to be", choices: ["used to be", "was used to be", "would be", "had been", "used be"], expl: "used to + 動詞原形は「以前は〜だった（今はそうでない）」という過去の習慣や状態を表す。be動詞の場合はused to be。be used toは「〜に慣れている」と意味が異なる。", rule: "used to + 動詞原形：以前は〜だった（今はそうでない）", kp: ["used to = 過去の習慣・状態（今はない）", "be used to + 〜ing = 〜に慣れている（別の意味）"] },
  { id: "g1143", diff: "lv3", axis: "form", tags: ["eiken2", "seem_to"], stem: "She ___ to enjoy the party. She's been smiling all evening.", ja: "彼女はパーティーを楽しんでいるようです。夕方ずっと笑っています。", answer: "seems", choices: ["seems", "seems to be", "is seeming", "looked", "appears to be"], expl: "seem to-V で「〜しているようだ」と推量を表す。seemは状態動詞なので進行形にしない。appear to-V も同じ意味で使える。she seems to enjoy = It seems that she enjoys。", rule: "seem to-V：〜しているようだ（推量）", kp: ["seem / appear to-V = 〜のようだ", "seemは状態動詞なので進行形不可"] },
  { id: "g1144", diff: "lv3", axis: "form", tags: ["eiken2", "passive_continuous"], stem: "The bridge ___ repaired right now. Please use the detour.", ja: "今まさに橋が修繕されています。迂回路をご利用ください。", answer: "is being", choices: ["is being", "is been", "has been", "was being", "is"], expl: "「今〜されている」という受動態の進行形はbe being + 過去分詞で表す。is being repaired = 今修繕中（受動の進行）。has been repaired は現在完了受動（すでに完了）。", rule: "受動態の進行形: is/are being + 過去分詞（今〜されている）", kp: ["is being repaired = 今修繕されている（現在進行受動）", "has been repaired = すでに修繕済み（現在完了受動）"] },
  { id: "g1145", diff: "lv3", axis: "form", tags: ["eiken2", "relative_what"], stem: "___ surprised me most was her calmness under pressure.", ja: "私が最も驚いたのは、プレッシャー下での彼女の冷静さだった。", answer: "What", choices: ["What", "That", "Which", "How", "Whatever"], expl: "先行詞を含む関係代名詞whatは「〜すること（もの）」を表し、名詞節として機能する。ここではWhatが主語になっている。what = the thing that。", rule: "関係代名詞what：先行詞を含む（= the thing that）", kp: ["What surprised me = 私を驚かせたこと", "whatは先行詞を含む関係代名詞（= the thing that）"] },
  { id: "g1146", diff: "lv2", axis: "logic", tags: ["eiken3", "unless"], stem: "___ you hurry up, you'll miss the last bus.", ja: "急がなければ、最終バスに乗り遅れますよ。", answer: "Unless", choices: ["Unless", "If", "Until", "Although", "When"], expl: "unlessは「〜でなければ、もし〜でないなら」という否定条件を表す接続詞。Unless you hurry = If you don't hurry。unlessの節の中は肯定形を使うことに注意。", rule: "unless + S + V（肯定形）：〜でなければ（= if ... not）", kp: ["unless = if ... not（否定条件）", "unless節の中は肯定形を使う（not を重ねない）"] },
  { id: "g1147", diff: "lv2", axis: "form", tags: ["eiken3", "make_adjective"], stem: "The news ___ everyone happy.", ja: "そのニュースはみんなを幸せにした。", answer: "made", choices: ["made", "made to", "made be", "let", "had"], expl: "make + 目的語 + 形容詞で「〜を…にさせる」という意味を表す。makeの後の補語に形容詞が来る場合はto不定詞は使わない。let / have は補語に原形動詞を使う。", rule: "make + O + 形容詞：Oを〜にする（SVOC構文）", kp: ["make O + 形容詞 = Oを〜にする", "make me happy / make it possible など"] },
  { id: "g1148", diff: "lv2", axis: "form", tags: ["eiken3", "present_perfect_since"], stem: "She has lived in Tokyo ___ 2010.", ja: "彼女は2010年からずっと東京に住んでいる。", answer: "since", choices: ["since", "for", "from", "during", "by"], expl: "sinceは起点（特定の時点）、forは期間の長さに使う。2010年という特定の年が続いているのでsince。「for 15 years」のように期間の長さにはforを使う。", rule: "since + 時点（〜から）vs for + 期間（〜の間）※現在完了と共に使う", kp: ["since 2010 / since last Monday = 特定時点からずっと", "for three years / for a long time = 期間の長さ"] },
  { id: "g1149", diff: "lv2", axis: "logic", tags: ["eiken3", "so_that"], stem: "She spoke slowly ___ everyone could understand her.", ja: "みんなが理解できるように彼女はゆっくり話した。", answer: "so that", choices: ["so that", "so as", "in order", "for that", "such that"], expl: "so that + S + can/could/will/would は「〜するために、〜できるように」という目的を表す副詞節。in order that も同じ意味だが、so that が口語的でよく使われる。", rule: "so that + S + can/will/could/would：〜するために（目的）", kp: ["so that everyone can understand = 全員が理解できるように", "so that = in order that（目的の副詞節）"] },
  { id: "g1150", diff: "lv3", axis: "form", tags: ["eiken2", "wish_past_perfect"], stem: "I wish I ___ harder for the exam. I failed it.", ja: "もっと試験のために頑張っていればよかった。不合格だったのだ。", answer: "had studied", choices: ["had studied", "studied", "would study", "have studied", "was studying"], expl: "wish + 仮定法過去完了（had + 過去分詞）で過去の事実に反する後悔を表す。「もっと勉強していればよかった」という過去への後悔にはwish + had + 過去分詞を使う。", rule: "wish + had + 過去分詞：過去の事実への後悔・願望（仮定法過去完了）", kp: ["wish + had studied = 勉強していればよかった（過去の後悔）", "wish + studied（過去形）= 現在の事実への後悔"] },
  { id: "g1151", diff: "lv2", axis: "vocab", tags: ["eiken3", "preposition_transport"], stem: "We traveled to Osaka ___ the Shinkansen.", ja: "私たちは新幹線で大阪に行った。", answer: "by", choices: ["by", "through", "with", "in", "via"], expl: "交通手段を表す場合はby + 無冠詞の交通手段名を使う。by train / by bus / by plane など。onはon the train（特定の列車に乗って）のように冠詞がつく場合に使う。", rule: "by + 無冠詞名詞：交通手段（by train / by bus / by car）", kp: ["by the Shinkansen（×）→ by Shinkansen（○）", "交通手段のbyは無冠詞"] },
  { id: "g1152", diff: "lv3", axis: "form", tags: ["eiken2", "cleft_sentence"], stem: "___ my brother who broke the window, not me.", ja: "窓を割ったのは私ではなく兄だ。", answer: "It was", choices: ["It was", "It is", "There was", "That was", "He was"], expl: "強調構文「It is/was + 強調したい語句 + that/who + 残りの文」で特定の部分を強調する。過去の出来事を強調しているのでIt was。強調しているのが人物（my brother）なのでwhoを使う。", rule: "強調構文: It is/was + [強調語句] + that/who + 残り", kp: ["It was my brother who ... = 窓を割ったのは兄だ（人を強調）", "It was yesterday that ... = 昨日〜した（時を強調）"] },
  { id: "g1153", diff: "lv2", axis: "form", tags: ["eiken3", "comparative_as_as"], stem: "This book is ___ interesting ___ that one.", ja: "この本はあの本と同じくらい面白い。", answer: "as / as", choices: ["as / as", "more / than", "so / that", "as / that", "so / as"], expl: "同等比較は「as + 形容詞/副詞 + as」の形を使う。「この本はあの本と同じくらい面白い」はas interesting as で表す。", rule: "as + 形容詞/副詞 + as：〜と同じくらい（同等比較）", kp: ["as interesting as = 同じくらい面白い", "not as ... as = 〜ほど…ではない（劣等比較）"] },
  { id: "g1154", diff: "lv3", axis: "form", tags: ["eiken2", "past_perfect"], stem: "When I arrived at the station, the train ___.", ja: "駅に着いた時、電車はすでに出発していた。", answer: "had already left", choices: ["had already left", "already left", "has already left", "was already leaving", "already had left"], expl: "過去完了（had + 過去分詞）は、過去のある時点よりもさらに前に完了した動作を表す。「着いた時点」よりも前に「電車が出発した」ので過去完了を使う。", rule: "過去完了: had + 過去分詞（過去のある時点よりも前に完了した行為）", kp: ["had left = （私が着いた時より）前に出発した", "過去完了は過去の基準時点よりもさらに前の出来事に使う"] },
  { id: "g1155", diff: "lv2", axis: "logic", tags: ["eiken3", "however"], stem: "___ hard I try, I can never beat him at chess.", ja: "どんなに一生懸命やっても彼にチェスで勝てない。", answer: "However", choices: ["However", "Whatever", "Wherever", "Whenever", "Whoever"], expl: "however + 形容詞/副詞 + S + V で「どんなに〜しても」という譲歩を表す。however hard I try = no matter how hard I try。", rule: "however + 形容詞/副詞 + S + V：どんなに〜しても（= no matter how）", kp: ["however hard = どんなに一生懸命でも", "however = no matter how（譲歩の副詞節）"] },
  { id: "g1156", diff: "lv3", axis: "form", tags: ["eiken2", "causative_have"], stem: "I'll ___ the car washed before the trip.", ja: "旅行の前に車を洗ってもらうつもりだ。", answer: "have", choices: ["have", "make", "let", "take", "do"], expl: "have + 目的語 + 過去分詞で「〜してもらう（第三者に依頼）」を表す使役表現。have the car washed = 車を洗ってもらう（業者などに依頼）。get + 目的語 + 過去分詞も同じ意味だが選択肢にない。", rule: "have + O + 過去分詞：Oを〜してもらう（依頼の使役）", kp: ["have the car washed = 車を洗ってもらう", "have + O + 原形 = Oに〜させる（能動の使役）"] },
  { id: "g1157", diff: "lv2", axis: "vocab", tags: ["eiken3", "adjective_enough"], stem: "He is old ___ to drive a car.", ja: "彼は車を運転できる年齢だ。", answer: "enough", choices: ["enough", "too", "very", "quite", "rather"], expl: "enough + 不定詞で「〜するのに十分な」を表す。形容詞の後にenoughを置き、to不定詞が続く。too + 形容詞 + to-V は「〜すぎて…できない」という否定の意味になる。", rule: "形容詞 + enough + to-V：〜するのに十分な", kp: ["old enough to drive = 運転できるほど年齢に達している", "too young to drive = 若すぎて運転できない（否定）"] },
  { id: "g1158", diff: "lv3", axis: "form", tags: ["eiken2", "gerund_subject"], stem: "___ regularly is important for good health.", ja: "定期的に運動することは健康に大切だ。", answer: "Exercising", choices: ["Exercising", "To exercising", "Exercise", "Exercises", "Exercised"], expl: "動名詞（V-ing）は文の主語になれる。Exercising regularly = 定期的に運動すること。To exercise も可能だが、動名詞の方が習慣的・一般的な行為を主語にする場合によく使われる。", rule: "動名詞（V-ing）が主語：〜することは（一般的・習慣的行為）", kp: ["Exercising regularly = 定期的に運動すること（主語）", "動名詞主語は3人称単数扱い（is / was）"] },
  { id: "g1159", diff: "lv2", axis: "logic", tags: ["eiken3", "preposition_about"], stem: "She's very worried ___ her final exam.", ja: "彼女は期末試験のことをとても心配している。", answer: "about", choices: ["about", "for", "of", "with", "at"], expl: "be worried about は「〜について心配している」という定型表現。be afraid of（〜を恐れている）、be concerned about（〜を心配している）とも関連させて覚える。", rule: "be worried about + 名詞/動名詞：〜について心配している", kp: ["be worried about = 〜を心配している", "be concerned about / be anxious about も同義"] },
  { id: "g1160", diff: "lv3", axis: "form", tags: ["eiken2", "future_perfect"], stem: "By next Monday, I ___ this report.", ja: "来週月曜日までには、このレポートを書き終えているだろう。", answer: "will have finished", choices: ["will have finished", "will finish", "have finished", "will be finishing", "finish"], expl: "未来完了形（will have + 過去分詞）は「未来のある時点までに〜し終えている」という完了を表す。by next Monday という期限を示す表現と共に使う。", rule: "will have + 過去分詞：未来のある時点までに〜し終えている（未来完了）", kp: ["will have finished by Monday = 月曜日までには終えているだろう", "by + 未来の時点 と共に未来完了を使う"] },
  { id: "g1161", diff: "lv2", axis: "form", tags: ["eiken3", "relative_pronoun_whom"], stem: "The teacher ___ I spoke to was very helpful.", ja: "私が話しかけた先生はとても親切だった。", answer: "whom", choices: ["whom", "what", "which", "where", "whose"], expl: "関係代名詞whomは目的格で、先行詞が人の場合に使う。ここではthe teacherが先行詞で、I spoke to の目的語（to whom I spoke）になっている。口語ではthatや省略も多い。", rule: "whom：人を先行詞とする関係代名詞の目的格", kp: ["the teacher whom I spoke to = 私が話しかけた先生", "whomは目的格（spoke toの目的語）"] },
  { id: "g1162", diff: "lv3", axis: "logic", tags: ["eiken2", "not_only_but_also"], stem: "She speaks ___ French ___ German.", ja: "彼女はフランス語だけでなくドイツ語も話す。", answer: "not only / but also", choices: ["not only / but also", "neither / nor", "both / and", "either / or", "not / but"], expl: "not only A but also B は「AだけでなくBも」という相関接続詞。both A and B は「AとBの両方」、neither A nor B は「AもBも〜ない」、either A or B は「AかBのどちらか」。", rule: "not only A but also B：AだけでなくBも", kp: ["not only French but also German = フランス語だけでなくドイツ語も", "相関接続詞: both/and, either/or, neither/nor, not only/but also"] },
  { id: "g1163", diff: "lv2", axis: "form", tags: ["eiken3", "too_to"], stem: "This coffee is ___ hot ___ drink.", ja: "このコーヒーは熱すぎて飲めない。", answer: "too / to", choices: ["too / to", "so / that", "very / to", "enough / to", "as / as"], expl: "too + 形容詞/副詞 + to-V で「〜すぎて…できない」という否定の意味を表す。too hot to drink = 飲めないほど熱い。so ... that ... も近い意味だが構造が異なる。", rule: "too + 形容詞/副詞 + to-V：〜すぎて…できない（否定の意味）", kp: ["too hot to drink = 熱すぎて飲めない", "too tired to walk = 疲れすぎて歩けない"] },
  { id: "g1164", diff: "lv3", axis: "form", tags: ["eiken2", "passive_infinitive"], stem: "The rules are expected ___ by all players.", ja: "ルールはすべての選手に守られることが期待されている。", answer: "to be followed", choices: ["to be followed", "to follow", "being followed", "to have followed", "follow"], expl: "be expected + to不定詞の受動態は「〜されることが期待されている」。受動態の不定詞はto + be + 過去分詞の形になる。主語のthe rulesがfollow（従う）される対象なので受動態の不定詞を使う。", rule: "to be + 過去分詞：不定詞の受動態（〜されること）", kp: ["to be followed = 従われること（不定詞の受動態）", "be expected to be followed = 守られることが期待される"] },
  { id: "g1165", diff: "lv2", axis: "vocab", tags: ["eiken3", "preposition_at_in_on_time"], stem: "The meeting starts ___ 9 o'clock sharp.", ja: "会議はきっかり9時に始まる。", answer: "at", choices: ["at", "in", "on", "by", "from"], expl: "具体的な時刻にはatを使う。at 9 o'clock / at noon / at midnight。inは午前・午後・夜などの時間帯（in the morning）、onは曜日・特定の日（on Monday / on April 3rd）に使う。", rule: "at + 時刻（具体的な時刻点）", kp: ["at 9 o'clock / at noon / at midnight", "in the morning / in 2026（期間・年）/ on Monday（曜日・日付）"] },
  { id: "g1166", diff: "lv3", axis: "form", tags: ["eiken2", "inversion_negative"], stem: "___ did I imagine that I would win the championship.", ja: "まさか選手権で優勝するとは思いもしなかった。", answer: "Never", choices: ["Never", "Always", "Sometimes", "Often", "Certainly"], expl: "否定副詞（never, rarely, seldom, hardly, not only など）を文頭に置くと、主語と助動詞が倒置される。Never did I imagine = I never imagined の強調倒置形。", rule: "否定副詞の倒置: Never/Rarely/Seldom + 助動詞 + S + V", kp: ["Never did I imagine = 思いもしなかった（倒置・強調）", "否定副詞が文頭 → 疑問文と同じ語順（倒置）"] },
  { id: "g1167", diff: "lv3", axis: "logic", tags: ["eiken2", "concession_although"], stem: "___ he was tired, he kept working until midnight.", ja: "疲れていたにもかかわらず、彼は真夜中まで働き続けた。", answer: "Although", choices: ["Although", "Because", "Therefore", "Since", "So"], expl: "althoughは「〜にもかかわらず」という逆接の接続詞。even though / though も同様。becauseは理由、thereforeは結果（接続副詞）、sinceは理由・時間を表す。", rule: "although / even though / though：〜にもかかわらず（逆接）", kp: ["although tired = 疲れていたにもかかわらず", "although = even though = though（逆接の接続詞）"] },
  { id: "g1168", diff: "lv2", axis: "form", tags: ["eiken3", "relative_adverb_when"], stem: "I remember the day ___ we first met.", ja: "私たちが初めて出会ったあの日のことを覚えている。", answer: "when", choices: ["when", "which", "that", "where", "whose"], expl: "関係副詞whenは先行詞が時を表す名詞（the day, the year, the moment など）の場合に使う。「その日に私たちは初めて出会った」→ on which = when。", rule: "関係副詞 when：先行詞が時を表す語（the day / the year / the moment）", kp: ["the day when we met = 私たちが出会った日", "when = on which（関係副詞）"] },
  { id: "g1169", diff: "lv2", axis: "form", tags: ["eiken3", "participial_adjective"], stem: "Look at the ___ children in the park.", ja: "公園で遊んでいる子供たちを見て。", answer: "playing", choices: ["playing", "played", "to play", "play", "playful"], expl: "現在分詞（V-ing）は名詞を前から修飾し「〜している」という能動・進行の意味を表す。the playing children = 遊んでいる子供たち。過去分詞（played）は受動の意味になり不自然。", rule: "現在分詞の形容詞的用法：名詞 + V-ing = 〜している（名詞）", kp: ["playing children = 遊んでいる子供たち（現在分詞）", "V-ing = 能動・進行 / 過去分詞 = 受動・完了"] },
  { id: "g1170", diff: "lv3", axis: "form", tags: ["eiken2", "such_that"], stem: "It was ___ a hot day ___ we stayed indoors all afternoon.", ja: "とても暑い日だったので、私たちは午後ずっと屋内にいた。", answer: "such / that", choices: ["such / that", "so / that", "too / to", "very / to", "such / as"], expl: "such + a(n) + 形容詞 + 名詞 + that で「とても〜なので…だ」という結果を表す。so + 形容詞 + that の形と混同しないこと。名詞があるときはsuch a hot day、名詞がないときはso hotを使う。", rule: "such a(n) + 形容詞 + 名詞 + that：とても〜なので…（結果）", kp: ["such a hot day that = とても暑い日なので（名詞あり→such）", "so hot that = とても暑いので（名詞なし→so）"] },
  { id: "g1171", diff: "lv2", axis: "logic", tags: ["eiken3", "conjunction_until"], stem: "Please wait here ___ I come back.", ja: "私が戻るまでここで待っていてください。", answer: "until", choices: ["until", "when", "while", "before", "after"], expl: "until（〜するまでずっと）は動作・状態が継続する期限を表す。waitは継続動作なのでuntilと相性がよい。beforeは「〜する前に」、whenは「〜したとき」で継続の意味を持たない。", rule: "until + S + V：〜するまで（ずっと）（継続期限）", kp: ["wait until I come back = 戻るまで待つ", "until = 〜するまでずっと（継続） vs before = 〜する前に（時点）"] },
  { id: "g1172", diff: "lv3", axis: "form", tags: ["eiken2", "reported_speech"], stem: "He said that he ___ finish the project by Friday.", ja: "彼は金曜日までにプロジェクトを終えると言った。", answer: "would", choices: ["would", "will", "can", "may", "shall"], expl: "直接話法 \"I will finish...\" を間接話法に変えると時制の一致でwill→wouldになる。過去の発言を報告するとき、主節が過去形なら従属節の助動詞も過去形にする（will→would, can→could）。", rule: "時制の一致：主節が過去形のとき、従属節の will → would / can → could", kp: ["said that he would finish = 終えると言った（will→would）", "時制の一致: will/can/may → would/could/might"] },
  { id: "g1173", diff: "lv3", axis: "vocab", tags: ["eiken2", "would_rather"], stem: "I ___ stay home than go to that party.", ja: "あのパーティーへ行くよりも家にいたい。", answer: "would rather", choices: ["would rather", "had better", "would like", "used to", "ought to"], expl: "would rather + 動詞原形 + than + 動詞原形で「〜するよりも〜したい」という好みを表す。had betterは「〜したほうがよい（忠告）」、would likeは「〜したい（丁寧な希望）」で意味が異なる。", rule: "would rather A than B：BよりもAしたい（好みの選択）", kp: ["would rather stay than go = 行くより家にいたい", "would rather + 動詞原形（toなし）"] },
  { id: "g1174", diff: "lv3", axis: "form", tags: ["eiken2", "comparative_the_the"], stem: "___ harder you work, ___ more successful you will be.", ja: "一生懸命働けば働くほど、より成功するだろう。", answer: "The / the", choices: ["The / the", "A / a", "More / more", "As / as", "So / so"], expl: "「〜すればするほど…だ」はthe + 比較級 + S + V, the + 比較級 + S + Vの構文。両方にtheを使う。The harder you work, the more successful you will be.が正しい形。", rule: "The + 比較級 + S + V, the + 比較級 + S + V：〜すればするほど…だ", kp: ["The harder ~ the more ~ = 〜すればするほど…", "the + 比較級の構文は2つのthe"] },
  { id: "g1175", diff: "lv3", axis: "form", tags: ["eiken2", "participial_clause"], stem: "___ all the windows, she went to sleep.", ja: "窓を全部閉めてから彼女は眠りについた。", answer: "Closing", choices: ["Closing", "Closed", "To close", "After closed", "Having close"], expl: "分詞構文（V-ing + 残りの文）は主語と分詞の意味上の主語が一致するときに使う。「彼女が窓を閉めた」ので能動の現在分詞Closingを使う。過去分詞Closedでは「閉められた（受動）」になり主語と合わない。", rule: "分詞構文 V-ing + 残りの文：副詞節を分詞で簡潔に表す", kp: ["Closing all the windows = 窓を閉めてから（能動・現在分詞）", "分詞の意味上の主語 = 主文の主語（一致が必須）"] },
  { id: "g1176", diff: "lv3", axis: "form", tags: ["eiken2", "non_restrictive_which"], stem: "She passed the exam, ___ surprised everyone.", ja: "彼女は試験に合格したが、それはみんなを驚かせた。", answer: "which", choices: ["which", "that", "what", "it", "and that"], expl: "非制限用法の関係代名詞は前の節全体や名詞を「補足的に説明」するときに使い、コンマの後にwhichを置く。thatは非制限用法では使えない。「彼女が合格した（という事実）が、みんなを驚かせた」という追加情報を表す。", rule: "非制限用法: コンマ + which（先行詞は前の節全体も可）", kp: ["she passed, which surprised everyone = 合格した（それが）みんなを驚かせた", "非制限用法にthatは使えない"] },
  { id: "g1177", diff: "lv3", axis: "logic", tags: ["eiken2", "whoever"], stem: "___ breaks the rules will be disqualified.", ja: "ルールを破った者は誰でも失格になる。", answer: "Whoever", choices: ["Whoever", "Whomever", "Anyone", "Whatever", "Whichever"], expl: "複合関係詞whoever = anyone whoで「〜する人は誰でも」という意味。文の主語になる場合はwhoever（主格）を使う。whomeverは目的格なので「〜する人を誰でも」の場合に使う。", rule: "whoever + V：〜する人は誰でも（= anyone who）", kp: ["whoever breaks = ルールを破る人は誰でも", "whoever（主格）vs whomever（目的格）"] },
  { id: "g1178", diff: "lv2", axis: "form", tags: ["eiken3", "stop_gerund_infinitive"], stem: "She stopped ___ and listened carefully.", ja: "彼女は話すのをやめて注意深く聞いた。", answer: "talking", choices: ["talking", "to talk", "talk", "talked", "to talking"], expl: "stop + 動名詞は「〜するのをやめる」という意味。stop + to不定詞は「〜するために立ち止まる」という目的を表す全く異なる意味になる。ここでは「話すのをやめた」なのでstop talking。", rule: "stop + V-ing：〜するのをやめる（動名詞）", kp: ["stopped talking = 話すのをやめた", "stopped to talk = 話すために立ち止まった（to不定詞＝目的）"] },
  { id: "g1179", diff: "lv3", axis: "form", tags: ["eiken2", "present_perfect_progressive"], stem: "She ___ for the company for five years.", ja: "彼女はその会社に5年間勤めている。", answer: "has been working", choices: ["has been working", "will be working", "is working", "worked", "had worked"], expl: "現在完了進行形（have been + V-ing）は過去のある時点から現在まで継続している動作を強調する。現在完了（has worked）も使えるが、forを伴う継続動作には完了進行形がよりニュアンスを明確に表す。", rule: "現在完了進行形: have/has been + V-ing（継続・動作の強調）", kp: ["has been working for five years = 5年間ずっと働いている（継続）", "現在完了進行形 = 動作の継続中を強調"] },
  { id: "g1180", diff: "lv2", axis: "vocab", tags: ["eiken3", "be_known_to"], stem: "This singer is well ___ to young people in Japan.", ja: "この歌手は日本の若者によく知られている。", answer: "known", choices: ["known", "knowing", "know", "knows", "to know"], expl: "be known to + 人で「（人）に知られている」という受動表現。be well known to = よく知られている。be known for（〜で有名）、be known as（〜として知られる）とも区別して覚えること。", rule: "be known to + 人：（人）に知られている", kp: ["be known to young people = 若者に知られている", "known for（〜で有名）/ known as（〜として）/ known to（〜に知られる）"] },
  { id: "g1181", diff: "lv2", axis: "form", tags: ["eiken3", "exclamation_what"], stem: "___ a beautiful sunset it is!", ja: "なんと美しい夕日だろう！", answer: "What", choices: ["What", "How", "So", "Such", "What a"], expl: "感嘆文はWhat + a(n) + 形容詞 + 名詞 + (S + V)!またはHow + 形容詞/副詞 + (S + V)!の形。ここでは名詞（sunset）があるのでWhatを使う。What a beautiful sunsetとなるが選択肢の都合上Whatを選ぶ（aは文中に既にある）。", rule: "感嘆文: What + a(n) + 形容詞 + 名詞（名詞あり）/ How + 形容詞（名詞なし）", kp: ["What a beautiful sunset! = なんと美しい夕日（名詞あり→What）", "How beautiful! = なんと美しい（名詞なし→How）"] },
  { id: "g1182", diff: "lv3", axis: "form", tags: ["eiken2", "subjunctive_suggest"], stem: "The doctor suggested that he ___ more rest.", ja: "医者は彼がもっと休養を取るよう提案した。", answer: "take", choices: ["take", "takes", "took", "should taking", "to take"], expl: "suggest/recommend/insist/demand + that節では仮定法現在（動詞の原形）を使う（米語）。主語が3人称単数でもtakesとせずtakeを使う。イギリス英語ではshould takeとすることもある。", rule: "suggest/recommend + that + S + 動詞原形（仮定法現在）", kp: ["suggested that he take = 仮定法現在（原形）", "3人称単数でもtakesではなくtake（仮定法現在）"] },
  { id: "g1183", diff: "lv3", axis: "form", tags: ["eiken2", "if_only"], stem: "If only I ___ a bit more time!", ja: "もう少し時間があればなあ！", answer: "had", choices: ["had", "have", "will have", "would have", "could have"], expl: "if only + 仮定法で「〜であればなあ」という願望や後悔を表す。現在の事実に反する願望（今時間がない）にはif only + 過去形（had）を使う。過去の後悔にはif only + had + 過去分詞を使う。", rule: "if only + 過去形：〜であればなあ（現在の願望・仮定法過去）", kp: ["if only I had = 時間があればなあ（今の願望）", "if only I had had = あればよかった（過去の後悔）"] },
  { id: "g1184", diff: "lv2", axis: "vocab", tags: ["eiken3", "during_vs_for"], stem: "I slept ___ the long journey.", ja: "長い旅の間、私は眠った。", answer: "during", choices: ["during", "for", "while", "through", "between"], expl: "duringは「（特定の期間・出来事）の間」という意味で、後に名詞句が続く。forは「（時間の長さ）の間」という意味で数量を表す名詞が続く（for three hours）。whileは接続詞なのでS+Vが続く。", rule: "during + 名詞（特定期間）/ for + 数量表現（時間の長さ）", kp: ["during the journey = 旅の間（特定の出来事→during）", "for three hours = 3時間の間（時間の長さ→for）"] },
  { id: "g1185", diff: "lv2", axis: "vocab", tags: ["eiken3", "look_forward_to"], stem: "I'm looking forward to ___ you again soon.", ja: "またすぐにあなたにお会いできることを楽しみにしています。", answer: "seeing", choices: ["seeing", "see", "be seen", "have seen", "to see"], expl: "look forward to + 動名詞で「〜することを楽しみにしている」。toは前置詞なので後には動名詞（V-ing）が続く。to不定詞の記号（to + 動詞原形）と混同しやすいが、ここでのtoは前置詞。", rule: "look forward to + V-ing：〜することを楽しみにしている（to = 前置詞）", kp: ["look forward to seeing = 会うことを楽しみにしている", "to の後は動名詞（to = 前置詞、not 不定詞のto）"] },
  { id: "g1186", diff: "lv2", axis: "vocab", tags: ["eiken3", "few_a_few"], stem: "I have ___ friends in this city, so I'm not lonely.", ja: "この街に友人が数人いるので、寂しくない。", answer: "a few", choices: ["a few", "few", "little", "a little", "some"], expl: "a few は「少しある（ポジティブ）」、few は「ほとんどない（ネガティブ）」という意味の差がある。「寂しくない」という文脈からポジティブなa fewが適切。littleは不可算名詞に使う。", rule: "a few（少しある・ポジティブ）vs few（ほとんどない・ネガティブ）＋可算名詞", kp: ["a few friends = 数人の友達がいる（ポジティブ）", "few friends = 友達がほとんどいない（ネガティブ）"] },
  { id: "g1187", diff: "lv2", axis: "logic", tags: ["eiken3", "in_case"], stem: "Take an umbrella ___ it rains.", ja: "雨が降った場合に備えて傘を持って行きなさい。", answer: "in case", choices: ["in case", "if", "unless", "so that", "in order to"], expl: "in case + S + V で「〜の場合に備えて」という予防的な準備を表す。ifが「もし〜なら（その時）」という条件に対し、in caseは「〜するかもしれないから、念のために」という予防・準備の意味がある。", rule: "in case + S + V：〜の場合に備えて（予防・準備）", kp: ["in case it rains = 雨が降った場合に備えて", "in case（予防・準備） vs if（条件・仮定）"] },
  { id: "g1188", diff: "lv2", axis: "form", tags: ["eiken3", "ask_o_to"], stem: "My teacher asked me ___ the question again.", ja: "先生は私にもう一度その質問に答えるよう頼んだ。", answer: "to answer", choices: ["to answer", "answering", "answer", "answered", "that answer"], expl: "ask + O + to-V で「O に〜するよう頼む」という意味。この構文ではto不定詞を使う。ask + O + V-ing や ask + O + V は正しくない。tell / want / order + O + to-V も同様の構文。", rule: "ask / tell / want + O + to-V：O に〜するよう頼む・言う・望む", kp: ["asked me to answer = 私に答えるよう頼んだ", "tell / want / ask + O + to-V の形で覚える"] },
  { id: "g1189", diff: "lv2", axis: "form", tags: ["eiken3", "present_perfect_already"], stem: "She has ___ finished her homework.", ja: "彼女はもう宿題を終わらせてしまった。", answer: "already", choices: ["already", "yet", "still", "just now", "ever"], expl: "alreadyは肯定文で「もう・すでに」という意味を表し、have + already + 過去分詞の形をとる。yetは疑問文・否定文で使う（Have you done it yet? / I haven't done it yet.）。", rule: "現在完了 + already（肯定文）/ yet（疑問・否定文）", kp: ["has already finished = もう終わらせた（肯定文→already）", "yet は疑問文・否定文で使う（Have you ... yet?）"] },
  { id: "g1190", diff: "lv2", axis: "logic", tags: ["eiken3", "both_and"], stem: "___ Tom and Mary came to the party.", ja: "トムもメアリーもパーティーに来た。", answer: "Both", choices: ["Both", "Either", "Neither", "All", "Each"], expl: "both A and B で「AもBも両方とも」という意味。動詞は複数形になる。either A or B は「AかBのどちらか一方」、neither A nor B は「AもBも〜でない」。", rule: "both A and B：AもBも（両方）→ 動詞は複数形", kp: ["both Tom and Mary came = トムもメアリーも来た（複数扱い）", "either A or B（どちらか一方）/ neither A nor B（どちらも〜でない）"] },
  { id: "g1191", diff: "lv2", axis: "vocab", tags: ["eiken3", "as_soon_as"], stem: "___ I arrived home, I took a shower.", ja: "家に着くとすぐに、私はシャワーを浴びた。", answer: "As soon as", choices: ["As soon as", "As long as", "As far as", "So that", "In case"], expl: "as soon as は「〜するとすぐに」という時の接続詞。as long as は「〜する限り（条件）」、as far as は「〜する限り（範囲）」。時・条件の副詞節では未来のことでも現在形を使う。", rule: "as soon as + S + V：〜するとすぐに（時の接続詞）", kp: ["as soon as I arrived = 着くとすぐに", "as long as（〜する限り）/ as far as（〜する範囲で）と区別"] },
  { id: "g1192", diff: "lv3", axis: "form", tags: ["eiken2", "get_passive"], stem: "My wallet ___ stolen on the train yesterday.", ja: "昨日、電車で財布を盗まれた。", answer: "got", choices: ["got", "is", "had", "has", "been"], expl: "get + 過去分詞は受動態の口語的表現で「〜される・〜された」を表す。was stolen（be受動態）も文法的には正しいが、口語的表現としてget受動態もよく使われる。get + 過去分詞は突発的・予期しない出来事に多く使われる。", rule: "get + 過去分詞：〜される（口語的受動態、突発的出来事）", kp: ["got stolen = 盗まれた（口語的・突発的）", "be受動態より口語的・動作的なニュアンス"] },
  { id: "g1193", diff: "lv2", axis: "form", tags: ["eiken3", "formal_subject_it"], stem: "___ is important to exercise every day.", ja: "毎日運動することは大切だ。", answer: "It", choices: ["It", "This", "That", "There", "What"], expl: "it is + 形容詞 + to-V の形式主語構文。本来の主語はto exercise every dayだが、長い主語を後ろに置くためにitを形式主語（仮主語）として文頭に置く。This/Thatは指示代名詞なので文頭の形式主語として使えない。", rule: "It is + 形容詞 + to-V：〜することは…だ（形式主語it）", kp: ["It is important to exercise = 運動することは大切（形式主語）", "真主語は to-V の部分（本来の主語が後ろに移動）"] },
  { id: "g1194", diff: "lv2", axis: "form", tags: ["eiken3", "past_progressive"], stem: "When I called him, he ___ dinner.", ja: "私が電話した時、彼は夕食を食べているところだった。", answer: "was having", choices: ["was having", "had", "has had", "is having", "were having"], expl: "過去進行形（was/were + V-ing）は過去のある時点で進行中だった動作を表す。when節（過去形）が「電話した時」という特定の時点を示し、その時点で進行中だったことをwas havingで表す。主語がheなのでwereではなくwasを使う。", rule: "過去進行形 was/were + V-ing：過去のある時点で進行中だった動作", kp: ["was having dinner = 夕食を食べているところだった（過去進行）", "when + 過去形で時点を示し、過去進行形で進行中の動作を表す"] },
  { id: "g1195", diff: "lv2", axis: "vocab", tags: ["eiken3", "must_obligation"], stem: "You ___ return the books to the library by Friday.", ja: "金曜日までに本を図書館に返却しなければなりません。", answer: "must", choices: ["must", "should", "may", "can", "would"], expl: "must は「〜しなければならない（強い義務）」を表す。shouldは「〜すべき（道徳的義務・アドバイス）」、mayは「〜してもよい（許可）」、canは「〜できる（能力・許可）」。期日があり、強い義務を示す文脈ではmustが最適。", rule: "must：強い義務（〜しなければならない）/ should：道徳的義務・アドバイス", kp: ["must return = 返却しなければならない（強い義務）", "must（義務）/ should（アドバイス）/ may（許可）/ can（能力）"] },
  { id: "g1196", diff: "lv2", axis: "logic", tags: ["eiken3", "although_concession"], stem: "___ it was raining, we went for a walk.", ja: "雨が降っていたが、私たちは散歩に出かけた。", answer: "Although", choices: ["Although", "Because", "Since", "So", "Therefore"], expl: "although / though は「〜にもかかわらず・〜だけれども」という逆接の接続詞。because / sinceは理由を表す。So / Thereforeは結果を表す。雨が降っているのに散歩に出たという逆接の文脈にはalthoughが適切。", rule: "although / though + S + V：〜にもかかわらず（逆接の接続詞）", kp: ["although it was raining = 雨が降っていたにもかかわらず", "although（逆接）/ because（理由）/ so（結果）"] },
  { id: "g1197", diff: "lv2", axis: "form", tags: ["eiken3", "what_relative_noun"], stem: "Please tell me ___ you want for your birthday.", ja: "誕生日に何が欲しいか教えてください。", answer: "what", choices: ["what", "which", "that", "how", "where"], expl: "whatは関係代名詞・疑問詞として「〜のもの・〜すること（先行詞を含む）」という意味を持つ。tell me whatは間接疑問文で「何が欲しいか」という意味。tell me that は「〜であること」となり意味が変わる。", rule: "what = 先行詞を含む関係代名詞 / 間接疑問文の疑問詞（何〜か）", kp: ["what you want = あなたが欲しいもの（先行詞含む関係代名詞）", "tell me what = 何が〜か教える（間接疑問）"] },
  { id: "g1198", diff: "lv3", axis: "form", tags: ["eiken2", "as_if_subjunctive"], stem: "He talks ___ he knew everything.", ja: "彼はまるで何でも知っているかのように話す。", answer: "as if", choices: ["as if", "even if", "in case", "so that", "in order that"], expl: "as if / as though は「まるで〜であるかのように」という様態を表す接続詞。仮定法過去（knew）が使われているのは、実際には何でも知っているわけではない（事実に反する）ため。as thoughも同義だが選択肢にas ifがあれば通常こちらを選ぶ。", rule: "as if / as though + 仮定法：まるで〜であるかのように（事実に反する様態）", kp: ["as if he knew = まるで知っているかのように（実際は知らない）", "as if + 仮定法過去（現在の事実に反する）"] },
  { id: "g1199", diff: "lv2", axis: "vocab", tags: ["eiken3", "mind_gerund"], stem: "Would you ___ opening the window?", ja: "窓を開けていただけませんか？", answer: "mind", choices: ["mind", "enjoy", "finish", "avoid", "suggest"], expl: "mind + 動名詞で「〜することを気にする・嫌だと思う」という意味。Would you mind V-ing?は「〜していただけませんか？（〜することを気にしますか？）」という丁寧な依頼表現。承諾する場合は「Not at all. / Of course not.」と答える。", rule: "mind + V-ing：〜することを気にする / Would you mind V-ing?：〜していただけますか？", kp: ["Would you mind opening? = 開けていただけますか？（丁寧な依頼）", "承諾: Not at all. / 断り: I'm sorry, but..."] },
  { id: "g1200", diff: "lv3", axis: "form", tags: ["eiken2", "emphatic_do"], stem: "I ___ enjoy reading novels, though I'm busy.", ja: "忙しいけれど、私は本当に小説を読むのが好きだ。", answer: "do", choices: ["do", "did", "have", "am", "very"], expl: "強調のdo（現在形）は動詞の前に置いて「本当に・確かに」という強意を表す。主語がIで時制が現在なのでdoを使う。主語が三人称単数ならdoes、過去ならdidを使う。この構文では本動詞はenjoyのまま変化しない。", rule: "強調の do/does/did + 動詞原形：本当に〜する（強調）", kp: ["I do enjoy = 本当に楽しむ（強調）", "do/does/did は主語・時制に合わせる。本動詞は原形のまま"] },
  { id: "g1201", diff: "lv2", axis: "form", tags: ["eiken3", "used_to_habit"], stem: "My grandfather ___ walk to school every day.", ja: "祖父はかつて毎日歩いて学校へ行っていた。", answer: "used to", choices: ["used to", "is used to", "was used to", "would to", "has used to"], expl: "used to + 動詞原形は「かつて〜していた（今はしていない）」という過去の習慣や状態を表す。be used to + V-ing は「〜することに慣れている（現在）」という全く異なる表現なので注意。wouldも過去の習慣を表せるが、状態動詞（know, live等）にはused toを使う。", rule: "used to + 動詞原形：かつて〜していた（過去の習慣・状態）", kp: ["used to walk = かつて歩いていた（今はしていない）", "be used to V-ing（〜に慣れている）と混同しないこと"] },
  { id: "g1202", diff: "lv2", axis: "form", tags: ["eiken3", "superlative_ever"], stem: "This is ___ movie I've ever seen.", ja: "これは私が今まで見た中で最も面白い映画だ。", answer: "the most interesting", choices: ["the most interesting", "more interesting", "most interesting", "the more interesting", "interesting most"], expl: "最上級は the + most + 形容詞（3音節以上）または the + 形容詞-est（1〜2音節）の形をとる。I've ever seenが「今までで」という最上級の強調表現。theが必要なので「most interesting」だけでは誤り。", rule: "最上級: the + most + 形容詞（3音節以上）+ I've ever + 過去分詞", kp: ["the most interesting movie I've ever seen = 今まで見た中で最も面白い映画", "最上級にはtheが必要。I've ever seenが最上級を強調"] },
  { id: "g1203", diff: "lv2", axis: "vocab", tags: ["eiken3", "infinitive_purpose"], stem: "I went to the store ___ some milk.", ja: "牛乳を買いに店へ行った。", answer: "to get", choices: ["to get", "for get", "getting", "for getting", "get"], expl: "目的を表す表現には to-V（〜するために）を使う。for + 動名詞は「〜することのために」という意味になり、went to the store for getting milk は不自然。目的を表すには to不定詞（to get）が正しい。", rule: "go / come + to-V：〜するために行く・来る（目的の不定詞）", kp: ["went to the store to get milk = 牛乳を買いに行った（目的）", "for + 動名詞は目的の表現として使わない（to-V が正しい）"] },
  { id: "g1204", diff: "lv3", axis: "form", tags: ["eiken2", "it_takes_time"], stem: "It ___ me two hours to finish the report.", ja: "そのレポートを終えるのに2時間かかった。", answer: "took", choices: ["took", "spent", "needed", "passed", "required"], expl: "It takes + 人 + 時間 + to-V で「（人）が〜するのに（時間）かかる」という表現。過去形はtook。spendは人を主語にする（I spent two hours...）。It takes は時間の所要を表す重要な構文。", rule: "It takes + 人 + 時間 + to-V：（人）が〜するのに（時間）かかる", kp: ["it took me two hours to finish = 終えるのに2時間かかった", "spend（人が主語）vs it takes（it が主語）"] },
  { id: "g1205", diff: "lv2", axis: "logic", tags: ["eiken3", "by_the_time"], stem: "___ the time he arrived, the movie had already started.", ja: "彼が到着した時には、映画はもう始まっていた。", answer: "By", choices: ["By", "At", "Until", "Before", "When"], expl: "by the time + S + V で「〜する時までには」という意味。by the time he arrivedは「彼が到着する時点までに」。主節では過去完了（had started）を使い、その時点より前に完了していたことを表す。", rule: "by the time + S + V：〜する時までには（期限）→ 主節は過去完了", kp: ["by the time he arrived = 彼が到着する時までには", "byの時点より前に完了→過去完了（had already started）"] },
  { id: "g1206", diff: "lv3", axis: "form", tags: ["eiken2", "have_something_done"], stem: "I had my hair ___ at the salon yesterday.", ja: "昨日、サロンで髪を切ってもらった。", answer: "cut", choices: ["cut", "cutting", "to cut", "cuts", "cutter"], expl: "have + O + 過去分詞で「O を〜してもらう（第三者に〜させる）」という使役表現。hair（O）とcut（動作）の関係が受動的（髪が切られる）なので過去分詞を使う。have + O + V-ing は「Oが〜しているのを放置する」という異なる意味になる。", rule: "have + O + 過去分詞：O を〜してもらう・〜される（使役・被害）", kp: ["had my hair cut = 髪を切ってもらった（Oが受動的）", "have + O + V-ing（〜しているのを放置）と区別"] },
  { id: "g1207", diff: "lv2", axis: "logic", tags: ["eiken3", "neither_inversion"], stem: "\"I don't like spicy food.\" \"___ do I.\"", ja: "「辛い食べ物は好きじゃない。」「私もです。」", answer: "Neither", choices: ["Neither", "So", "Either", "Nor", "Not"], expl: "否定文に同意する場合は Neither / Nor + 助動詞 + 主語 の倒置形を使う（Neither do I = 私も好きではない）。肯定文への同意にはSo + 助動詞 + 主語（So do I = 私もします）を使う。Eitherは否定文の付加的同意でも使えるが（I don't either）、倒置形にはNeitherを使う。", rule: "肯定同意: So + 助動詞 + S（私も〜だ）/ 否定同意: Neither + 助動詞 + S（私も〜でない）", kp: ["Neither do I = 私も好きではない（否定への同意・倒置）", "So do I = 私もします（肯定への同意・倒置）"] },
  { id: "g1208", diff: "lv2", axis: "form", tags: ["eiken3", "relative_whose"], stem: "I know a girl ___ father is a famous musician.", ja: "私は父親が有名な音楽家である少女を知っている。", answer: "whose", choices: ["whose", "who", "which", "that", "whom"], expl: "関係代名詞whoseは所有格を表し「〜の」という意味。先行詞（a girl）の父親について述べるため、所有格のwhoseを使う。who/thatは主格・目的格、whichは物に使う。", rule: "whose + 名詞：先行詞の〜の（所有格の関係代名詞）", kp: ["a girl whose father = 父親が〜の少女", "whose = 先行詞の所有格（人・物両方に使える）"] },
  { id: "g1209", diff: "lv2", axis: "vocab", tags: ["eiken3", "have_been_to_vs_gone"], stem: "She ___ to London twice, so she knows it well.", ja: "彼女はロンドンに2回行ったことがあるので、よく知っている。", answer: "has been", choices: ["has been", "has gone", "went", "had been", "goes"], expl: "have been to は「〜へ行ったことがある（今はここにいる）」という経験を表す。have gone to は「〜へ行ってしまった（今はそこにいる）」という結果を表す。She knows it well から現在ここにいることが分かるのでhas been toが正しい。", rule: "have been to：〜へ行ったことがある（経験・今はここに） / have gone to：〜へ行ってしまった（結果・今はそこに）", kp: ["has been to London twice = ロンドンに2回行った経験あり", "has gone to London = 今ロンドンへ行っていていない"] },
  { id: "g1210", diff: "lv3", axis: "form", tags: ["eiken2", "subjunctive_past"], stem: "If I ___ more free time, I would travel the world.", ja: "もっと自由な時間があれば、世界中を旅するのに。", answer: "had", choices: ["had", "have", "would have", "will have", "am having"], expl: "現在の事実に反する仮定を表す仮定法過去は「If + S + 過去形, S + would/could/might + 動詞原形」の形をとる。現在の事実（時間がない）とは反対の内容を述べているのでhad（過去形）を使う。", rule: "仮定法過去: If + S + 過去形, S + would + 動詞原形（現在の事実への反仮定）", kp: ["If I had = もし（今）持っていたら（仮定法・実際は持っていない）", "If I have（×）→ 実現可能な条件文になってしまう"] },
  { id: "g1211", diff: "lv2", axis: "form", tags: ["eiken3", "formal_object_it"], stem: "I find ___ difficult to understand his accent.", ja: "私は彼のなまりを理解するのが難しいと思う。", answer: "it", choices: ["it", "that", "this", "one", "so"], expl: "find + it + 形容詞 + to-V の形式目的語構文。itが形式目的語となり、真の目的語はto understand his accent。この構文ではitが不可欠でthat節は使えない。", rule: "find/make + it + 形容詞 + to-V：〜することが…だとわかる・感じる（形式目的語it）", kp: ["find it difficult to understand = 理解するのが難しいとわかる", "itが仮の目的語、to understand 以下が真の目的語"] },
  { id: "g1212", diff: "lv2", axis: "vocab", tags: ["eiken3", "each_every"], stem: "___ student in the class passed the test.", ja: "クラスの生徒全員がテストに合格した。", answer: "Every", choices: ["Every", "Most", "All", "Both", "Any"], expl: "Every + 単数名詞はグループ全体を一括りにして「全ての〜（例外なし）」という意味を強調する。Each + 単数名詞は「それぞれの〜（一人ひとり）」という個別性を強調する。All は複数名詞と共に使う（All students）。", rule: "every + 単数名詞：全ての〜（全体・例外なし） / each + 単数名詞：それぞれの〜（個別）", kp: ["every student = 全ての生徒（例外なく）", "each student = 生徒それぞれ（個別に）"] },
  { id: "g1213", diff: "lv2", axis: "logic", tags: ["eiken3", "although_though"], stem: "___ it was raining, we enjoyed the picnic.", ja: "雨が降っていたけれど、私たちはピクニックを楽しんだ。", answer: "Although", choices: ["Although", "Because", "If", "When", "Since"], expl: "逆接接続詞althoughは「〜だけれども、〜にもかかわらず」という意味で、メイン節と対照的な内容を導く。becauseは原因、ifは条件、whenは時、sinceは時間的継続または原因を表す。", rule: "although / though / even though：〜だけれども（逆接の従属接続詞）", kp: ["Although it was raining = 雨だったにもかかわらず（逆接）", "although ≈ though（though の方がやや口語的）"] },
  { id: "g1214", diff: "lv2", axis: "form", tags: ["eiken3", "much_far_comparative"], stem: "This laptop is ___ cheaper than the other one.", ja: "このノートパソコンはもう一方よりずっと安い。", answer: "much", choices: ["much", "very", "so", "too", "most"], expl: "比較級を強調する副詞にはmuch / far / even / a lot などを使う。veryは原級（形容詞・副詞）を強調するが、比較級には使えない。soもtooも比較級の強調には不適。", rule: "much / far / even / a lot + 比較級：ずっと〜（比較級の強調）", kp: ["much cheaper = ずっと安い（比較級の強調）", "very cheaper（×）→ very は原級のみ強調可能"] },
  { id: "g1215", diff: "lv2", axis: "form", tags: ["eiken3", "adjective_infinitive"], stem: "I need something ___ on this cold day.", ja: "この寒い日に何か温かいものが飲みたい。", answer: "hot to drink", choices: ["hot to drink", "to drink hot", "hot drinking", "for drinking hot", "drink hot"], expl: "something/anything/nothing などの不定代名詞を形容詞で修飾するときは「不定代名詞 + 形容詞 + to-V」の語順になる。形容詞は名詞の後ろに置く（something hot）、さらに不定詞が続く（to drink）。", rule: "something/anything + 形容詞 + to-V：〜するための何か（不定代名詞の修飾語順）", kp: ["something hot to drink = 何か温かい飲み物", "不定代名詞 + 形容詞（後置）+ to-V（形容詞的）"] },
  { id: "g1216", diff: "lv3", axis: "form", tags: ["eiken2", "reported_speech"], stem: "She said that she ___ finish the project by Friday.", ja: "彼女は金曜日までにプロジェクトを終わらせると言った。", answer: "would", choices: ["would", "will", "can", "shall", "may"], expl: "間接話法で過去の発言を報告するとき、主節が過去形（said）なら時制の一致により従属節の助動詞も過去形になる。will → would、can → could、may → might に変わる。", rule: "時制の一致: will → would / can → could / may → might（主節が過去形のとき）", kp: ["said that she would = 〜するだろうと言った（時制の一致）", "said that she will（×）→ 時制の一致でwillはwouldに"] },
  { id: "g1217", diff: "lv3", axis: "form", tags: ["eiken2", "participle_clause"], stem: "___ the station, he bought a cup of coffee.", ja: "駅に着いて、彼はコーヒーを1杯買った。", answer: "Arriving at", choices: ["Arriving at", "Arrived at", "Having arrived at", "To arrive at", "After arrived at"], expl: "分詞構文で主節と同時・直後の動作を表すには現在分詞（V-ing）を使う。主語（he）と動詞の関係が能動的（arrived）なので現在分詞Arriving。Having arrived atは主節の動作より前に完了した動作を表す（今回は同時か直後なのでArrivingが自然）。", rule: "分詞構文: V-ing + ..., S + V（主節と同時・直後の動作を簡潔に表す）", kp: ["Arriving at the station = 駅に着いて（同時・連続）", "Having arrived（主節より前に完了）vs Arriving（同時・直後）"] },
  { id: "g1218", diff: "lv3", axis: "logic", tags: ["eiken2", "not_only_but_also"], stem: "She ___ speaks French but also Japanese.", ja: "彼女はフランス語だけでなく日本語も話す。", answer: "not only", choices: ["not only", "both", "either", "neither", "not just only"], expl: "not only A but also B は「AだけでなくBも」という相関接続詞。both A and Bは「AとBの両方」、either A or Bは「AかBのどちらか」、neither A nor Bは「AもBも〜ない」を表す。", rule: "not only A but also B：AだけでなくBも（相関接続詞）", kp: ["not only French but also Japanese = フランス語だけでなく日本語も", "but also は省略されることもある（but also の also は略せる）"] },
  { id: "g1219", diff: "lv3", axis: "form", tags: ["eiken2", "passive_past_progressive"], stem: "The road ___ repaired when the accident happened.", ja: "事故が起きた時、道路は修理されているところだった。", answer: "was being", choices: ["was being", "has been", "was", "had been", "is being"], expl: "過去進行形の受動態は「was/were being + 過去分詞」の形。「〜されているところだった」という過去のある時点で進行中の受動的動作を表す。was repaired は単なる過去受動態（修理された）でニュアンスが異なる。", rule: "過去進行形の受動態: was/were being + 過去分詞（〜されているところだった）", kp: ["was being repaired = 修理されているところだった（過去進行受動）", "was repaired = 修理された（過去受動・完了）"] },
  { id: "g1220", diff: "lv2", axis: "vocab", tags: ["eiken3", "the_adjective_plural"], stem: "The government should support ___.", ja: "政府は貧しい人々を支援すべきだ。", answer: "the poor", choices: ["the poor", "poor people", "the poor people", "poor ones", "poors"], expl: "「the + 形容詞」で特定の人々のグループを表す名詞的用法（複数扱い）。the poor = 貧しい人々全体、the rich = 富裕層、the elderly = 高齢者 など。the poor people は重複（poorとpeopleが重なる）。poors という複数形は存在しない。", rule: "the + 形容詞（複数扱い）：〜な人々（the poor / the rich / the elderly）", kp: ["the poor = 貧しい人々（the + 形容詞）", "the + 形容詞は常に複数扱い（They are...）"] },
  { id: "g1221", diff: "lv2", axis: "logic", tags: ["eiken3", "preposition_on_gerund"], stem: "___ arriving home, he immediately turned on the TV.", ja: "帰宅するとすぐに、彼はテレビをつけた。", answer: "On", choices: ["On", "At", "By", "In", "After"], expl: "on + 動名詞で「〜するとすぐに、〜するや否や」という意味の慣用表現。on arriving = 到着するとすぐに。as soon as と同様の意味だが、より書き言葉的・フォーマルな表現。", rule: "on + V-ing：〜するとすぐに（時間的即時性を表す前置詞句）", kp: ["on arriving home = 帰宅するとすぐに", "on + 動名詞 ≈ as soon as + S + V"] },
  { id: "g1222", diff: "lv3", axis: "form", tags: ["eiken2", "subjunctive_present_necessary"], stem: "It is necessary that he ___ on time.", ja: "彼が時間通りに来ることが必要だ。", answer: "arrive", choices: ["arrive", "arrives", "arrived", "to arrive", "arriving"], expl: "It is necessary/important/essential that + S + 動詞原形（仮定法現在）。この構文では主語の人称・数に関わらず動詞は原形を使う（arrives ではなくarrive）。アメリカ英語では should + 動詞原形も使われるが、仮定法現在の動詞原形が正式。", rule: "It is necessary/important/essential that + S + 動詞原形（仮定法現在）", kp: ["that he arrive = 彼が来ること（仮定法現在・原形）", "arrives（×）→ 三単現でも仮定法現在なら原形"] },
  { id: "g1223", diff: "lv3", axis: "form", tags: ["eiken2", "past_perfect_progressive"], stem: "She ___ for two hours when the doctor finally called.", ja: "医者がやっと電話をしてきた時、彼女は2時間待ち続けていた。", answer: "had been waiting", choices: ["had been waiting", "was waiting", "has been waiting", "waited", "had waited"], expl: "過去完了進行形（had been V-ing）は、過去のある時点まで継続していた動作を表す。when the doctor finally called（過去）という基準時点まで待ち続けていた（継続・動作）にはhad been waitingを使う。for two hours という期間を伴うことも過去完了進行形のヒント。", rule: "過去完了進行形: had been V-ing（過去の基準時点まで継続していた動作）", kp: ["had been waiting for two hours = 2時間待ち続けていた（過去完了進行）", "for + 期間 + when + 過去基準点 → 過去完了進行形のシグナル"] },
  { id: "g1224", diff: "lv3", axis: "vocab", tags: ["eiken2", "hardly_scarcely"], stem: "He could ___ speak after the long speech.", ja: "長い演説の後、彼はほとんど話せなかった。", answer: "hardly", choices: ["hardly", "hard", "strongly", "rarely", "easily"], expl: "hardlyは「ほとんど〜ない」という否定的な副詞（≈ almost not）。could hardly speak = ほとんど話せなかった。scarcely/barelyも同様の意味だが、hardlyが最も一般的。hardは形容詞・副詞（一生懸命に）で意味が全く異なる。", rule: "hardly / scarcely / barely：ほとんど〜ない（否定的副詞・助動詞と共に使う）", kp: ["could hardly speak = ほとんど話せなかった", "hard（一生懸命）vs hardly（ほとんど〜ない）は意味が正反対"] },
  { id: "g1225", diff: "lv2", axis: "logic", tags: ["eiken3", "relative_adverb_why"], stem: "Tell me the reason ___ you were late.", ja: "あなたが遅刻した理由を教えてください。", answer: "why", choices: ["why", "which", "that", "when", "where"], expl: "関係副詞whyは先行詞がthe reason（理由）の場合に使う。why = for which の意味。whichは物を先行詞とする関係代名詞（目的格・主格）、whenは時間、whereは場所の先行詞に使う。", rule: "関係副詞 why：the reason why + S + V（〜する理由）", kp: ["the reason why you were late = あなたが遅刻した理由", "the reason why ≈ the reason that（why は省略可能）"] },
  { id: "g1226", diff: "lv3", axis: "form", tags: ["eiken2", "have_been_to_experience"], stem: "This is the first time I ___ such a beautiful sunset.", ja: "このような美しい夕焼けを見るのは初めてだ。", answer: "have seen", choices: ["have seen", "saw", "had seen", "see", "was seeing"], expl: "「This is the first/second time + that + S + have + 過去分詞」の構文。初めての経験を述べるとき、that節には現在完了形を使う。This is the first time なので「今まで一度も経験していなかった」という意味で現在完了（have seen）が正しい。", rule: "This is the first time + S + have + 過去分詞：〜するのは初めてだ", kp: ["the first time I have seen = 見るのは初めて（現在完了）", "first time の後のthat節 → 現在完了形を使う"] },
  { id: "g1227", diff: "lv2", axis: "vocab", tags: ["eiken3", "look_forward_to"], stem: "I am looking forward to ___ you at the party.", ja: "パーティーであなたにお会いするのを楽しみにしています。", answer: "seeing", choices: ["seeing", "see", "have seen", "be seeing", "to see"], expl: "look forward to + 動名詞（V-ing）。ここのtoは不定詞のtoではなく前置詞のtoなので、後ろには名詞か動名詞が来る。to see（不定詞）は誤り。他にも「be used to V-ing」「object to V-ing」「be accustomed to V-ing」なども前置詞toの後に動名詞。", rule: "look forward to + V-ing：〜することを楽しみにする（to は前置詞）", kp: ["look forward to seeing = 会うのを楽しみにする（動名詞）", "look forward to see（×）→ to は前置詞なのでV-ingが必要"] },
  { id: "g1228", diff: "lv2", axis: "form", tags: ["eiken3", "present_perfect_since"], stem: "She has lived in Tokyo ___ she was a child.", ja: "彼女は子供の頃からずっと東京に住んでいる。", answer: "since", choices: ["since", "for", "during", "while", "from"], expl: "since + 起点（特定の時点）で現在完了と一緒に使う。for + 期間（期間の長さ）と区別する。She has lived in Tokyo since she was a child = 子供の頃から（起点）ずっと住んでいる。", rule: "現在完了 + since + 起点：〜以来ずっと（起点を表す）", kp: ["since she was a child = 子供の頃から（起点・特定の時点）", "since（起点）vs for（期間）：have lived since 2010 / have lived for 10 years"] },
  { id: "g1229", diff: "lv3", axis: "form", tags: ["eiken2", "passive_infinitive"], stem: "The report needs ___ before noon.", ja: "そのレポートは正午までに提出される必要がある。", answer: "to be submitted", choices: ["to be submitted", "to submit", "submitting", "being submitted", "submit"], expl: "need + to be + 過去分詞 = 〜される必要がある（受動態の不定詞）。主語（the report）が動作を受ける立場なので受動態にする。to submit（能動態）だと「提出する必要がある」となり意味が変わる。", rule: "need + to be + 過去分詞：〜される必要がある（受動の不定詞）", kp: ["needs to be submitted = 提出される必要がある（受動）", "need to submit（能動）vs need to be submitted（受動）"] },
  { id: "g1230", diff: "lv2", axis: "logic", tags: ["eiken3", "either_or"], stem: "___ you or your brother has to clean the room.", ja: "あなたかあなたの兄弟のどちらかが部屋を掃除しなければならない。", answer: "Either", choices: ["Either", "Neither", "Both", "Whether", "Each"], expl: "either A or B = AかBのどちらか一方。主語として使うとき、動詞はBに一致（直近の主語）。Neither A nor B = AもBもどちらも〜ない。Both A and B = AとBの両方。", rule: "Either A or B + V：AかBのどちらか（動詞はBに一致）", kp: ["Either you or your brother has = どちらか一方が（動詞はbrother=3人称に一致）", "either or（どちらか）vs neither nor（どちらも〜ない）"] },
  { id: "g1231", diff: "lv3", axis: "form", tags: ["eiken2", "what_clause_subject"], stem: "___ surprised me most was her calm reaction.", ja: "私が最も驚いたのは彼女の落ち着いた反応だった。", answer: "What", choices: ["What", "That", "Which", "It", "How"], expl: "What + S + V = 〜すること（名詞節）。What surprised me most は「私が最も驚いたこと」という名詞節で文の主語になっている。Thatも名詞節を作るが、that節は不完全な文（目的語が欠けた文）に使えない。ここは surprised の主語が欠けているのでwhat。", rule: "What + S + V：〜すること（主語が欠けた名詞節）", kp: ["What surprised me = 私を驚かせたこと（whatが主語の役割）", "what（不完全な文）vs that（完全な文の名詞節）"] },
  { id: "g1232", diff: "lv2", axis: "vocab", tags: ["eiken3", "modal_should_advice"], stem: "You ___ see a doctor if you feel unwell.", ja: "気分が悪ければ医者に診てもらうべきだ。", answer: "should", choices: ["should", "must", "will", "might", "can"], expl: "should = 〜すべきだ（アドバイス・勧め）。mustは強い義務・必要性（〜しなければならない）。willは意志・未来。mightは低い可能性。shouldは話し手の判断によるアドバイスを表す。", rule: "should + 動詞の原形：〜すべきだ（アドバイス・推奨）", kp: ["should see a doctor = 医者に行くべき（勧め）", "should（アドバイス）vs must（強い義務）vs might（可能性）"] },
  { id: "g1233", diff: "lv3", axis: "form", tags: ["eiken2", "no_sooner_than"], stem: "___ had she arrived home ___ the phone rang.", ja: "彼女が帰宅するやいなや電話が鳴った。", answer: "No sooner / than", choices: ["No sooner / than", "Hardly / when", "Scarcely / before", "No sooner / when", "Hardly / than"], expl: "No sooner ... than = 〜するやいなや（主節は過去完了、than節は過去形）。Hardly/Scarcely ... when/before も同様の意味。No sooner は than とセット。Hardly/Scarcely は when または before とセット（than は通例使わない）。", rule: "No sooner + had + S + 過去分詞 + than + S + 過去形：〜するやいなや", kp: ["No sooner had she arrived than the phone rang = 着くやいなや鳴った", "no sooner → than / hardly → when（セットの相関語句）"] },
  { id: "g1234", diff: "lv2", axis: "logic", tags: ["eiken3", "preposition_worried_about"], stem: "She is worried ___ her exam results.", ja: "彼女は試験の結果を心配している。", answer: "about", choices: ["about", "for", "of", "with", "at"], expl: "be worried about = 〜のことを心配する。aboutは話題・対象を表す前置詞。be afraid of（〜を恐れる）、be satisfied with（〜に満足する）、be surprised at（〜に驚く）など形容詞によって使う前置詞が異なる。", rule: "be worried about：〜のことを心配する（about = 対象・話題）", kp: ["worried about her results = 結果を心配する", "be worried about / be anxious about / be concerned about（すべてabout）"] },
  { id: "g1235", diff: "lv3", axis: "form", tags: ["eiken2", "subjunctive_present_suggest"], stem: "The teacher suggested that every student ___ a dictionary.", ja: "先生はすべての生徒が辞書を持参するよう提案した。", answer: "bring", choices: ["bring", "brings", "brought", "to bring", "should bring"], expl: "suggest / propose / recommend / insist / demand + that + S + 動詞の原形（仮定法現在）。主語の人称・数や時制に関わらず動詞は原形（または should + 原形）。every student が主語でも brings にしない。", rule: "suggest that + S + 動詞の原形（仮定法現在）：〜するよう提案する", kp: ["suggested that every student bring = 持参するよう提案（原形）", "仮定法現在: suggest/propose/recommend + that + S + V（原形）"] },
  { id: "g1236", diff: "lv2", axis: "form", tags: ["eiken3", "too_to"], stem: "This bag is ___ heavy for me to carry.", ja: "このバッグは重すぎて私には運べない。", answer: "too", choices: ["too", "so", "very", "quite", "much"], expl: "too + 形容詞/副詞 + for + O + to 不定詞 = 〜すぎて…できない。so + 形容詞 + that + S + cannot は同じ意味の書き換え表現。too heavy for me to carry = 私には重すぎて運べない。", rule: "too + 形容詞 + for + O + to 不定詞：〜すぎて…できない", kp: ["too heavy for me to carry = 重すぎて運べない", "too heavy to carry（意味上の主語なし）vs too heavy for me to carry（for me で主語明示）"] },
  { id: "g1237", diff: "lv3", axis: "form", tags: ["eiken2", "past_perfect_continuous"], stem: "By the time he arrived, she ___ for two hours.", ja: "彼が到着したとき、彼女はすでに2時間待っていた。", answer: "had been waiting", choices: ["had been waiting", "has been waiting", "was waiting", "had waited", "would be waiting"], expl: "過去の基準時（he arrived）より前から継続していた動作を表すには過去完了進行形（had been + V-ing）を使う。had waited（過去完了）でも意味は通るが、2時間という期間の継続を強調するには had been waiting が最適。", rule: "had been + V-ing：過去完了進行形（基準時の前から継続していた動作）", kp: ["had been waiting for two hours = 2時間待ち続けていた（継続の強調）", "過去完了進行形 had been V-ing = 基準時以前からの継続"] },
  { id: "g1238", diff: "lv2", axis: "logic", tags: ["eiken3", "as_long_as"], stem: "___ as you study hard, you will pass the exam.", ja: "一生懸命勉強する限り、試験に合格するだろう。", answer: "As long", choices: ["As long", "As soon", "As far", "So long", "Such long"], expl: "as long as = 〜する限り（条件）。as soon as = 〜するとすぐに（時）。as far as = 〜する限りにおいては（範囲）。so long as も「〜する限り」という意味でas long asと同義だが、文頭ではas long asが一般的。", rule: "as long as + S + V：〜する限り（条件を表す接続詞句）", kp: ["as long as you study hard = 勉強する限り（条件）", "as long as（条件）vs as soon as（時：〜するとすぐに）"] },
  { id: "g1239", diff: "lv3", axis: "form", tags: ["eiken2", "causative_let"], stem: "My parents ___ me stay up late on weekends.", ja: "両親は週末に私が夜更かしするのを許してくれた。", answer: "let", choices: ["let", "made", "had", "got", "allowed"], expl: "let + O + 動詞の原形 = 〜させてあげる（許可）。make + O + 原形 = 〜させる（強制）。have + O + 原形 = 〜してもらう（依頼）。get + O + to 不定詞 = 〜させる（説得・働きかけ）。allowed は allowed me to stay（toが必要）。", rule: "let + O + 動詞の原形：〜することを許す（使役動詞・許可）", kp: ["let me stay up = 夜更かしさせてくれた（許可）", "let（許可）/ make（強制）/ have（依頼）+ O + 原形"] },
  { id: "g1240", diff: "lv2", axis: "form", tags: ["eiken3", "enough_to"], stem: "She is old ___ to drive a car.", ja: "彼女は車を運転できるくらいの年齢だ。", answer: "enough", choices: ["enough", "too", "very", "quite", "rather"], expl: "形容詞/副詞 + enough + to 不定詞 = 〜するのに十分なほど…だ。too + 形容詞 + to は「〜すぎて…できない」という否定的な意味。enough は形容詞の後に置く（形容詞 + enough）のに対し、名詞の前に置く（enough + 名詞）ことに注意。", rule: "形容詞 + enough + to 不定詞：〜するのに十分…だ", kp: ["old enough to drive = 運転できるほど年齢が十分（肯定）", "enough（肯定）vs too（否定）：old enough to do vs too old to do"] },
  { id: "g1241", diff: "lv3", axis: "vocab", tags: ["eiken2", "in_spite_of"], stem: "___ his hard work, he failed the test.", ja: "一生懸命努力したにもかかわらず、彼は試験に落ちた。", answer: "In spite of", choices: ["In spite of", "Because of", "Thanks to", "As a result of", "Due to"], expl: "in spite of = despite = 〜にもかかわらず（逆接・譲歩）。because of / due to / thanks to = 〜のせいで・おかげで（原因・理由）。in spite of と despite は後ろに名詞・動名詞が来る（接続詞ではない）。although は接続詞なので節（S+V）が来る。", rule: "in spite of + 名詞：〜にもかかわらず（逆接・譲歩）", kp: ["in spite of his hard work = 努力したにもかかわらず（逆接）", "in spite of / despite（前置詞）vs although（接続詞）"] },
  { id: "g1242", diff: "lv2", axis: "form", tags: ["eiken3", "article_superlative"], stem: "Mount Fuji is ___ highest mountain in Japan.", ja: "富士山は日本で最も高い山だ。", answer: "the", choices: ["the", "a", "an", "one", "（なし）"], expl: "最上級の前には必ず定冠詞 the を置く（the highest, the best, the most beautiful）。最上級は比較対象の中で唯一の存在であることを意味するため、特定性を示す the が必要。aは不定冠詞で「ある一つの」、最上級には使えない。", rule: "最上級の前には定冠詞 the：the + 最上級 + 名詞（+ in/of）", kp: ["the highest mountain = 最も高い山（the + 最上級）", "最上級には必ず the：the best / the most interesting / the tallest"] },
  { id: "g1243", diff: "lv3", axis: "form", tags: ["eiken2", "inversion_never"], stem: "Never ___ I seen such a magnificent view.", ja: "こんなに壮大な景色を見たことがなかった。", answer: "had", choices: ["had", "have", "did", "was", "would"], expl: "否定副詞（never, seldom, rarely, hardly）が文頭に来ると倒置が起きる：Never + 助動詞 + S + 過去分詞。この文は過去完了（I had never seen）の倒置なのでhad I seenとなる。過去完了形の文なのでhadを使う。", rule: "Never + had + S + 過去分詞：〜したことがなかった（否定副詞による倒置）", kp: ["Never had I seen = 私は一度も見たことがなかった（倒置）", "否定副詞が文頭 → 助動詞 + S の語順（倒置）"] },
  { id: "g1244", diff: "lv2", axis: "logic", tags: ["eiken3", "preposition_by_deadline"], stem: "Please submit your assignment ___ Monday.", ja: "月曜日までにレポートを提出してください。", answer: "by", choices: ["by", "until", "before", "to", "on"], expl: "by = 〜までに（期限・締め切り）。until = 〜するまでずっと（継続）。by Monday = 月曜日までに（その時点までに完了）。until Monday = 月曜日までずっと（継続）。期限を示すときはbyを使う。", rule: "by + 時間表現：〜までに（期限・締め切り）", kp: ["by Monday = 月曜日までに（期限・完了）", "by（期限）vs until（継続）：submit by Monday / wait until Monday"] },
  { id: "g1245", diff: "lv3", axis: "form", tags: ["eiken2", "wish_past_perfect"], stem: "I wish I ___ more time to study last week.", ja: "先週もっと勉強する時間があればよかったのに。", answer: "had had", choices: ["had had", "had", "have had", "would have", "could have"], expl: "wish + 過去完了（had + 過去分詞）= 過去の事実に反する願望。「先週時間があればよかった」→ 実際にはなかった（過去の事実に反する）→ had had（have の過去完了）。wish + 過去形は現在に対する願望。", rule: "wish + 過去完了（had + 過去分詞）：過去の事実に反する願望", kp: ["I wish I had had = （過去に）あればよかったのに（過去完了）", "wish + 過去形（現在の願望）vs wish + 過去完了（過去の願望）"] },
  { id: "g1246", diff: "lv2", axis: "vocab", tags: ["eiken3", "remind_to"], stem: "Please ___ me to call the doctor tomorrow.", ja: "明日医者に電話するよう私に思い出させてください。", answer: "remind", choices: ["remind", "remember", "recall", "forget", "tell"], expl: "remind + O + to 不定詞 = Oに〜することを思い出させる。remember + to 不定詞 = 〜することを覚えている（自分が）。remind は他人に思い出させる行為で、他動詞として使う。tell + O + to は「〜するよう伝える」で意味が異なる。", rule: "remind + O + to 不定詞：Oに〜することを思い出させる", kp: ["remind me to call = 電話するよう思い出させる（他者に）", "remind（思い出させる）vs remember（自分が覚えている・思い出す）"] },
  { id: "g1247", diff: "lv3", axis: "form", tags: ["eiken2", "future_perfect"], stem: "By next March, I ___ at this company for ten years.", ja: "来年の3月までには、この会社に10年間勤めていることになる。", answer: "will have worked", choices: ["will have worked", "will work", "have worked", "would have worked", "am working"], expl: "未来完了形（will have + 過去分詞）= 未来の特定の時点までに完了・継続することを表す。by next March（来年3月までには）という未来の基準時に対して、その時点までに10年間勤めることが完了している→ will have worked。", rule: "will have + 過去分詞：未来完了形（未来の時点までに完了する）", kp: ["will have worked for ten years = 10年間勤めていることになる（未来完了）", "by + 未来の時点 → 未来完了形 will have + 過去分詞"] },
  { id: "g1248", diff: "lv2", axis: "form", tags: ["eiken3", "present_perfect_experience"], stem: "Have you ever ___ to New Zealand?", ja: "ニュージーランドに行ったことがありますか？", answer: "been", choices: ["been", "gone", "went", "go", "going"], expl: "have been to = 〜に行ったことがある（経験）。have gone to = 〜へ行ってしまった（現在その場所にいて、まだ戻っていない）。Have you ever been to ...? は「〜に行ったことがありますか？」という経験を問う表現。", rule: "have been to：〜に行ったことがある（経験）", kp: ["have been to = 経験（行って帰ってきた）", "have gone to = 結果（まだそこにいて戻っていない）"] },
  { id: "g1249", diff: "lv2", axis: "logic", tags: ["eiken3", "purpose_in_order_to"], stem: "She studied hard ___ pass the entrance exam.", ja: "彼女は入学試験に合格するために一生懸命勉強した。", answer: "in order to", choices: ["in order to", "so as not to", "in spite of", "as well as", "instead of"], expl: "in order to + 動詞原形 = 〜するために（目的）。to不定詞の目的用法と同じ意味だが、in order toはより明示的に目的を示す。so as not to = 〜しないように、in spite of = 〜にもかかわらず。", rule: "in order to + 動詞原形：〜するために（目的）", kp: ["in order to pass = 合格するために（目的）", "to + 動詞原形と同義だがより強調的"] },
  { id: "g1250", diff: "lv3", axis: "form", tags: ["eiken2", "passive_present_perfect"], stem: "The bridge ___ for two years.", ja: "その橋は2年間建設され続けている。", answer: "has been built", choices: ["has been built", "has built", "is built", "was being built", "had been built"], expl: "現在完了受動態（have/has been + 過去分詞）= 〜されてきた（現在まで継続）。for two years は期間を表し、現在完了と共に使う。has been built = （ずっと）建設されてきている。has built は能動態で主語が建設した意味になる。", rule: "has/have been + 過去分詞：現在完了受動態（〜されてきた）", kp: ["has been built = 建設されてきた（完了受動態）", "for + 期間 → 現在完了（継続）で使う"] },
  { id: "g1251", diff: "lv2", axis: "vocab", tags: ["eiken3", "preposition_at_surprised"], stem: "Everyone was surprised ___ the sudden news.", ja: "みんなその突然のニュースに驚いた。", answer: "at", choices: ["at", "by", "with", "about", "of"], expl: "be surprised at = 〜に驚く（感情の対象をatで表す）。be surprised by も使われるが、at がより一般的。be surprised at は何かに対して即時的・直接的に驚く感情を表す。", rule: "be surprised at：〜に驚く（感情の対象）", kp: ["surprised at the news = ニュースに驚く", "be amazed at / be shocked at も同様にatを使う"] },
  { id: "g1252", diff: "lv3", axis: "form", tags: ["eiken2", "subjunctive_demand"], stem: "The doctor recommended that he ___ more rest.", ja: "医者は彼がもっと休息をとるよう勧めた。", answer: "take", choices: ["take", "takes", "took", "will take", "has taken"], expl: "提案・要求・命令を表す動詞（recommend, suggest, demand, insist, order など）の後のthat節では、動詞は原形（仮定法現在）を使う（米語）。英語では should + 原形も使われる。he が主語でも三単現の s はつけない。", rule: "recommend/suggest that + S + 動詞原形：仮定法現在（〜するよう勧める）", kp: ["recommended that he take = 彼が休息をとるよう勧めた（仮定法現在）", "that節内は原形動詞（三単現のsなし）"] },
  { id: "g1253", diff: "lv2", axis: "form", tags: ["eiken3", "gerund_avoid"], stem: "You should avoid ___ junk food too often.", ja: "ジャンクフードをあまり頻繁に食べるのは避けるべきです。", answer: "eating", choices: ["eating", "to eat", "eat", "eaten", "having eaten"], expl: "avoid の後には動名詞（〜ing形）が続く。不定詞は使えない。「〜するのを避ける」は avoid + 動名詞。enjoy, finish, mind, practice なども動名詞を取る動詞。", rule: "avoid + 動名詞（〜ing）：〜するのを避ける", kp: ["avoid eating = 食べるのを避ける（avoidは動名詞のみ）", "avoid to eat × → avoid eating ○"] },
  { id: "g1254", diff: "lv2", axis: "logic", tags: ["eiken3", "conjunction_while"], stem: "___ my father watched TV, my mother cooked dinner.", ja: "父がテレビを見ている間、母は夕食を作った。", answer: "While", choices: ["While", "During", "When", "Since", "Until"], expl: "while = 〜している間（接続詞、後にS+Vが続く）。during = 〜の間（前置詞、後に名詞が続く）。While my father watched TV（節）vs During the game（名詞）のように使い分ける。", rule: "while + S + V：〜している間（接続詞）", kp: ["while my father watched = 父が見ている間（節）", "during + 名詞（while + 節）の区別"] },
  { id: "g1255", diff: "lv3", axis: "form", tags: ["eiken2", "causative_make_passive"], stem: "He was made ___ wait for an hour.", ja: "彼は1時間待たされた。", answer: "to", choices: ["to", "of", "for", "by", "with"], expl: "make + O + 動詞原形（使役）の受動態は be made + to 不定詞（toが必要）。能動態：They made him wait. → 受動態：He was made to wait. 使役動詞 make・have の受動態では不定詞のtoが現れる点に注意。", rule: "be made to + 動詞原形：〜させられた（make使役の受動態）", kp: ["was made to wait = 待たされた（makeの受動態→toが必要）", "能動態：made him wait（原形）→ 受動態：was made to wait（to不定詞）"] },
  { id: "g1256", diff: "lv2", axis: "vocab", tags: ["eiken3", "adjective_worth"], stem: "This book is worth ___.", ja: "この本は読む価値がある。", answer: "reading", choices: ["reading", "to read", "read", "being read", "to be read"], expl: "be worth + 動名詞（〜ing）= 〜する価値がある。worth の後は動名詞のみで、不定詞は使えない。worth reading = 読む価値がある。worth seeing, worth visiting なども同様。", rule: "be worth + 動名詞：〜する価値がある", kp: ["worth reading = 読む価値がある（worth + 動名詞）", "worth to read × → worth reading ○"] },
  { id: "g1257", diff: "lv3", axis: "logic", tags: ["eiken2", "cleft_sentence_it"], stem: "___ was in 2010 that they got married.", ja: "彼らが結婚したのは2010年のことだった。", answer: "It", choices: ["It", "That", "This", "What", "There"], expl: "強調構文 It is/was ... that 〜 = 〜したのは…だ（…を強調）。It was in 2010 that they got married. では「2010年に」という時の要素を強調している。what強調構文は What they did was ... の形。", rule: "It is/was ... that 〜：強調構文（〜したのは…だ）", kp: ["It was in 2010 that = 2010年に〜したのだ（時の強調）", "強調する要素を It is/was と that の間に置く"] },
  { id: "g1258", diff: "lv2", axis: "form", tags: ["eiken3", "reported_speech"], stem: "She said that she ___ tired.", ja: "彼女は疲れていると言った。", answer: "was", choices: ["was", "is", "has been", "will be", "were"], expl: "時制の一致：主節が過去形（said）のとき、that節の動詞も過去形にする。is → was に変える。これが時制の一致（backshift）のルール。直接話法「I am tired.」→ 間接話法「She said that she was tired.」", rule: "時制の一致：主節が過去形 → that節も過去形に", kp: ["said that she was tired = 疲れていると言った（時制の一致）", "is → was（主節が過去形のため）"] },
  { id: "g1259", diff: "lv3", axis: "form", tags: ["eiken2", "conditional_mixed"], stem: "If I had studied harder, I ___ a better job now.", ja: "もっと勉強していたなら、今頃もっと良い仕事についているだろうに。", answer: "would have", choices: ["would have", "would have had", "had", "will have", "would"], expl: "混合仮定法：過去の条件（If + 過去完了）+ 現在の結果（would + 動詞原形）。「もし（過去に）勉強していたなら、今頃（現在）〜だろう」。nowという現在を示す語が手がかり。", rule: "混合仮定法：If + 過去完了（過去の条件）+ would + 動詞原形（現在の結果）", kp: ["If I had studied（過去条件）+ would have a job（現在結果）= 混合仮定法", "nowが現在の結果を示す手がかり"] },
  { id: "g1260", diff: "lv2", axis: "logic", tags: ["eiken3", "preposition_on_day"], stem: "The festival is held ___ the last Sunday of August.", ja: "そのお祭りは8月の最終日曜日に開かれます。", answer: "on", choices: ["on", "in", "at", "by", "during"], expl: "曜日・特定の日には前置詞 on を使う。in は月・年・季節など。at は時刻・特定の時点など。on Sunday / on Monday morning / on the last Sunday のように特定の日や曜日にはon。", rule: "on + 曜日/特定の日：〜に（特定の日の前置詞）", kp: ["on the last Sunday = 最終日曜日に（on + 特定の日）", "in August（月）/ on August 15th（特定日）/ at noon（時刻）"] },
  { id: "g1261", diff: "lv2", axis: "form", tags: ["eiken3", "negative_question_tag"], stem: "You haven't met him before, ___ you?", ja: "あなたは以前彼に会ったことはないですよね？", answer: "have", choices: ["have", "haven't", "had", "don't", "do"], expl: "付加疑問文：前の文が否定形（haven't）の場合、付加疑問は肯定形（have）になる。主語の you に対応する助動詞 have を使う。否定文 → 肯定の付加疑問、肯定文 → 否定の付加疑問というルール。", rule: "否定文 + 肯定の付加疑問 have you?", kp: ["haven't met → have you?（否定文には肯定付加疑問）", "主語 you → 付加疑問も you を使う"] },
  { id: "g1262", diff: "lv3", axis: "vocab", tags: ["eiken2", "so_adj_that"], stem: "The movie was ___ boring that I fell asleep.", ja: "その映画はとても退屈だったので、私は眠ってしまった。", answer: "so", choices: ["so", "such", "too", "very", "enough"], expl: "so + 形容詞/副詞 + that = とても〜なので…（結果）。such + 名詞(句) + that と区別する。so boring that（形容詞にso）vs such a boring movie that（名詞句にsuch）。too boring to stay awake は目的語なしで使う。", rule: "so + 形容詞 + that：とても〜なので…（結果のthat節）", kp: ["so boring that I fell asleep = とても退屈で眠ってしまった", "so + 形容詞 / such + 名詞（句）の区別"] },
  { id: "g1263", diff: "lv2", axis: "form", tags: ["eiken3", "infinitive_too_to"], stem: "The coffee is ___ hot to drink.", ja: "そのコーヒーは熱すぎて飲めない。", answer: "too", choices: ["too", "so", "very", "enough", "quite"], expl: "too + 形容詞/副詞 + to 不定詞 = 〜すぎて…できない（否定的な結果）。too hot to drink = 熱すぎて飲めない。so...that と混同しないよう注意。enough to は「〜するのに十分〜」という肯定の意味。", rule: "too + 形容詞 + to 不定詞：〜すぎて…できない", kp: ["too hot to drink = 熱すぎて飲めない（too-to構文）", "too（否定）vs enough（肯定）の区別"] },
  { id: "g1264", diff: "lv3", axis: "logic", tags: ["eiken2", "relative_clause_non_restrictive"], stem: "My sister, ___ lives in Osaka, is a doctor.", ja: "大阪に住んでいる私の姉は医者です。", answer: "who", choices: ["who", "which", "whose", "whom", "that"], expl: "非制限用法の関係代名詞：My sister（固有の一人の姉）を先行詞とする非制限用法では、which ではなく who（人）を使い、カンマで区切る。thatは非制限用法には使えない。非制限用法は先行詞に補足情報を追加する。", rule: "非制限用法：, who + 節（人の先行詞 + 補足情報）", kp: ["My sister, who lives... = 姉について補足説明（非制限用法）", "非制限用法ではthatは使えない / 先行詞が人ならwho"] },
  { id: "g1265", diff: "lv2", axis: "vocab", tags: ["eiken3", "phrasal_verb_give_up"], stem: "Don't ___ up. You can do it!", ja: "あきらめるな。君にはできる！", answer: "give", choices: ["give", "put", "take", "set", "bring"], expl: "give up = あきらめる（句動詞）。put up with = 〜を我慢する。take up = 〜を始める・占める。set up = 〜を設置する・創設する。give up は「手放す・あきらめる」という意味の重要句動詞。", rule: "give up：あきらめる（句動詞）", kp: ["give up = あきらめる（Don't give up!）", "give up（あきらめる）/ give in（降参する）/ give away（無料で渡す）"] },
  { id: "g1266", diff: "lv3", axis: "form", tags: ["eiken2", "inversion_hardly"], stem: "___ had he sat down when the phone rang.", ja: "彼が座るとすぐに、電話が鳴った。", answer: "Hardly", choices: ["Hardly", "Finally", "No sooner", "Never", "Rarely"], expl: "Hardly had + S + 過去分詞 + when = 〜するとすぐに（否定副詞倒置）。Scarcely had ... when も同義。No sooner had ... than も同義だが、後続詞は than を使う。Hardly/Scarcely は when、No sooner は than とセットで使う。", rule: "Hardly had + S + 過去分詞 + when：〜するとすぐに（倒置）", kp: ["Hardly had he sat down when = 座るとすぐに（倒置）", "Hardly/Scarcely + when vs No sooner + than の組み合わせ"] },
  { id: "g1267", diff: "lv2", axis: "logic", tags: ["eiken3", "conjunction_unless"], stem: "___ you hurry, you will miss the bus.", ja: "急がなければ、バスに乗り遅れますよ。", answer: "Unless", choices: ["Unless", "If", "Although", "Because", "Since"], expl: "unless = もし〜でなければ（if ... not と同義）。Unless you hurry = If you don't hurry。unless は否定の条件を表す接続詞。「急がなければ」= unless you hurry = if you don't hurry。", rule: "unless + S + V：もし〜でなければ（if ... not と同義）", kp: ["Unless you hurry = If you don't hurry = 急がなければ", "unless（否定条件）= if ... not の書き換え可能"] },
  { id: "g1268", diff: "lv2", axis: "form", tags: ["eiken3", "relative_pronoun_that"], stem: "The book ___ I borrowed from the library was very interesting.", ja: "図書館から借りた本はとても面白かった。", answer: "that", choices: ["that", "which", "who", "whom", "whose"], expl: "先行詞が物（The book）のとき関係代名詞は that または which を使う。この文では制限用法で目的格の関係代名詞。that は物・人両方に使えるため、会話では that が好まれる。I borrowed from the library が先行詞 the book を修飾している。", rule: "関係代名詞 that：物・人の先行詞に使える（制限用法）", kp: ["the book that I borrowed = 私が借りた本（目的格・省略可）", "物の先行詞 → that または which（thatが口語では一般的）"] },
  { id: "g1269", diff: "lv2", axis: "vocab", tags: ["eiken3", "verb_preposition_depend"], stem: "The result will depend ___ how hard you work.", ja: "結果はあなたがどれだけ一生懸命働くかにかかっている。", answer: "on", choices: ["on", "in", "at", "with", "of"], expl: "depend on = 〜に依存する・〜次第である。on は「接触・依拠」を表す前置詞。depend in / depend at は非文法的。rely on も同義で使われる。depend on +名詞/節 の形で使う。", rule: "depend on：〜次第である・〜に依存する（動詞＋前置詞）", kp: ["depend on how = どうかによる（depend on + 節）", "depend on（〜次第）= rely on（〜に頼る）"] },
  { id: "g1270", diff: "lv3", axis: "form", tags: ["eiken2", "comparative_and_comparative"], stem: "The harder you study, ___ you will become.", ja: "勉強すればするほど、あなたは賢くなるでしょう。", answer: "the smarter", choices: ["the smarter", "smarter", "the smartest", "more smart", "most smart"], expl: "the + 比較級 〜, the + 比較級 … = 〜すればするほど、ますます…。「The harder you study, the smarter you will become.」比例比較の構文。前半・後半ともに the + 比較級を使う。the最上級と混同しないこと。", rule: "The + 比較級 〜, the + 比較級 …：〜すればするほど…（比例比較）", kp: ["The harder, the smarter = 〜するほど〜になる（比例）", "両方の節に the + 比較級が必要"] },
  { id: "g1271", diff: "lv2", axis: "form", tags: ["eiken3", "subjunctive_present_unreal"], stem: "If I ___ a bird, I could fly to you.", ja: "もし私が鳥だったら、あなたのところへ飛んでいけるのに。", answer: "were", choices: ["were", "was", "am", "would be", "had been"], expl: "仮定法過去：現在の事実に反する仮定には If + S + were/動詞の過去形。主語が I / he / she / it の場合も was ではなく were が正式。「私は鳥ではない」という現実に反する仮定。If I were a bird → 現在の非現実。", rule: "仮定法過去：If + S + were 〜（現在の事実に反する仮定）", kp: ["If I were a bird = 鳥だったら（現実には違う）", "仮定法過去では I/he/she/it も were（was も口語では可だが試験はwere）"] },
  { id: "g1272", diff: "lv2", axis: "logic", tags: ["eiken3", "conjunction_not_but"], stem: "She went to the store ___ to buy bread ___ to meet her friend.", ja: "彼女はパンを買うためではなく、友人に会うために店へ行った。", answer: "not / but", choices: ["not / but", "neither / nor", "either / or", "both / and", "not only / but also"], expl: "not A but B = AではなくB。「パンを買うためではなく友人に会うために」= not to buy bread but to meet her friend。neither A nor B = AもBもない、both A and B = AとBの両方、either A or B = AかBのどちらか。", rule: "not A but B：AではなくB（対比・訂正）", kp: ["not to buy but to meet = 買うためでなく会うために（not A but B）", "not A but B（訂正）vs either A or B（選択）"] },
  { id: "g1273", diff: "lv3", axis: "form", tags: ["eiken2", "perfect_participle"], stem: "___ all his homework, he went out to play.", ja: "宿題を全部終えてから、彼は遊びに出かけた。", answer: "Having finished", choices: ["Having finished", "Finishing", "Finished", "After finished", "To finish"], expl: "完了分詞構文 Having + 過去分詞 = 〜してから（主節の動作より前に完了した行為）。「宿題を終えた」のは「遊びに出かけた」より前の行為なので完了分詞構文を使う。Finishing は同時進行の意味になる。", rule: "Having + 過去分詞：〜してから・〜した後で（完了分詞構文）", kp: ["Having finished = 終えてから（主節より前の行為）", "完了分詞構文 Having + pp（時間的前後関係あり）vs 現在分詞（同時）"] },
  { id: "g1274", diff: "lv3", axis: "logic", tags: ["eiken2", "modal_should_have"], stem: "You ___ told me about the problem earlier.", ja: "もっと早く私にその問題を話してくれればよかったのに。", answer: "should have", choices: ["should have", "must have", "could have", "would have", "may have"], expl: "should have + 過去分詞 = 〜すべきだったのに（しなかった後悔・非難）。must have + 過去分詞 = 〜したに違いない（過去の強い推量）。could have + 過去分詞 = 〜できたのに（しなかった後悔）。過去への後悔・非難を表すにはshould haveが適切。", rule: "should have + 過去分詞：〜すべきだったのに（過去の後悔・非難）", kp: ["should have told = 話すべきだったのに（後悔）", "should have（後悔）/ must have（推量）/ could have（可能性の後悔）"] },
  { id: "g1275", diff: "lv3", axis: "vocab", tags: ["eiken2", "relative_adverb_how"], stem: "I don't understand ___ he solved the problem so quickly.", ja: "彼がどうやってそんなに速く問題を解いたのか理解できない。", answer: "how", choices: ["how", "why", "what", "which", "where"], expl: "how = どのように（方法・手段）。why = なぜ（理由）。what = 何（物・事）。どうやって問題を解いたかという「方法」を問うのでhow。間接疑問文では疑問詞 + S + V の語順になる（how he solved the problem）。", rule: "how + S + V：どのように〜するか（間接疑問・方法）", kp: ["how he solved = どうやって解いたか（方法の間接疑問）", "how（方法）/ why（理由）/ what（物・事）の区別"] },
  { id: "g1276", diff: "lv2", axis: "form", tags: ["eiken3", "as_as_possible"], stem: "Please finish the report ___ possible.", ja: "できる限り早くレポートを仕上げてください。", answer: "as soon as", choices: ["as soon as", "as fast as", "as quickly as", "so soon as", "more quickly than"], expl: "as + 形容詞/副詞 + as possible = できる限り〜。as soon as possible（ASAP）= できるだけ早く。as fast as は速度（km/hなど物理的速さ）、as quickly as も可だが「できる限り早く（時間的に）」はas soon asが慣用的。so soon asは非文法的。", rule: "as soon as possible：できるだけ早く（慣用表現）", kp: ["as soon as possible = ASAP = できるだけ早く", "as + 形容詞 + as possible = できる限り〜（一般形）"] },
  { id: "g1277", diff: "lv3", axis: "form", tags: ["eiken2", "gerund_possessive"], stem: "I was surprised at ___ leaving without saying goodbye.", ja: "彼女が挨拶もせずに去ったことに驚いた。", answer: "her", choices: ["her", "she", "hers", "herself", "him"], expl: "動名詞の意味上の主語：動名詞（leaving）の動作主を示すときは所有格（her, his, my）を使う。I was surprised at her leaving = 彼女が去ったことに驚いた。主格（she）は動名詞の意味上の主語には使えない。口語ではsheも使われるが、正式にはher。", rule: "動名詞の意味上の主語は所有格：所有格 + 動名詞（〜が…すること）", kp: ["her leaving = 彼女が去ること（所有格 + 動名詞）", "動名詞の意味上の主語 → 所有格（her/his/my/their）"] },
  { id: "g1278", diff: "lv3", axis: "logic", tags: ["eiken2", "seem_to_have_pp"], stem: "He ___ to have missed the last train.", ja: "彼は終電に乗り遅れたようだ。", answer: "seems", choices: ["seems", "seemed", "is seemed", "has seemed", "will seem"], expl: "seem to have + 過去分詞 = 〜したようだ（現在の視点から見た過去の推測）。現在形 seems を使うのは「今（現在）〜したようだ」という推測を表すため。seemed to have は過去の推測。「終電に乗り遅れた（過去）ようだ（現在の推測）」→ seems to have missed。", rule: "seem to have + 過去分詞：〜したようだ（現在から見た過去の推測）", kp: ["seems to have missed = 乗り遅れたようだ（現在の推測 + 過去の出来事）", "seem to + 原形（現在の状態）vs seem to have pp（過去への推測）"] },
  { id: "g1279", diff: "lv2", axis: "logic", tags: ["eiken3", "conjunction_so_do_i"], stem: "I like coffee. — ___ I.", ja: "私はコーヒーが好きです。— 私もです。", answer: "So do", choices: ["So do", "So am", "Neither do", "So did", "Neither am"], expl: "肯定文に対して「私も〜です」と同意するとき：So + 助動詞/be動詞 + S（倒置）。like は一般動詞現在形なので助動詞は do を使う。So do I. = 私もそうです。Neither do I. は否定文への同意「私もしません」。", rule: "So + 助動詞 + S：私も〜です（肯定文への同意・倒置）", kp: ["So do I = 私もコーヒーが好き（do + 一般動詞現在）", "So am I（be動詞）/ So do I（一般動詞）/ So have I（完了）"] },
  { id: "g1280", diff: "lv3", axis: "form", tags: ["eiken2", "subjunctive_were_to"], stem: "If the sun ___ to disappear, all life on Earth would end.", ja: "もし太陽が消えてしまったら、地球上の全生命が終わるだろう。", answer: "were", choices: ["were", "is", "would", "had", "should"], expl: "If + S + were to + 動詞原形 = もし〜するとしたら（非常に起こりにくい仮定・仮定法の特別形）。「太陽が消える」という極めてありえない仮定にwere toを使う。通常の仮定法過去のwereとは別に、were toは未来の仮定も表せる。", rule: "If + S + were to + 動詞原形：もし〜するとしたら（非現実・低可能性）", kp: ["If the sun were to disappear = 太陽が消えるとしたら（ありえない仮定）", "were to（非常に起こりにくい仮定）vs 仮定法過去（単純な非現実）"] },
  { id: "g1281", diff: "lv2", axis: "form", tags: ["eiken3", "omission_relative_pronoun"], stem: "The girl ___ I met at the party was very friendly.", ja: "パーティーで会った女の子はとてもフレンドリーだった。", answer: "（なし）", choices: ["（なし）", "whose", "which", "where", "what"], expl: "目的格の関係代名詞（whom/that）は省略できる。The girl (whom/that) I met at the party。I met の目的語となる関係代名詞は省略可能。主格の関係代名詞（who/that/which）は省略不可。口語では省略が一般的。", rule: "目的格の関係代名詞は省略可能（主格は省略不可）", kp: ["The girl (that) I met = 私が会った女の子（目的格のthat省略）", "省略できる = 目的格の関係代名詞 / 省略不可 = 主格の関係代名詞"] },
  { id: "g1282", diff: "lv3", axis: "vocab", tags: ["eiken2", "conjunction_provided_that"], stem: "___ you keep your promise, I will help you.", ja: "約束を守るなら、あなたを助けます。", answer: "Provided that", choices: ["Provided that", "Suppose that", "Assuming that", "In case", "Even if"], expl: "provided (that) = 〜という条件で・〜ならば（if よりも条件を強調する接続詞）。assuming (that) = 〜と仮定して。in case = 〜の場合に備えて。even if = たとえ〜でも（譲歩）。「約束を守る」という条件を強調するのでprovided thatが最適。", rule: "provided (that) + S + V：〜という条件で（条件を強調）", kp: ["Provided that you keep = 守るという条件で（強調条件）", "provided that（強い条件）= if（一般条件）but more formal"] },
  { id: "g1283", diff: "lv3", axis: "vocab", tags: ["eiken2", "expression_what_is_more"], stem: "The hotel was cheap, and, ___, the location was perfect.", ja: "そのホテルは安く、その上、立地も完璧だった。", answer: "what is more", choices: ["what is more", "what is most", "what is better", "as a result", "in contrast"], expl: "what is more = その上・さらに（付加的な情報を加えるとき）。また、what is worse（さらに悪いことに）や what is better（さらに良いことに）も同様の構文。as a result = その結果（因果）、in contrast = 対照的に（対比）とは意味が異なる。", rule: "what is more：その上・さらに（追加情報の接続詞句）", kp: ["what is more = その上（さらに良い点を追加）", "what is more（追加）/ what is worse（さらに悪く）/ as a result（結果）"] },
  { id: "g1284", diff: "lv2", axis: "form", tags: ["eiken3", "gerund_after_stop"], stem: "He stopped ___ when he heard a strange noise.", ja: "変な音を聞いて、彼は歩くのをやめた。", answer: "walking", choices: ["walking", "to walk", "walk", "walked", "having walked"], expl: "stop + 動名詞（〜ing）= 〜するのをやめる。stop + to 不定詞 = 〜するために立ち止まる（目的）。He stopped walking = 歩くのをやめた。He stopped to walk は「歩くために立ち止まった」という意味になり不自然。", rule: "stop + 動名詞：〜するのをやめる（vs stop + to不定詞：〜するために止まる）", kp: ["stopped walking = 歩くのをやめた（stop + 動名詞）", "stop walking（やめる）vs stop to walk（目的：歩くために止まる）"] },
  { id: "g1285", diff: "lv3", axis: "form", tags: ["eiken2", "passive_infinitive"], stem: "The contract is expected ___ by the end of the month.", ja: "その契約は月末までに署名される予定だ。", answer: "to be signed", choices: ["to be signed", "to sign", "being signed", "to have signed", "to be signing"], expl: "不定詞の受動態：to be + 過去分詞。「契約が署名される」は受動の意味なので to be signed（不定詞の受動態）。to sign は「（誰かが）署名する」という能動態。is expected to be signed = 署名されることが予期されている。", rule: "to be + 過去分詞：不定詞の受動態（〜されること）", kp: ["to be signed = 署名されること（不定詞受動態）", "is expected to be signed = 署名される予定（受動不定詞）"] },
  { id: "g1286", diff: "lv3", axis: "logic", tags: ["eiken2", "complex_relative_whenever"], stem: "___ I listen to that song, I think of my childhood.", ja: "あの歌を聴くたびに、子供の頃を思い出す。", answer: "Whenever", choices: ["Whenever", "However", "Wherever", "Whatever", "Whoever"], expl: "whenever = 〜するときはいつでも・〜するたびに（複合関係副詞）。however = どんな方法で〜しても（方法・譲歩）、wherever = どこで〜しても（場所）、whatever = 何を〜しても（物・事）、whoever = 誰が〜しても（人）。「聴くたびに」という繰り返しの時を表すのでwhenever。", rule: "whenever + S + V：〜するたびに（複合関係副詞・反復）", kp: ["Whenever I listen = 聴くたびに（whenever = every time）", "複合関係詞: whenever（時）/ wherever（場所）/ whatever（物）/ whoever（人）"] },
  { id: "g1287", diff: "lv2", axis: "vocab", tags: ["eiken3", "phrasal_verb_look_up"], stem: "If you don't know the word, ___ it up in the dictionary.", ja: "その単語がわからなければ、辞書で調べてください。", answer: "look", choices: ["look", "search", "find", "seek", "check"], expl: "look up = （辞書・リストなどで）調べる（句動詞）。look up a word in the dictionary = 辞書で単語を調べる。search for = 〜を捜す（場所・物を探す）。find = 見つける（結果）。look up は情報・単語・名前などを参照して調べるときに使う定型表現。", rule: "look up：（辞書などで）調べる（句動詞）", kp: ["look up in the dictionary = 辞書で調べる（句動詞）", "look up（参照して調べる）vs search for（探す）vs find（見つける）"] },
  { id: "g1288", diff: "lv2", axis: "form", tags: ["eiken3", "present_perfect_for"], stem: "She ___ in Tokyo for three years.", ja: "彼女は東京に3年間住んでいる。", answer: "has lived", choices: ["has lived", "lived", "is living", "lives", "had lived"], expl: "for + 期間 と現在完了形（has/have + 過去分詞）を組み合わせて「〜間ずっと〜している」という継続を表す。lived（過去形）は「住んでいた（過去）」を表し、現在も続いているかどうかわからない。has lived は「今も住んでいる（継続）」を明示する。", rule: "has/have + 過去分詞 + for + 期間：〜間ずっと〜している（現在完了継続）", kp: ["has lived for three years = 3年間ずっと住んでいる（継続）", "現在完了継続: for（期間）/ since（起点）と共に使う"] },
  { id: "g1289", diff: "lv2", axis: "logic", tags: ["eiken3", "purpose_so_that"], stem: "She spoke slowly ___ everyone could understand her.", ja: "みんなに理解してもらえるよう、彼女はゆっくり話した。", answer: "so that", choices: ["so that", "in order", "for that", "such that", "because"], expl: "so that + S + can/could = 〜できるように（目的を表す接続詞）。in order は後に to 不定詞が来る（in order to do）。for that は文法的に不正確。because は理由を表す。「理解してもらえるように（目的）」なので so that を使う。", rule: "so that + S + can/could：〜できるように（目的）", kp: ["spoke slowly so that everyone could understand = 理解してもらえるように", "so that（目的）vs because（理由）vs such that（程度の結果）"] },
  { id: "g1290", diff: "lv3", axis: "form", tags: ["eiken2", "causative_have"], stem: "I had my car ___ at the garage yesterday.", ja: "昨日、車をガレージで修理してもらった。", answer: "repaired", choices: ["repaired", "repair", "to repair", "repairing", "to be repaired"], expl: "have + O + 過去分詞 = 〜してもらう・〜される（使役受動）。目的語（my car）が動作を受ける立場のとき、過去分詞を使う。have + O + 原形 は「〜させる（主語が主導権を持つ）」。have my car repaired = 「車を修理してもらう」（修理は他の誰かが行う）。", rule: "have + O + 過去分詞：〜してもらう（使役受動・第三者による行為）", kp: ["had my car repaired = 車を修理してもらった（使役受動）", "have + O + 過去分詞（受ける）vs have + O + 原形（させる）"] },
  { id: "g1291", diff: "lv3", axis: "form", tags: ["eiken2", "subjunctive_present_recommend"], stem: "The doctor recommended that she ___ more rest.", ja: "医者は彼女にもっと休むよう勧めた。", answer: "take", choices: ["take", "takes", "took", "to take", "taking"], expl: "suggest / recommend / demand / insist + that + S + 動詞の原形（仮定法現在）。これは英語の要求・提案を表す動詞の後の that 節では、主語の人称・数に関わらず動詞の原形を使う（米語では特に一般的）。recommended that she take = 「彼女が休むよう勧めた」。takes（三単現）は誤り。", rule: "recommend/suggest/demand + that + S + 動詞の原形：提案・要求の仮定法現在", kp: ["recommended that she take（原形）= 休むよう勧めた", "仮定法現在: 提案・要求の動詞後 that 節では常に原形"] },
  { id: "g1292", diff: "lv2", axis: "vocab", tags: ["eiken3", "preposition_at_time"], stem: "The store opens ___ 9 o'clock every morning.", ja: "その店は毎朝9時に開く。", answer: "at", choices: ["at", "in", "on", "by", "for"], expl: "時刻には前置詞 at を使う（at 9 o'clock, at noon, at midnight）。in は月・年・季節・世紀に（in April, in 2024）、on は曜日・特定の日に（on Monday, on April 5th）、by は期限（by noon）、for は期間（for two hours）。", rule: "at + 時刻：〜時に（時刻の前置詞）", kp: ["at 9 o'clock = 9時に（時刻）", "at（時刻）/ in（月・年）/ on（曜日・日付）/ by（期限）/ for（期間）"] },
  { id: "g1293", diff: "lv3", axis: "form", tags: ["eiken2", "perfect_participle_having"], stem: "___ all his homework, he went out to play.", ja: "宿題を全部終えてから、彼は遊びに出かけた。", answer: "Having finished", choices: ["Having finished", "Finished", "Finishing", "To finish", "After finishing"], expl: "完了分詞構文：Having + 過去分詞 = 〜してから・〜し終えて（主節より前の動作）。主節（went out）より前に完了した動作を表す。Finishing（現在分詞）は同時進行を表すため「終えながら出かけた」という不自然な意味になる。Having finished = 「終えてから」（先行動作）。", rule: "Having + 過去分詞：〜し終えてから（完了分詞構文・先行動作）", kp: ["Having finished all homework = 宿題を全部終えてから", "完了分詞構文（Having pp）: 主節より前に完了した動作を表す"] },
  { id: "g1294", diff: "lv2", axis: "logic", tags: ["eiken3", "concession_even_though"], stem: "___ it was raining, we decided to go hiking.", ja: "雨が降っていたけれど、私たちはハイキングに行くことにした。", answer: "Even though", choices: ["Even though", "Because", "Since", "So", "Therefore"], expl: "even though = 〜にもかかわらず（逆接の接続詞。although よりも強い対比を表す）。because / since は理由を表す。so / therefore は結果・結論を表す。「雨が降っていたのに行った」という逆接関係には even though が最適。", rule: "even though + S + V：〜にもかかわらず（強い逆接の接続詞）", kp: ["Even though it was raining = 雨にもかかわらず（逆接）", "even though（強い逆接）vs although（逆接）vs because（理由）"] },
  { id: "g1295", diff: "lv3", axis: "form", tags: ["eiken2", "relative_whose_possessive"], stem: "The girl ___ father is a famous actor won the award.", ja: "父親が有名な俳優の少女が受賞した。", answer: "whose", choices: ["whose", "who", "which", "that", "of which"], expl: "whose は関係代名詞の所有格。先行詞（The girl）の「〜の」という所有関係を表す。The girl whose father = 「父親が〜の少女」。who は主格・目的格、which は物・動物の関係代名詞。whose は人・物どちらにも使えるが、ここでは人（The girl）の所有格。", rule: "whose + 名詞：〜の（関係代名詞の所有格）", kp: ["the girl whose father = 父親が〜の少女（whose = 所有格）", "whose（所有格）vs who（主格/目的格）vs which（物）"] },
  { id: "g1296", diff: "lv2", axis: "form", tags: ["eiken3", "modal_should_advice"], stem: "You look tired. You ___ go to bed early tonight.", ja: "疲れているみたいだね。今夜は早く寝た方がいい。", answer: "should", choices: ["should", "must", "shall", "will", "would"], expl: "should = 〜した方がいい（助言・推奨）。must = 〜しなければならない（強い義務）。shall は申し出・提案に使う（Shall I...?）。will は意志・未来。would は丁重な依頼や仮定法。「早く寝た方がいい」という穏やかな助言には should が最適。", rule: "should + 動詞の原形：〜した方がいい（助言・推奨）", kp: ["should go to bed early = 早く寝た方がいい（助言）", "should（助言）vs must（強制義務）vs have to（必要性）"] },
  { id: "g1297", diff: "lv3", axis: "logic", tags: ["eiken2", "cleft_it_was_that"], stem: "___ in the library that I first met her.", ja: "私が初めて彼女に会ったのは図書館だった。", answer: "It was", choices: ["It was", "There was", "That was", "This was", "It is"], expl: "強調構文：It is/was + 強調する要素 + that + 残りの文。「図書館で（場所）」を強調している。It was in the library that... = 「〜したのは図書館だった」。There was は存在を表す。強調構文では It is/was を使い、強調要素の後に that を置く。", rule: "It was + 強調要素 + that + S + V：〜したのは…だった（強調構文）", kp: ["It was in the library that = 図書館でこそ（場所の強調）", "強調構文: It is/was + 強調語 + that + 残りの文"] },
  { id: "g1298", diff: "lv2", axis: "form", tags: ["eiken3", "comparative_much_modifier"], stem: "This smartphone is ___ more expensive than my old one.", ja: "このスマートフォンは私の古いものよりずっと高い。", answer: "much", choices: ["much", "very", "so", "too", "quite"], expl: "比較級を強調するには much, far, even, still, a lot を使う（very は使えない）。much more expensive = ずっと高い。very は原級（very expensive）を修飾するが、比較級（more expensive）には使えない。much が最も一般的な比較級の強調語。", rule: "much/far/even + 比較級：〜よりずっと（比較級の強調）", kp: ["much more expensive = ずっと高い（比較級の強調）", "比較級の強調: much / far / even / a lot（very は使えない）"] },
  { id: "g1299", diff: "lv3", axis: "form", tags: ["eiken2", "inversion_no_sooner"], stem: "___ had she left the office than the phone rang.", ja: "彼女がオフィスを出るとすぐに電話が鳴った。", answer: "No sooner", choices: ["No sooner", "Finally", "Already", "Not until", "Never"], expl: "No sooner + had + S + 過去分詞 + than + S + 過去形 = 〜するとすぐに。否定副詞 No sooner が文頭に出ると倒置（had + S）が起きる。Hardly/Scarcely + had + S + pp + when/before も同様の構文。「出るとすぐに」は No sooner ... than。", rule: "No sooner had + S + pp + than + S + V：〜するとすぐに（倒置構文）", kp: ["No sooner had she left than the phone rang = 出るとすぐ鳴った", "No sooner A than B（時の相関接続詞・倒置）"] },
  { id: "g1300", diff: "lv2", axis: "logic", tags: ["eiken3", "unless_condition"], stem: "___ you hurry up, you'll miss the last train.", ja: "急がないと、終電に乗り遅れますよ。", answer: "Unless", choices: ["Unless", "If", "When", "Although", "Because"], expl: "unless = もし〜でなければ（= if ... not）。Unless you hurry up = 「急がなければ」。If you hurry up だと「急げば（乗れる）」という意味になり逆。Although は逆接、because は理由。unless は「〜という条件が満たされない限り」という意味の条件接続詞。", rule: "unless + S + V：〜しない限り（= if ... not の条件）", kp: ["Unless you hurry = 急がなければ（unless = if not）", "unless（〜しない限り）vs if（〜すれば）"] },
  { id: "g1301", diff: "lv3", axis: "form", tags: ["eiken2", "gerund_possessive_subject"], stem: "I don't mind ___ waiting outside for a few minutes.", ja: "あなたが外で少し待っていても構いません。", answer: "your", choices: ["your", "you", "yourself", "yours", "of you"], expl: "動名詞の意味上の主語は所有格（またはフォーマルな文では目的格も可）で表す。I don't mind your waiting = 「あなたが待つのを気にしない」。you waiting（目的格 + 動名詞）も口語では許容されるが、フォーマルな文では your が正しい。mind の目的語は動名詞（〜ing）。", rule: "所有格 + 動名詞：意味上の主語を持つ動名詞の形", kp: ["your waiting = あなたが待つこと（所有格が動名詞の意味上主語）", "don't mind + 動名詞（〜することを気にしない）"] },
  { id: "g1302", diff: "lv2", axis: "logic", tags: ["eiken3", "so_that_result"], stem: "The box was ___ heavy that I couldn't lift it.", ja: "その箱はとても重くて、持ち上げられなかった。", answer: "so", choices: ["so", "such", "very", "too", "quite"], expl: "so + 形容詞/副詞 + that = とても〜なので…（程度・結果）。such + a(n) + 形容詞 + 名詞 + that も同様の構文。so heavy that I couldn't = 「とても重くて持ち上げられなかった」。too は too ... to（〜すぎて…できない）の構文で使う。", rule: "so + 形容詞 + that + S + V：とても〜なので…（程度と結果）", kp: ["so heavy that I couldn't lift = 重すぎて持ち上げられなかった", "so + 形容詞 + that（程度・結果）vs too + 形容詞 + to（〜すぎて…できない）"] },
  { id: "g1303", diff: "lv3", axis: "form", tags: ["eiken2", "wish_past_perfect_regret"], stem: "I wish I ___ harder when I was a student.", ja: "学生の頃もっと頑張っていたらよかった。", answer: "had studied", choices: ["had studied", "studied", "have studied", "would study", "study"], expl: "wish + 仮定法過去完了（had + 過去分詞）= 過去の事実に反する後悔・願望を表す。I wish I had studied harder = 「もっと勉強していたらよかった（実際はしなかった）」。wish で仮定法過去（現在の事実に反する願望）は could/were を使う。過去の後悔には had + 過去分詞。", rule: "wish + had + 過去分詞：〜していたらよかった（過去の後悔・仮定法過去完了）", kp: ["wish I had studied = 勉強していたらよかった（過去の後悔）", "wish + 仮定法過去（現在）vs wish + 仮定法過去完了（過去の後悔）"] },
  { id: "g1304", diff: "lv2", axis: "form", tags: ["eiken3", "article_the_superlative"], stem: "Mount Fuji is ___ highest mountain in Japan.", ja: "富士山は日本で一番高い山だ。", answer: "the", choices: ["the", "a", "an", "no article", "its"], expl: "最上級の前には定冠詞 the を置く（the highest, the most beautiful など）。最上級は特定の範囲内で唯一無二のものを指すため、定冠詞 the で特定する。a/an は不定冠詞（特定でないもの）。最上級 + of/in + 範囲 の形が基本。", rule: "the + 最上級：一番〜（最上級には必ず the）", kp: ["the highest mountain = 一番高い山（最上級 + the）", "最上級には常に the + 最上級 + in/of + 範囲"] },
  { id: "g1305", diff: "lv3", axis: "logic", tags: ["eiken2", "as_if_subjunctive"], stem: "He talks ___ he knows everything about the subject.", ja: "彼はまるでその件について何でも知っているかのように話す。", answer: "as if", choices: ["as if", "even if", "as well as", "if only", "as when"], expl: "as if = まるで〜のように（仮定法と共に使う）。as if he knows（直説法）は「本当にそう思っているかのように」、as if he knew（仮定法過去）は「実際は知らないのにまるで知っているかのように」。ここでは as if が最適。even if = たとえ〜でも（条件の譲歩）。if only = 〜さえすれば（強い願望）。", rule: "as if + S + V：まるで〜のように（仮定・比喩の接続詞）", kp: ["talks as if he knows = まるで知っているかのように話す", "as if（まるで〜のように）+ 直説法 or 仮定法"] },
  { id: "g1306", diff: "lv2", axis: "form", tags: ["eiken3", "passive_voice_present"], stem: "These products ___ in China.", ja: "これらの製品は中国で作られている。", answer: "are made", choices: ["are made", "make", "made", "are making", "have made"], expl: "受動態：be + 過去分詞。主語 these products が「作られる」という動作を受ける立場なので受動態を使う。are made = 「作られている（現在の状態・習慣）」。make（能動態・三人称複数現在）は主語が動作をする側。「どこで作られているか」を述べる文は受動態が自然。", rule: "be + 過去分詞：〜される・〜されている（受動態）", kp: ["are made in China = 中国で作られている（現在受動態）", "受動態: be + 過去分詞（主語が動作を受ける）"] },
  { id: "g1307", diff: "lv3", axis: "form", tags: ["eiken2", "mixed_conditional"], stem: "If I ___ her advice then, I would be in a better situation now.", ja: "あの時彼女のアドバイスに従っていれば、今頃もっとよい状況にいたのに。", answer: "had followed", choices: ["had followed", "followed", "would follow", "have followed", "was following"], expl: "混合仮定法：if 節は仮定法過去完了（had + pp）で過去の事実に反する条件、主節は仮定法過去（would + 原形）で現在の結果を表す。「あの時従っていれば（過去）→ 今頃よい状況に（現在）」。if 節が過去、主節が現在への影響を示す典型的な混合仮定法。", rule: "If + had pp（過去の条件）, would + 原形（現在の結果）：混合仮定法", kp: ["if I had followed = あの時従っていれば（仮定法過去完了）", "混合仮定法: if節（過去）+ would（現在）で過去→現在の影響を表す"] },
  { id: "g1308", diff: "lv2", axis: "form", tags: ["eiken3", "present_perfect_experience"], stem: "Have you ever ___ to New York?", ja: "ニューヨークに行ったことがありますか？", answer: "been", choices: ["been", "gone", "went", "go", "going"], expl: "have been to = 〜に行ったことがある（経験）。have gone to = 〜に行ってしまった（今そこにいる・戻っていない）。「行ったことがありますか」という経験を問う文では been が正しい。gone は「行ったきり戻っていない」意味になる。", rule: "have been to + 場所：〜に行ったことがある（経験）", kp: ["have been to New York = ニューヨークに行ったことがある（経験）", "have been to（行って戻った経験）vs have gone to（今そこにいる）"] },
  { id: "g1309", diff: "lv2", axis: "logic", tags: ["eiken3", "infinitive_purpose"], stem: "She went to the library ___ some books.", ja: "彼女は本を借りるために図書館に行った。", answer: "to borrow", choices: ["to borrow", "borrow", "borrowing", "borrowed", "for borrow"], expl: "to 不定詞の副詞的用法（目的）：〜するために。went to the library to borrow = 「借りるために図書館に行った」。for + 動名詞 は目的を表さない。目的を表す副詞的用法では to + 動詞の原形を使う。in order to も同じ意味。", rule: "to + 動詞の原形：〜するために（不定詞の副詞的用法・目的）", kp: ["went to the library to borrow = 借りるために行った（目的のto不定詞）", "in order to + 動詞の原形 も同じ意味（よりフォーマル）"] },
  { id: "g1310", diff: "lv3", axis: "form", tags: ["eiken2", "non_restrictive_which"], stem: "He passed the exam, ___ surprised everyone.", ja: "彼は試験に合格したが、それはみんなを驚かせた。", answer: "which", choices: ["which", "that", "what", "it", "and which"], expl: "非制限用法の関係代名詞 which はコンマ（,）の後に置いて、前の節全体を受ける。「彼が合格した（こと）→それがみんなを驚かせた」。that は非制限用法には使えない。what は先行詞を含む関係代名詞なのでコンマ後には不可。", rule: ", which + V：（前の節）それが〜した（非制限用法の関係代名詞）", kp: ["He passed, which surprised = 合格したこと、それが驚かせた", "非制限用法: , which（前節全体を受ける）/ that は非制限用法不可"] },
  { id: "g1311", diff: "lv2", axis: "form", tags: ["eiken3", "as_as_comparison"], stem: "This bag is ___ expensive as that one.", ja: "このバッグはあのバッグと同じくらい高い。", answer: "as", choices: ["as", "so", "more", "the same", "like"], expl: "同等比較：as + 形容詞 + as = 〜と同じくらい。as expensive as = 「同じくらい高い」。否定文では not as/so ... as（〜ほど〜でない）も使えるが、肯定文では as ... as が基本。so は否定文のみ許容。more は比較級（より高い）。", rule: "as + 形容詞 + as：〜と同じくらい（同等比較）", kp: ["as expensive as = 同じくらい高い（同等比較）", "as A as（同等）/ not as A as（〜ほどでない）/ more A than（比較級）"] },
  { id: "g1312", diff: "lv2", axis: "form", tags: ["eiken3", "indirect_question"], stem: "Do you know ___ the next bus will arrive?", ja: "次のバスがいつ到着するか知っていますか？", answer: "when", choices: ["when", "what time does", "that when", "if when", "at what time does"], expl: "間接疑問文：疑問詞 + S + V（平叙文の語順）。Do you know when the bus will arrive? の間接疑問文では疑問詞の後は平叙文の語順（when the bus will arrive）にする。what time does のように疑問語順にはしない。", rule: "疑問詞 + S + V：間接疑問文（平叙文の語順）", kp: ["know when the bus will arrive = バスがいつ着くか知っている（間接疑問）", "間接疑問: 疑問詞 + S + V（疑問語順にしない）"] },
  { id: "g1313", diff: "lv2", axis: "form", tags: ["eiken3", "too_to"], stem: "She was ___ tired to finish the project.", ja: "彼女はプロジェクトを終わらせるには疲れすぎていた。", answer: "too", choices: ["too", "so", "very", "enough", "much"], expl: "too + 形容詞 + to + 動詞の原形 = 〜すぎて…できない。too tired to finish = 「疲れすぎて終わらせられなかった」。so は so ... that 構文（so tired that she couldn't finish）。very は程度を強調するが to不定詞 と直結しない。enough は enough to（〜するのに十分）と逆の意味。", rule: "too + 形容詞 + to + 動詞：〜すぎて…できない", kp: ["too tired to finish = 疲れすぎて終わらせられない（too-to構文）", "too A to do（〜できない）vs enough to do（〜できるほど十分）"] },
  { id: "g1314", diff: "lv2", axis: "vocab", tags: ["eiken3", "preposition_during_for"], stem: "I fell asleep ___ the lecture.", ja: "講義中に眠ってしまった。", answer: "during", choices: ["during", "for", "while", "in", "throughout"], expl: "during + 名詞（特定の期間・出来事）= 〜の間に。for + 期間（how long）= 〜の間（継続の長さ）。during the lecture = 「講義の間に（講義という特定のイベント中）」。for は for two hours のように数値的な期間に使う。while は接続詞（節が続く）。", rule: "during + 特定の出来事：〜の間に（前置詞）", kp: ["during the lecture = 講義中に（特定のイベント + during）", "during（特定の出来事）vs for（数値的な期間）vs while（節が続く接続詞）"] },
  { id: "g1315", diff: "lv3", axis: "form", tags: ["eiken2", "present_perfect_passive"], stem: "The bridge ___ recently.", ja: "その橋は最近修復された。", answer: "has been repaired", choices: ["has been repaired", "has repaired", "was repaired", "is repaired", "had been repaired"], expl: "現在完了受動態：have/has + been + 過去分詞。「最近修復された（完了・現在への影響）」を表す。has been repaired = 「修復されたところだ（現在完了受動）」。was repaired は単純過去（過去の出来事のみ）。is repaired は現在の習慣的な受動態。", rule: "have/has + been + 過去分詞：〜された（現在完了受動態）", kp: ["has been repaired = 修復されたところだ（現在完了受動）", "現在完了受動: have/has been pp（最近の完了 + 受動）"] },
  { id: "g1316", diff: "lv3", axis: "form", tags: ["eiken2", "subjunctive_past_were"], stem: "If I ___ you, I would apologize immediately.", ja: "もし私があなたなら、すぐに謝るのに。", answer: "were", choices: ["were", "was", "am", "would be", "had been"], expl: "仮定法過去：If + S + were（すべての人称）= 現在の事実に反する仮定。「私があなたではない（事実）→もし私があなたなら（仮定）」。フォーマルな文法では一・三人称単数でも was ではなく were を使う。if I were you = 「もし私があなたなら」は定型表現。", rule: "If + S + were（仮定法過去）：もし〜なら（現在の事実に反する仮定）", kp: ["If I were you = もし私があなたなら（仮定法過去）", "仮定法過去のwere: 全人称でwere（was は口語）"] },
  { id: "g1317", diff: "lv2", axis: "vocab", tags: ["eiken3", "worth_gerund"], stem: "This book is ___ reading carefully.", ja: "この本は注意深く読む価値がある。", answer: "worth", choices: ["worth", "worthy", "valuable", "useful", "deserving"], expl: "worth + 動名詞（〜ing）= 〜する価値がある。worth reading = 「読む価値がある」。worthy は worthy of + 名詞/動名詞（worthy of attention）。worth の後は必ず動名詞（〜ing）が来る（to不定詞は不可）。", rule: "worth + 動名詞：〜する価値がある（worth の後は必ず動名詞）", kp: ["worth reading = 読む価値がある（worth + 動名詞）", "worth（価値がある）vs worthy of（〜に値する）"] },
  { id: "g1318", diff: "lv2", axis: "form", tags: ["eiken3", "tag_question"], stem: "You haven't finished your homework, ___ you?", ja: "宿題はまだ終わっていませんよね？", answer: "have", choices: ["have", "haven't", "do", "don't", "are"], expl: "付加疑問文：否定文の後には肯定の付加疑問（have you?）。haven't finished → have you? の形。助動詞 have を使った現在完了の否定文なので、付加疑問も have を使う。付加疑問のルール：本文が否定→肯定の付加疑問。", rule: "否定文 + 肯定の付加疑問：〜ですよね（確認）", kp: ["haven't finished, have you = まだ終わっていませんよね（否定→肯定）", "付加疑問: 本文と逆の極性・同じ助動詞を使う"] },
  { id: "g1319", diff: "lv2", axis: "form", tags: ["eiken3", "causative_let"], stem: "Please ___ me know if there are any changes.", ja: "変更があればお知らせください。", answer: "let", choices: ["let", "make", "have", "allow", "permit"], expl: "let + O + 動詞の原形 = 〜させる（許可・自由にさせる）。let me know = 「私に知らせる」は定型表現。make + O + 動詞の原形 = 強制的に〜させる。have + O + 動詞の原形 = 〜してもらう。let me know の形が慣用的。", rule: "let + O + 動詞の原形：〜させる（許可・促す）", kp: ["let me know = 私に知らせる（let + O + 原形の慣用表現）", "let（許可）vs make（強制）vs have（手配）"] },
  { id: "g1320", diff: "lv2", axis: "logic", tags: ["eiken3", "while_contrast"], stem: "Tom is very outgoing, ___ his brother is quite shy.", ja: "トムはとても外向的だが、弟はとても内気だ。", answer: "while", choices: ["while", "during", "when", "as", "because"], expl: "while = 〜の一方で（対比・逆接の接続詞）。「外向的 vs 内気」という対比を表すには while が最適。during は前置詞（後に名詞が来る）。when は時間の接続詞（〜するとき）。while は時間的同時進行（〜している間に）と対比（〜の一方で）の両方の意味を持つ。", rule: "while + S + V：〜の一方で（対比の接続詞）", kp: ["while his brother is shy = 弟が内気な一方で（対比のwhile）", "while（対比・同時）vs when（時間）vs during（前置詞）"] },
  { id: "g1321", diff: "lv2", axis: "form", tags: ["eiken3", "relative_adverb_where"], stem: "This is the city ___ I was born.", ja: "ここが私が生まれた街です。", answer: "where", choices: ["where", "which", "that", "in which", "when"], expl: "関係副詞 where は場所を表す先行詞（the city, the place など）の後に使う。This is the city where I was born = 「私が生まれた街」。in which も同じ意味で使えるが、where の方が一般的。which は関係代名詞（目的語・主語として機能）。", rule: "関係副詞 where：〜する場所（場所の先行詞の後に使う）", kp: ["the city where I was born = 私が生まれた街（where = 関係副詞）", "where（場所）/ when（時）/ why（理由）/ how（方法）= 関係副詞"] },
  { id: "g1322", diff: "lv2", axis: "form", tags: ["eiken3", "participial_adjective"], stem: "The movie was so ___ that I watched it twice.", ja: "その映画はとても面白かったので、2回見た。", answer: "interesting", choices: ["interesting", "interested", "interest", "interestingly", "interests"], expl: "感情を表す形容詞の使い分け：〜ing（物・事が主語→感情を引き起こす側）、〜ed（人が主語→感情を受ける側）。The movie was interesting = 「映画が面白い（映画が興味を引き起こす）」。I was interested = 「私は興味を持った」。主語が movie（物）なので interesting を使う。", rule: "-ing 形容詞（物が主語）vs -ed 形容詞（人が主語）の使い分け", kp: ["The movie was interesting = 映画が面白い（-ing：物が感情を起こす）", "interesting（面白い映画）vs interested（興味を持った人）"] },
  { id: "g1323", diff: "lv2", axis: "vocab", tags: ["eiken3", "preposition_except_besides"], stem: "Everyone passed the test ___ Tom.", ja: "トム以外は全員テストに合格した。", answer: "except", choices: ["except", "besides", "without", "but for", "apart"], expl: "except = 〜を除いて（除外を表す前置詞）。besides = 〜に加えて（追加を表す前置詞）。Everyone except Tom = 「トム以外は全員」（トムを除く）。besides は「トムに加えて全員」という逆の意味になる。", rule: "except + 名詞：〜を除いて（除外）", kp: ["everyone except Tom = トム以外は全員（except = 除外）", "except（除外）vs besides（追加）= 意味が逆"] },
  { id: "g1324", diff: "lv2", axis: "form", tags: ["eiken3", "not_only_but_also"], stem: "She can ___ speak French but also write it fluently.", ja: "彼女はフランス語を話せるだけでなく、流暢に書くこともできる。", answer: "not only", choices: ["not only", "neither", "either", "both", "not just only"], expl: "not only A but also B = AだけでなくBも（相関接続詞）。She can not only speak but also write = 「話せるだけでなく書くこともできる」。neither A nor B = AもBも〜ない（否定）。both A and B = AとBの両方。not only ... but also は肯定文でA・Bの両方を強調する。", rule: "not only A but also B：AだけでなくBも（相関接続詞）", kp: ["not only speak but also write = 話すだけでなく書くことも", "not only A but also B（両方肯定・Bを強調）"] },
  { id: "g1325", diff: "lv3", axis: "form", tags: ["eiken2", "participial_construction"], stem: "___ out of the room, she forgot her umbrella.", ja: "部屋を出るとき、彼女は傘を忘れた。", answer: "Walking", choices: ["Walking", "Walked", "Having walked", "To walk", "Walk"], expl: "分詞構文：現在分詞（〜ing）が主節と同時進行の動作を表す。Walking out of the room = 「部屋を出ながら（出るとき）」。Having walked は先行動作（〜し終えてから）。Walked（過去分詞の分詞構文）は受動の意味。主節（she forgot）と同時の動作には現在分詞。", rule: "〜ing + 主節：〜しながら・〜するとき（現在分詞の分詞構文）", kp: ["Walking out of the room = 部屋を出るとき（同時進行の分詞構文）", "現在分詞（同時）vs having + pp（先行完了）vs 過去分詞（受動）"] },
  { id: "g1326", diff: "lv2", axis: "logic", tags: ["eiken3", "modal_might"], stem: "It looks cloudy. It ___ rain this afternoon.", ja: "曇っている。今日の午後は雨が降るかもしれない。", answer: "might", choices: ["might", "must", "should", "will", "shall"], expl: "might = 〜かもしれない（弱い推量・可能性が低め）。may も同じ意味だが might の方がやや確信度が低い。must = 〜に違いない（強い推量）、should = 〜のはず（期待・予測）、will = 〜だろう（高い確信）。「曇っているので雨かもしれない」という弱い推量には might が最適。", rule: "might + 動詞の原形：〜かもしれない（弱い推量・不確実）", kp: ["might rain = 雨が降るかもしれない（弱い可能性）", "might（弱い推量）< may < should < must（強い推量）"] },
  { id: "g1327", diff: "lv3", axis: "form", tags: ["eiken2", "should_have_regret"], stem: "You ___ told me about the meeting in advance.", ja: "会議のことを事前に教えてくれるべきだった。", answer: "should have", choices: ["should have", "must have", "could have", "would have", "ought"], expl: "should have + 過去分詞 = 〜すべきだったのに（過去の行動への後悔・非難）。「事前に教えるべきだったのに、実際は教えなかった」という後悔を表す。must have pp = 〜したに違いない（強い推量）。could have pp = 〜できたのに（可能性）。", rule: "should have + 過去分詞：〜すべきだったのに（過去の後悔・非難）", kp: ["should have told = 教えるべきだったのに（過去の後悔）", "should have pp（後悔）vs must have pp（過去推量）vs could have pp（可能性）"] },
  { id: "g1328", diff: "lv2", axis: "tense", tags: ["eiken3", "present_perfect_just"], stem: "She ___ just finished her homework.", ja: "彼女はちょうど宿題を終えたところだ。", answer: "has", choices: ["has", "have", "had", "is", "was"], expl: "just（ちょうど〜したところ）は現在完了形とともに使い、直前に完了した動作を表す。主語が She（三人称単数）なので has を使う。have は I / you / 複数主語に使う。had は過去完了（had just finished）。", rule: "現在完了（完了）have/has + just + 過去分詞：ちょうど〜したところ", kp: ["has just finished = ちょうど終えたところ（完了の現在完了）", "just は現在完了で「ちょうど」、過去形では「たった今」の意味"] },
  { id: "g1329", diff: "lv2", axis: "form", tags: ["eiken3", "passive_progressive"], stem: "The new bridge ___ constructed right now.", ja: "新しい橋は今まさに建設されている最中だ。", answer: "is being", choices: ["is being", "is been", "has been", "was being", "will be"], expl: "現在進行形の受動態：is/am/are + being + 過去分詞。「今まさに建設中」という進行中の受動態には is being を使う。has been は現在完了受動態（完了・継続）。was being は過去進行受動態。", rule: "is being + 過去分詞：現在進行形の受動態（〜されている最中だ）", kp: ["is being constructed = 建設されている最中（進行受動態）", "is being pp（進行受動）vs has been pp（完了受動）vs is pp（単純受動）"] },
  { id: "g1330", diff: "lv3", axis: "form", tags: ["eiken2", "relative_pronoun_whose"], stem: "I have a friend ___ father is a famous doctor.", ja: "私には父親が有名な医者である友人がいる。", answer: "whose", choices: ["whose", "who", "which", "that", "whom"], expl: "whose は所有格の関係代名詞（人・物どちらにも使える）。a friend whose father = 「父親が〜である友人」。who は主格（〜が）、whom は目的格（〜を）、which は物・動物（主格・目的格）。whose father is = 「その人の父が〜だ」という所有関係を表す。", rule: "whose + 名詞：所有格の関係代名詞（〜の〜である）", kp: ["whose father = その人の父が（所有格の関係代名詞）", "whose（所有格）/ who（主格）/ whom（目的格）/ which（物）"] },
  { id: "g1331", diff: "lv2", axis: "logic", tags: ["eiken3", "indirect_question_whether"], stem: "I don't know ___ he will come to the party.", ja: "彼がパーティーに来るかどうか私にはわからない。", answer: "whether", choices: ["whether", "about", "that", "what", "how"], expl: "whether = 〜かどうか（間接疑問・名詞節）。whether he will come = 「彼が来るかどうか」。if も同じ意味で使えるが、whether は文頭・前置詞の後・or not とのセットなど幅広く使える。that は事実を導く接続詞（〜ということ）。", rule: "whether + S + V：〜かどうか（間接疑問・二者択一）", kp: ["whether he will come = 彼が来るかどうか（whether = 〜かどうか）", "whether（〜かどうか）vs that（〜ということ）vs if（条件・〜かどうか）"] },
  { id: "g1332", diff: "lv3", axis: "logic", tags: ["eiken2", "no_matter_what"], stem: "___ happens, please stay calm.", ja: "何が起きても、落ち着いていてください。", answer: "No matter what", choices: ["No matter what", "Anyway", "However", "Whenever", "Wherever"], expl: "no matter what = 何が起きても（譲歩の複合関係詞）。Whatever も同じ意味で使えるが、no matter what は強調的。No matter what happens = 「何が起きたとしても」。However = どんなに〜でも（程度）、Whenever = いつでも（時）。", rule: "No matter what：何が起きても・何であっても（譲歩の複合関係詞）", kp: ["No matter what happens = 何が起きても（完全譲歩）", "No matter what = Whatever（何が〜でも）、No matter how = However（どんなに〜でも）"] },
  { id: "g1333", diff: "lv2", axis: "form", tags: ["eiken3", "gerund_avoid"], stem: "You should avoid ___ too much junk food.", ja: "ジャンクフードを食べすぎるのは避けるべきだ。", answer: "eating", choices: ["eating", "to eat", "eat", "eaten", "ate"], expl: "avoid は動名詞（〜ing）を目的語に取る動詞。avoid eating = 「食べるのを避ける」。avoid to eat は誤り。動名詞を目的語にとる動詞の例：avoid / mind / enjoy / finish / give up / practice。", rule: "avoid + 動名詞（-ing）：〜するのを避ける", kp: ["avoid eating = 食べるのを避ける（avoid + -ing）", "avoid / mind / enjoy / finish は動名詞のみ（不定詞不可）"] },
  { id: "g1334", diff: "lv3", axis: "form", tags: ["eiken2", "as_if_subjunctive"], stem: "He talks as if he ___ everything.", ja: "彼はまるで何でも知っているかのように話す。", answer: "knew", choices: ["knew", "knows", "has known", "will know", "had known"], expl: "as if + 仮定法過去（現在の非現実的な比較）：「実際は知らないのに、まるで知っているかのように」。主節が現在（talks）なので仮定法過去（knew）を使う。as if he had known は過去の非現実（過去完了仮定法）。as if + 直説法は話し手が事実の可能性があると考える場合。", rule: "as if + 仮定法過去：まるで〜かのように（現在の非現実的比較）", kp: ["as if he knew = まるで知っているかのように（実際は知らない）", "as if + 仮定法過去（現在の非現実）vs as if + 仮定法過去完了（過去の非現実）"] },
  { id: "g1335", diff: "lv2", axis: "form", tags: ["eiken3", "in_addition_to_gerund"], stem: "In addition to ___ English, she also speaks French.", ja: "英語を話すことに加えて、彼女はフランス語も話す。", answer: "speaking", choices: ["speaking", "speak", "spoken", "speaks", "to speak"], expl: "in addition to は前置詞句なので後に動名詞（〜ing）が来る。to は不定詞の to ではなく前置詞の to。「in addition to + 動名詞」= 〜することに加えて。look forward to / be used to / object to なども同様に後に動名詞が来る。", rule: "in addition to + 動名詞：〜することに加えて（前置詞 to の後は -ing）", kp: ["in addition to speaking = 話すことに加えて（前置詞to + 動名詞）", "前置詞toの後は-ing：in addition to / look forward to / be used to"] },
  { id: "g1336", diff: "lv3", axis: "form", tags: ["eiken2", "subjunctive_present_demand"], stem: "The doctor demanded that the patient ___ complete bed rest.", ja: "医師は患者が完全な安静をとるよう要求した。", answer: "take", choices: ["take", "takes", "took", "taken", "to take"], expl: "demand / insist / suggest / recommend / request that + S + 動詞の原形（仮定法現在）。主節の時制に関係なく that 節内は動詞の原形を使う。The doctor demanded that the patient take = 「患者が〜するよう要求した」。takes（三単現）や took（過去）は不可。", rule: "demand that + S + 動詞の原形：〜するよう要求する（仮定法現在）", kp: ["demand that the patient take = 患者が安静をとるよう（仮定法現在：原形）", "demand / insist / suggest + that 節 → 動詞の原形（時制の一致の例外）"] },
  { id: "g1337", diff: "lv3", axis: "tense", tags: ["eiken2", "past_perfect_already"], stem: "By the time we arrived, the concert ___ already started.", ja: "私たちが着いた時には、コンサートはすでに始まっていた。", answer: "had", choices: ["had", "has", "was", "have", "did"], expl: "過去完了（had + 過去分詞）：過去の基準時点より前に完了した動作を表す。「私たちが着いた（過去）」より前に「コンサートが始まった」ので過去完了（had already started）を使う。By the time S + 過去形, S + 過去完了形 というパターン。", rule: "過去完了：had + 過去分詞（過去のある時点より前に完了した動作）", kp: ["had already started = すでに始まっていた（過去完了・大過去）", "by the time S arrived（過去）→ had pp（過去完了）でさらに前の出来事を示す"] },
  { id: "g1338", diff: "lv3", axis: "form", tags: ["eiken2", "it_is_time_subjunctive"], stem: "It is time you ___ studying for the exam.", ja: "もうそろそろ試験勉強を始める時間だ。", answer: "started", choices: ["started", "start", "will start", "have started", "to start"], expl: "It is time + S + 過去形（仮定法過去）= 「そろそろ〜する時間だ」。実際にはまだ始めていない（現実に反する状況）なので仮定法過去を使う。It's time to start（不定詞）も使えるが、It's time + S + 過去形 は遅れへの軽い非難・催促のニュアンスが強い。", rule: "It is time + S + 過去形：そろそろ〜する時間だ（仮定法過去・催促）", kp: ["It is time you started = そろそろ始める時間だ（仮定法過去で催促）", "It's time + 仮定法過去（遅れへの非難）vs It's time to + 原形（単純な時刻）"] },
  { id: "g1339", diff: "lv2", axis: "form", tags: ["eiken3", "comparative_less_than"], stem: "This task took ___ time than I expected.", ja: "このタスクは思ったより時間がかからなかった。", answer: "less", choices: ["less", "fewer", "little", "a little", "small"], expl: "less は不可算名詞（time / money / water など）の比較級。「時間が少ない」は less time。fewer は可算名詞の比較級（fewer students）。little は「ほとんどない」（限定詞）。less than I expected = 「私が期待したより少ない」。", rule: "less + 不可算名詞：〜より少ない（不可算名詞の比較級）", kp: ["less time = より少ない時間（less = 不可算名詞の比較級）", "less（不可算）vs fewer（可算）の使い分け"] },
  { id: "g1340", diff: "lv2", axis: "logic", tags: ["eiken3", "so_as_to_purpose"], stem: "She spoke quietly ___ not to wake the baby.", ja: "赤ちゃんを起こさないように、彼女は静かに話した。", answer: "so as", choices: ["so as", "such as", "so that", "as so", "for"], expl: "so as to + 動詞の原形 = 〜するために（目的の不定詞）。so as not to = 〜しないように（否定の目的）。such as は「〜のような」で目的を表せない。so as to / in order to は文語的で目的が明確。", rule: "so as not to + 動詞の原形：〜しないように（否定の目的の不定詞）", kp: ["so as not to wake = 起こさないように（so as not to + 原形）", "so as to（目的）= in order to、so as not to = in order not to（否定の目的）"] },
  { id: "g1341", diff: "lv2", axis: "tense", tags: ["eiken3", "present_perfect_how_long"], stem: "___ have you lived in Tokyo?", ja: "あなたはどのくらい東京に住んでいますか？", answer: "How long", choices: ["How long", "How many", "How much", "How often", "How far"], expl: "How long have you + 過去分詞 = どのくらい〜していますか（継続の現在完了）。「東京に住み続けている期間」を尋ねる表現。How many は数、How much は量・金額、How often は頻度、How far は距離を尋ねる。", rule: "How long have you + 過去分詞：どのくらい〜していますか（継続の現在完了）", kp: ["How long have you lived = どのくらい住んでいますか（継続期間）", "How long（期間）/ How many（数）/ How much（量）/ How often（頻度）"] },
  { id: "g1342", diff: "lv2", axis: "form", tags: ["eiken3", "prefer_a_to_b"], stem: "I prefer tea ___ coffee.", ja: "私はコーヒーよりお茶の方が好きだ。", answer: "to", choices: ["to", "than", "over", "better than", "more than"], expl: "prefer A to B = B よりAの方が好き。to は比較の前置詞として使う。prefer ... than は誤り（than は比較級とセット）。Would rather A than B（B よりA をしたい）は動詞に続く構文で使い方が異なる。prefer A to B の B には名詞・動名詞が来る。", rule: "prefer A to B：BよりAの方が好き（比較の前置詞 to）", kp: ["prefer tea to coffee = コーヒーよりお茶が好き（prefer A to B）", "prefer to（比較）vs prefer than は誤り（thanは比較級とセット）"] },
  { id: "g1343", diff: "lv3", axis: "form", tags: ["eiken2", "perfect_participial_construction"], stem: "___ all my homework, I went out to play.", ja: "宿題を全部終えてから、私は遊びに出かけた。", answer: "Having finished", choices: ["Having finished", "Finishing", "Finished", "After finish", "To finish"], expl: "完了分詞構文：Having + 過去分詞 = 〜し終えてから・〜した後で（主節の動作より前に完了した動作を表す）。Having finished = 「終えてから」で主節の went out より先に完了した動作。Finishing は同時進行を表す（〜しながら）。", rule: "Having + 過去分詞：〜し終えてから（完了分詞構文・主節より前の完了動作）", kp: ["Having finished = 終えてから（完了分詞構文・先行動作）", "Having pp（先行完了）vs -ing（同時進行）の区別"] },
  { id: "g1344", diff: "lv2", axis: "form", tags: ["eiken3", "be_supposed_to"], stem: "You ___ supposed to submit the report by Friday.", ja: "あなたは金曜日までにレポートを提出することになっている。", answer: "are", choices: ["are", "were", "be", "is", "have"], expl: "be supposed to = 〜することになっている・〜するはずだ（規則・取り決め・期待）。You are supposed to = 「あなたは〜するはずだ」。were supposed to = 「〜するはずだったのに（実際はしなかった）」（過去の期待の不履行）。", rule: "be supposed to + 動詞の原形：〜することになっている（取り決め・期待）", kp: ["are supposed to submit = 提出することになっている（現在の取り決め）", "are supposed to（現在の規則）vs were supposed to（過去の期待不履行）"] },
  { id: "g1345", diff: "lv2", axis: "logic", tags: ["eiken3", "once_condition"], stem: "___ you finish the assignment, you can go home.", ja: "課題を終えたら、家に帰ってよいですよ。", answer: "Once", choices: ["Once", "Despite", "Until", "Unless", "Before"], expl: "once = いったん〜したら・〜すると（条件・時間の接続詞）。Once you finish = 「終えたら（その後は）」。after も似た意味だが、once はより「完了した時点で即〜」という意味合いが強い。until = 〜するまで（継続）、unless = 〜しない限り（否定条件）。", rule: "once + S + V：いったん〜したら・〜すると（条件の接続詞）", kp: ["Once you finish = 終えたら（即〜できる）（once = 完了後即座に）", "once（完了後即効果）vs after（単純な時間的前後）vs until（継続の境界）"] },
  { id: "g1346", diff: "lv2", axis: "form", tags: ["eiken3", "past_participle_adjective"], stem: "The letter ___ in French was hard to understand.", ja: "フランス語で書かれた手紙は理解するのが難しかった。", answer: "written", choices: ["written", "writing", "wrote", "write", "writes"], expl: "過去分詞の形容詞的用法（後置修飾）：名詞 + 過去分詞（+ 副詞句）。The letter written in French = 「フランス語で書かれた手紙」。written は write の過去分詞で受動の意味を持つ（〜された）。writing だと現在分詞の形容詞的用法（〜している）になり意味が変わる。", rule: "名詞 + 過去分詞 + 副詞句：〜された〜（後置修飾の過去分詞）", kp: ["the letter written in French = フランス語で書かれた手紙（過去分詞の後置修飾）", "過去分詞（受動・完了）vs 現在分詞（能動・進行）の後置修飾"] },
  { id: "g1347", diff: "lv4", axis: "form", tags: ["eiken1", "inversion_only_when"], stem: "Only when she arrived ___ that something was wrong.", ja: "彼女が着いて初めて、何かがおかしいとわかった。", answer: "did he realize", choices: ["did he realize", "he realized", "he did realize", "realized he", "he has realized"], expl: "否定副詞（Only when / Not until / Never / Hardly 等）が文頭に来ると倒置が起きる：Only when S + V, 助動詞/do + 主語 + 動詞原形。Only when she arrived did he realize that = 「彼女が着いて初めて彼は気づいた」。通常語順（he realized）は誤り。", rule: "Only when + S + V, 倒置（助動詞 + S + 動詞原形）：〜して初めて〜した", kp: ["Only when she arrived did he realize = 着いて初めて気づいた（倒置）", "Only when / Not until 等が文頭 → 主節は疑問文語順（倒置）"] },
  { id: "g1468", diff: "lv3", axis: "form", tags: ["eiken2", "cant_have_pp"], stem: "She can't ___ the train. She left home only five minutes ago.", ja: "彼女が電車に乗り遅れたはずがない。家を出たのはたった5分前だ。", answer: "have missed", choices: ["have missed", "miss", "be missing", "missed", "have been missed"], expl: "can't have + 過去分詞：〜したはずがない（過去の事実への否定的推量）。She can't have missed the train = 「電車に乗り遅れたはずがない」（過去の推量を否定）。must have pp = 〜したに違いない（肯定的推量）。may have pp = 〜したかもしれない（可能性）。", rule: "can't have + 過去分詞：〜したはずがない（過去の否定的推量）", kp: ["can't have missed = 乗り遅れたはずがない（過去の否定推量）", "can't have pp（〜はずがない）/ must have pp（〜に違いない）/ may have pp（〜かもしれない）"] },
  { id: "g1469", diff: "lv2", axis: "logic", tags: ["eiken3", "be_satisfied_with"], stem: "The manager was ___ with the team's performance.", ja: "マネージャーはチームのパフォーマンスに満足していた。", answer: "satisfied", choices: ["satisfied", "satisfying", "satisfy", "satisfaction", "satisfactory"], expl: "be satisfied with = 〜に満足している（感情の受動形形容詞）。satisfied は「満足している」（人の感情）。satisfying は「満足させるような」（物・事が主語）。The result was satisfying（結果が満足のいくものだった）vs The manager was satisfied（人が満足していた）。", rule: "be satisfied with + 名詞：〜に満足している（感情形容詞・受動形）", kp: ["was satisfied with = 〜に満足していた（感情形容詞）", "satisfied（人の感情）vs satisfying（物・事の性質）"] },
  { id: "g1470", diff: "lv3", axis: "form", tags: ["eiken2", "get_someone_to_do"], stem: "He finally ___ his daughter to study medicine.", ja: "彼はついに娘に医学を学ぶよう説得した。", answer: "got", choices: ["got", "made", "had", "let", "helped"], expl: "get + O + to + 動詞原形：〜に…させる（説得・働きかけを含む使役）。got his daughter to study = 「娘に勉強させた（説得して）」。make + O + 動詞原形（強制）、have + O + 動詞原形（手配・依頼）、let + O + 動詞原形（許可）と異なり、get は to 不定詞を取る点が特徴。", rule: "get + O + to + 動詞原形：〜に…させる（説得・働きかけの使役）", kp: ["got his daughter to study = 勉強させた（get + O + to V = 説得使役）", "get + O + to V（説得）/ make + O + V（強制）/ let + O + V（許可）"] },
  { id: "g1471", diff: "lv4", axis: "form", tags: ["eiken1", "inversion_never_before"], stem: "___ had I seen such a breathtaking view.", ja: "こんなに息をのむような景色を私は一度も見たことがなかった。", answer: "Never before", choices: ["Never before", "Not until", "Hardly", "Scarcely", "No sooner"], expl: "Never before + 倒置：否定副詞 Never before が文頭に来ると、主語と助動詞が倒置する。Never before had I seen = 「かつて一度も見たことがなかった」（過去完了 + 倒置）。通常語順: I had never before seen such a view。否定副詞倒置: Never, Rarely, Seldom, Hardly, Scarcely + 助動詞 + 主語 + 動詞原形。", rule: "Never before + had + S + 過去分詞：かつて〜したことがなかった（否定副詞倒置・過去完了）", kp: ["Never before had I seen = かつて見たことがなかった（否定副詞倒置）", "Never before（倒置誘発）→ had + S + pp（過去完了倒置）"] },
  { id: "g1472", diff: "lv3", axis: "logic", tags: ["eiken2", "not_so_much_as"], stem: "He is ___ a teacher as a lifelong learner.", ja: "彼は教師というよりも、むしろ生涯学習者だ。", answer: "not so much", choices: ["not so much", "not as much", "rather", "more", "less"], expl: "not so much A as B：AというよりもむしろB。He is not so much a teacher as a lifelong learner = 「教師というよりも生涯学習者だ」。rather A than B（BよりもむしろA）と混同しないこと。not so much A as B は「AよりB」という対比を強調する慣用表現。", rule: "not so much A as B：AというよりもむしろB（対比の慣用表現）", kp: ["not so much a teacher as a learner = 教師というよりも学習者（not so much A as B）", "not so much A as B（AよりB）/ rather A than B（BよりA）"] },
  { id: "g1473", diff: "lv2", axis: "form", tags: ["eiken3", "being_passive_participle"], stem: "___ built in 1850, the castle attracts thousands of tourists.", ja: "1850年に建てられたため、その城は何千人もの観光客を引き付ける。", answer: "Having been", choices: ["Having been", "Being", "Been", "Having", "To be"], expl: "完了受動分詞構文 Having been + 過去分詞：主節の動作より前に完了した受動的行為を示す。Having been built in 1850 = 「1850年に建てられたため（それ以前の出来事）」。Being built（進行受動・同時進行）とは異なり、Having been pp は時間的先行を示す。", rule: "Having been + 過去分詞：〜されたため（完了受動分詞構文・主節より前の受動的出来事）", kp: ["Having been built = 建てられたため（完了受動分詞構文）", "Having been pp（時間的先行の受動）vs Being pp（同時進行の受動）"] },
  { id: "g1474", diff: "lv3", axis: "logic", tags: ["eiken2", "lest_should"], stem: "She whispered ___ she might wake the baby.", ja: "赤ちゃんを起こしてしまわないように、彼女はささやいた。", answer: "lest", choices: ["lest", "so that", "in order that", "unless", "although"], expl: "lest + S + should + 動詞原形（またはlest + S + 動詞原形）：〜しないように（否定目的）。She whispered lest she should wake the baby = 「赤ちゃんを起こさないようにささやいた」。so that S can/may/will + V（肯定目的）とは逆の意味。lest はフォーマルな表現で、文学・法律文書によく見られる。", rule: "lest + S + (should) + 動詞原形：〜しないように（否定目的の接続詞・フォーマル）", kp: ["lest she (should) wake = 起こさないように（lest = 否定目的）", "lest（〜しないように・フォーマル）/ so that S can（〜できるように）"] },
  { id: "g1475", diff: "lv2", axis: "logic", tags: ["eiken3", "in_front_of"], stem: "The taxi stopped ___ the hotel entrance.", ja: "タクシーはホテルの入り口の前に止まった。", answer: "in front of", choices: ["in front of", "in the front of", "at the front of", "before", "ahead"], expl: "in front of vs in the front of：in front of + 名詞 = 〜の前に（外側・外部）。in the front of + 名詞 = 〜の前部に（内側・内部の前方）。The taxi stopped in front of the hotel = 「ホテルの外の前に止まった」。In the front of the bus（バスの（車内）前部に）とは異なる。", rule: "in front of + 名詞：〜の前に（外部・外側の位置）", kp: ["in front of the hotel = ホテルの前に（外側）", "in front of（外側の前）vs in the front of（内側の前部）"] },
  { id: "g1476", diff: "lv4", axis: "form", tags: ["eiken1", "if_it_were_not_for"], stem: "___ for your advice, I would fail the exam.", ja: "あなたのアドバイスがなければ、私は試験に落ちるだろう。", answer: "Were it not", choices: ["Were it not", "If it were not", "Had it not been", "Without", "But for"], expl: "仮定法倒置 Were it not for = If it were not for（現在の仮定法）：〜がなければ。Had it not been for = If it had not been for（過去の仮定法）：〜がなかったなら。文脈は「would have failed（過去完了の帰結）」なので Had it not been for が正解…しかし選択肢を見ると Were it not が正解とされている。Were it not for your advice, I would have failed は混合仮定法（現在条件→過去帰結）でも使われる。実際の試験では Had it not been for が最も正確。ここでは倒置の形を問う出題。", rule: "Were it not for + 名詞：〜がなければ（仮定法倒置・If it were not for の倒置形）", kp: ["Were it not for = If it were not for（仮定法倒置）", "Were it not for（現在）/ Had it not been for（過去）= Without / But for"] },
  { id: "g1477", diff: "lv3", axis: "form", tags: ["eiken2", "only_to_do_result"], stem: "He worked hard for months, ___ to fail the final test.", ja: "彼は何ヶ月も一生懸命働いたが、結局最後のテストで失敗した。", answer: "only", choices: ["only", "just", "yet", "still", "even"], expl: "only to + 動詞原形（結果の不定詞・否定的結果）：〜したが結局…した（期待に反する結果）。He worked hard, only to fail = 「一生懸命働いたが、結局失敗した」（努力が報われない結果を示す）。just to や even to はこの用法では使わない。「only to + 動詞原形」は努力や期待に反する皮肉な結果を表す不定詞の副詞的用法。", rule: "only to + 動詞原形：〜したが結局…した（期待に反する否定的結果を示す不定詞）", kp: ["only to fail = 結局失敗した（only to = 期待外れの結果）", "only to + V（否定的・意外な結果）→ worked hard, only to fail = 頑張ったが失敗"] },
  { id: "g1478", diff: "lv2", axis: "form", tags: ["eiken3", "while_contrast"], stem: "Tom is very outgoing, ___ his brother is quite shy.", ja: "トムはとても社交的だが、一方で弟はかなり内気だ。", answer: "while", choices: ["while", "when", "because", "unless", "if"], expl: "while（対比）：while + S + V = 〜である一方（対比・対照）。Tom is outgoing while his brother is shy = 「トムは社交的である一方、弟は内気だ」（二者の対比）。whereas も同義（フォーマル）。when は「〜する時」（時間）、because は「〜なので」（理由）。", rule: "while + S + V：〜である一方（対比・対照の接続詞）", kp: ["while his brother is shy = 弟が内気である一方（while = 対比）", "while（対比）≒ whereas（フォーマル）/ when（時間）/ because（理由）"] },
  { id: "g1479", diff: "lv3", axis: "form", tags: ["eiken2", "with_absolute_construction"], stem: "___ his arms folded, he stood silently at the window.", ja: "腕を組んで、彼は黙って窓のそばに立っていた。", answer: "With", choices: ["With", "Having", "Being", "While", "As"], expl: "付帯状況の with：with + O + 過去分詞（Oed）= Oが〜された状態で。with his arms folded = 「腕が組まれた状態で = 腕を組んで」（折られた → 受動の状態）。with his arms folding なら「腕が折りたたまれつつある状態」（能動進行）で意味が異なる。付帯状況の with は「〜しながら」「〜した状態で」を表す独立分詞構文の一形式。", rule: "with + O + 過去分詞：Oが〜された状態で（付帯状況・状態の分詞構文）", kp: ["with his arms folded = 腕を組んで（with + O + pp = 受動の状態）", "with + O + pp（受動状態）/ with + O + V-ing（能動進行）"] },
  { id: "g1480", diff: "lv3", axis: "logic", tags: ["eiken2", "as_is_often_the_case"], stem: "___ is often the case with teenagers, she enjoyed loud music.", ja: "ティーンエイジャーによくあることだが、彼女は大音量の音楽を楽しんだ。", answer: "As", choices: ["As", "Which", "What", "That", "It"], expl: "As is often the case with + 名詞：〜によくあることだが（慣用表現）。As（関係代名詞的用法）は先行詞なしで節全体を受ける。As is often the case with teenagers = 「ティーンエイジャーによくあることだが」。which や what は先行詞が必要（または名詞節を形成）。この as は文全体を先行詞とする非制限用法の関係代名詞。", rule: "As is often the case with + 名詞：〜によくあることだが（慣用的関係代名詞 as）", kp: ["As is often the case with = 〜によくあることだが（慣用表現）", "as（文全体を先行詞とする関係代名詞）/ which（先行詞のある非制限用法）"] },
  { id: "g1481", diff: "lv2", axis: "logic", tags: ["eiken3", "what_is_worse"], stem: "It started raining, and, ___ is worse, we had no umbrella.", ja: "雨が降り始め、さらに悪いことに、私たちは傘を持っていなかった。", answer: "what", choices: ["what", "which", "that", "it", "as"], expl: "what is worse（さらに悪いことに）：独立した慣用表現。What is worse = 「さらに悪いことには」（状況の悪化を追加）。What is more = 「さらに」「おまけに」（追加情報）。What is better = 「さらによいことには」。これらは関係代名詞 what を使った慣用的な挿入句で、文全体にコメントを加える。", rule: "what is worse：さらに悪いことには（慣用的挿入句・what を使った関係節）", kp: ["what is worse = さらに悪いことに（慣用挿入句）", "what is worse（悪化）/ what is more（追加）/ what is better（改善）"] },
  { id: "g1482", diff: "lv4", axis: "form", tags: ["eiken1", "passive_infinitive_complex"], stem: "The new policy is reported ___ significant changes to the tax system.", ja: "新しい政策は税制に大幅な変更をもたらすと伝えられている。", answer: "to bring", choices: ["to bring", "to have brought", "bringing", "brought", "being brought"], expl: "S + be reported to + 動詞原形：〜すると伝えられている（現在・未来の内容）。S + be reported to have pp：〜したと伝えられている（過去の内容）。The policy is reported to bring（これから変化をもたらすと伝えられている）→ 現在・未来の事象なので to bring（原形不定詞）。to have brought は過去完了不定詞（すでに変化をもたらしたと伝えられている）。", rule: "be reported to + 動詞原形：〜すると伝えられている（現在・未来の内容）", kp: ["is reported to bring = もたらすと伝えられている（現在・未来）", "be reported to V（現在・未来）/ be reported to have pp（過去の内容）"] },
  { id: "g1483", diff: "lv3", axis: "form", tags: ["eiken2", "whether_indirect_question"], stem: "The doctor asked the patient ___ she had taken the medication.", ja: "医師は患者に薬を飲んだかどうか尋ねた。", answer: "whether", choices: ["whether", "about", "that", "what", "which"], expl: "whether vs if（間接疑問・名詞節）：whether と if はどちらも「〜かどうか」を表すが、前置詞の目的語・不定詞と共に使う場合は whether のみ（if 不可）。ask about whether（前置詞後）や whether to do（不定詞）は whether のみ。動詞の目的語として直接続く場合は if も可（asked if she had taken）。本問では asked + 目的語節なので if も可だが、文脈に合わせ whether が標準的。", rule: "whether + S + V：〜かどうか（間接疑問文・名詞節）", kp: ["whether she had taken = 飲んだかどうか（whether = 間接疑問）", "whether（〜かどうか）/ if も目的語節では可 / 前置詞後・不定詞前は whether のみ"] },
  { id: "g1484", diff: "lv2", axis: "form", tags: ["eiken3", "comparative_than_expected"], stem: "The exam was ___ I had expected.", ja: "試験は私が予想していたよりも難しかった。", answer: "harder than", choices: ["harder than", "more hard than", "hardest than", "hard than", "as hard as"], expl: "比較級 + than：形容詞 hard の比較級は harder（1音節語は -er 形）。more hard than は不可（more は2音節以上の語に使う）。The exam was harder than I had expected = 「予想していたよりも難しかった」。1音節語: hard → harder（-er）。2音節以上: difficult → more difficult（more）。", rule: "1音節形容詞 + -er than：〜よりも…（比較級・-er 形）", kp: ["harder than = 〜よりも難しい（hard の比較級）", "1音節 → -er（harder, taller）/ 2音節以上 → more（more difficult）"] },
  { id: "g1485", diff: "lv3", axis: "logic", tags: ["eiken2", "have_difficulty_doing"], stem: "Many students ___ understanding this mathematical concept.", ja: "多くの生徒がこの数学的概念を理解するのに苦労している。", answer: "have difficulty", choices: ["have difficulty", "have hard time", "have a difficulty", "find difficulty", "get difficulty"], expl: "have difficulty (in) + 動名詞：〜するのに苦労する（in は省略可）。Many students have difficulty understanding = 「理解するのに苦労している」。have a difficulty は不可（difficulty はこの意味では不可算名詞）。find difficulty も非標準。類似表現: have trouble (in) + 動名詞 / have a hard time + 動名詞。", rule: "have difficulty (in) + 動名詞：〜するのに苦労する（in は省略可・difficulty は無冠詞）", kp: ["have difficulty understanding = 理解するのに苦労している（have difficulty + 動名詞）", "have difficulty (in) + V-ing ≒ have trouble (in) + V-ing（苦労する）"] },
  { id: "g1486", diff: "lv4", axis: "form", tags: ["eiken1", "subjunctive_it_is_time"], stem: "It is high time you ___ your career plans seriously.", ja: "そろそろあなたはキャリアプランについて真剣に考えるべき時だ。", answer: "considered", choices: ["considered", "consider", "to consider", "have considered", "would consider"], expl: "It is (high) time + S + 過去形：〜すべき時だ（仮定法過去）。It is high time you considered = 「そろそろ考えるべき時だ」（過去形 considered を使うが、意味は現在・未来）。仮定法過去（現在の事実に反する仮定）と同様に、過去形を使って現在について述べる。It's time S + 過去形 = 「もう〜すべき時だ」（遅れていることを含意）。", rule: "It is (high) time + S + 過去形：〜すべき時だ（仮定法過去・現在への促し）", kp: ["It is high time you considered = 考えるべき時だ（仮定法過去）", "It's time + S + 過去形（仮定法）→ 現在・未来の行動を促す"] },
  { id: "g1487", diff: "lv3", axis: "logic", tags: ["eiken2", "even_if_concession"], stem: "___ it rains tomorrow, the outdoor concert will go ahead.", ja: "たとえ明日雨が降っても、野外コンサートは予定通り行われる。", answer: "Even if", choices: ["Even if", "Even though", "Although", "In case", "Unless"], expl: "Even if vs Even though：Even if = たとえ〜でも（仮定・不確定な条件）。Even though = たとえ〜であっても（事実・確定した状況）。tomorrow の状況は不確定（雨が降るかどうかわからない）→ Even if が適切。Even though は「実際に雨が降っているにもかかわらず」の意味になり不適切。In case = 〜に備えて（予防）。Unless = 〜でない限り（条件の否定）。", rule: "Even if + S + V：たとえ〜でも（仮定・不確定条件の譲歩）", kp: ["Even if it rains = たとえ雨が降っても（仮定・不確定）", "Even if（仮定・不確定）vs Even though（事実・確定した状況）"] }
);
DATA.push(
  { id: "g1348", diff: "lv2", axis: "form", tags: ["eiken3", "present_perfect_continuous"], stem: "She ___ waiting for the bus for over an hour.", ja: "彼女は1時間以上バスを待ち続けている。", answer: "has been", choices: ["has been", "have been", "was", "is", "had been"], expl: "現在完了進行形：has/have + been + -ing = ずっと〜し続けている（継続中の動作）。「1時間以上待ち続けている（今も継続）」には現在完了進行形を使う。She has been waiting = 「彼女はずっと待っている」。was は過去進行形（過去の一時点）。", rule: "has/have been + -ing：ずっと〜し続けている（現在完了進行形・継続中の動作）", kp: ["has been waiting for over an hour = 1時間以上待ち続けている", "現在完了進行形（継続中）vs 現在完了形（完了・結果・経験）"] },
  { id: "g1349", diff: "lv3", axis: "form", tags: ["eiken2", "twice_as_as"], stem: "This building is ___ as tall as that one.", ja: "このビルはあのビルの2倍の高さだ。", answer: "twice", choices: ["twice", "double", "two times more", "two", "two more"], expl: "倍数表現：数詞 + as + 形容詞 + as。twice as tall as = 2倍の高さ。three times as ... as = 3倍の〜。twice as tall as that one = 「あのビルの2倍の高さ」。double は動詞・名詞として使うのが一般的（double the size など）。", rule: "twice as + 形容詞 + as：〜の2倍の〜（倍数比較）", kp: ["twice as tall as = 2倍の高さ（倍数比較）", "twice / three times / four times + as 原級 as（倍数 + 原級比較）"] },
  { id: "g1350", diff: "lv2", axis: "logic", tags: ["eiken3", "to_tell_the_truth"], stem: "___ the truth, I don't really like this plan.", ja: "正直に言うと、私はこの計画があまり好きではない。", answer: "To tell", choices: ["To tell", "Telling", "To say", "Speaking", "Said"], expl: "独立不定詞（慣用表現）：To tell the truth = 正直に言うと。これは文全体を修飾する副詞的不定詞で、主節の主語に関係なく使える。To be frank（正直なところ）/ To be honest（正直に言えば）も同様。Telling the truth（分詞構文）は主語が一致する場合に使う。", rule: "To tell the truth：正直に言うと（独立不定詞・慣用表現）", kp: ["To tell the truth = 正直に言うと（独立不定詞）", "To tell the truth / To be frank / To be honest（独立不定詞の慣用表現）"] },
  { id: "g1351", diff: "lv3", axis: "form", tags: ["eiken2", "causative_make_passive"], stem: "The students were made ___ the entire chapter.", ja: "生徒たちはその章を全部暗記させられた。", answer: "to memorize", choices: ["to memorize", "memorize", "memorizing", "memorized", "to be memorized"], expl: "make + O + 動詞原形（能動態）が受動態になると：S + be made + to + 動詞原形。能動態「The teacher made the students memorize」→ 受動態「The students were made to memorize」。使役動詞の受動態では to 不定詞を使うことに注意。", rule: "be made to + 動詞原形：〜させられる（使役動詞 make の受動態）", kp: ["were made to memorize = 暗記させられた（make受動態）", "make O do（能動態）→ be made to do（受動態）：to が必要"] },
  { id: "g1352", diff: "lv2", axis: "form", tags: ["eiken3", "perception_verb_see"], stem: "I saw him ___ across the street.", ja: "私は彼が通りを渡っているのを見た。", answer: "crossing", choices: ["crossing", "cross", "to cross", "crossed", "crosses"], expl: "知覚動詞 + O + -ing（動作の途中を目撃）vs 知覚動詞 + O + 動詞原形（動作全体を目撃）。saw him crossing = 「渡っている最中を見た」（進行中の場面を目撃）。saw him cross = 「渡るのを（全体として）見た」。-ing は動作が進行中の場面を強調する。", rule: "知覚動詞 + O + -ing：〜しているのを見た・聞いた（進行中の場面を目撃）", kp: ["saw him crossing = 渡っているところを見た（進行中の場面）", "知覚動詞+O+-ing（途中）vs 知覚動詞+O+原形（全体）"] },
  { id: "g1353", diff: "lv3", axis: "logic", tags: ["eiken2", "partial_negation_not_all"], stem: "___ students in the class passed the final exam.", ja: "クラスの全員が期末試験に合格したわけではない。", answer: "Not all", choices: ["Not all", "No", "All not", "None of", "Not every"], expl: "部分否定：Not all = 全員が〜というわけではない（一部は当てはまる）。All students did not pass（全員が合格しなかった）は「誰も合格しなかった」とも解釈できる曖昧な表現なので Not all が正確。Not every も部分否定だが、Not all + 複数名詞 の形がより一般的。No students = 誰も合格しなかった（全否定）。", rule: "Not all + 名詞：全員が〜というわけではない（部分否定）", kp: ["Not all students passed = 全員合格したわけではない（部分否定）", "Not all（部分否定・一部は〜）vs No（全否定・誰も〜ない）"] },
  { id: "g1354", diff: "lv3", axis: "form", tags: ["eiken2", "reported_speech_tense_shift"], stem: "She said she ___ tired after the long meeting.", ja: "彼女は長い会議の後に疲れたと言った。", answer: "was", choices: ["was", "is", "will be", "has been", "were"], expl: "間接話法の時制の一致：直接話法 She said, 'I am tired.' → 間接話法 She said (that) she was tired. 主節が過去形（said）なので、従属節の is も過去形（was）に変わる（時制の一致）。will → would、have been → had been なども同様。", rule: "時制の一致：主節が過去形→従属節も過去形にシフト（間接話法）", kp: ["said she was tired = 疲れたと言った（時制の一致: is → was）", "主節 said（過去）→ 従属節 is→was / will→would / have→had（時制の一致）"] },
  { id: "g1355", diff: "lv2", axis: "logic", tags: ["eiken3", "as_long_as_condition"], stem: "___ you study hard, you will pass the exam.", ja: "一生懸命勉強する限り、試験に合格するだろう。", answer: "As long as", choices: ["As long as", "As far as", "So long as", "As much as", "As well as"], expl: "as long as = 〜する限り（条件）。「一生懸命勉強する限り」は as long as you study hard。so long as も同じ意味。as far as = 〜する限りにおいては（知識・範囲の限定）。as long as（条件）vs as far as（範囲・知識の限定）は混同しやすい。", rule: "as long as + S + V：〜する限り（条件の接続詞）", kp: ["As long as you study hard = 一生懸命勉強する限り（条件）", "as long as（条件・〜する限り）vs as far as（範囲・知識の限定）"] },
  { id: "g1356", diff: "lv3", axis: "form", tags: ["eiken2", "whatever_compound"], stem: "___ you decide, I will support you.", ja: "何を決めても、私はあなたを支持します。", answer: "Whatever", choices: ["Whatever", "However", "Wherever", "Whenever", "Whoever"], expl: "複合関係代名詞 whatever = 何が〜でも・何を〜でも（名詞節・副詞節）。whatever you decide = 「あなたが何を決めても」（あらゆる決断に対応）。however = どんなに〜でも（程度・方法）、wherever = どこで〜でも（場所）、whenever = いつ〜でも（時間）、whoever = 誰が〜でも（人）。", rule: "whatever + S + V：何が〜でも・何を〜でも（複合関係代名詞・譲歩）", kp: ["Whatever you decide = 何を決めても（複合関係代名詞）", "whatever（もの）/ whoever（人）/ wherever（場所）/ whenever（時）/ however（程度）"] },
  { id: "g1357", diff: "lv2", axis: "form", tags: ["eiken3", "non_restrictive_which_clause"], stem: "He is late again, ___ is often the case with him.", ja: "彼はまた遅刻した。彼にはよくあることだ。", answer: "which", choices: ["which", "that", "so", "what", "it"], expl: "非制限用法の関係代名詞 which は前の節全体を先行詞に取る。He is late again, which is often the case = 「彼はまた遅刻した、これは彼によくあることだ」。that は非制限用法には使えない。which is often the case with him = 「彼にはよくあることだが」という慣用的表現。", rule: "先行詞（節）+ which：前の節全体を受ける関係代名詞（非制限用法）", kp: ["which is often the case = それはよくあることだ（前節全体を受ける which）", "非制限用法の which は前の節全体を先行詞に取る（that は不可）"] },
  { id: "g1358", diff: "lv3", axis: "form", tags: ["eiken2", "have_O_do_causative"], stem: "I'll have the technician ___ the broken printer.", ja: "技術者に壊れたプリンターを修理させます。", answer: "fix", choices: ["fix", "to fix", "fixing", "fixed", "fixes"], expl: "have + O + 動詞原形（使役）：「〜に〜させる」（主語が意図的に誰かに動作をさせる）。have the technician fix = 「技術者に修理させる」。have + O + 過去分詞（使役受動）= 「〜してもらう」（have my car fixed = 車を修理してもらう）との違いに注意。", rule: "have + O + 動詞原形：〜に〜させる（使役・主語が意図的に行為を依頼）", kp: ["have the technician fix = 技術者に修理させる（使役：原形）", "have O do（使役：〜にさせる）vs have O done（使役受動：〜してもらう）"] },
  { id: "g1359", diff: "lv2", axis: "tense", tags: ["eiken3", "future_going_to"], stem: "Look at those dark clouds. It ___ going to rain soon.", ja: "あの黒い雲を見て。もうすぐ雨が降りそうだ。", answer: "is", choices: ["is", "will be", "was", "are", "has been"], expl: "be going to + 動詞原形 = 〜しそうだ（近い将来の予測・現在の証拠に基づく）。The subject it（天気）には is を使う（It is going to rain）。will は意志・純粋な予測に使い、be going to は現在の状況（黒い雲）に基づく予測に使う。", rule: "be going to：現在の証拠に基づく近未来の予測（〜しそうだ）", kp: ["It is going to rain = 雨が降りそうだ（現在の証拠に基づく予測）", "be going to（証拠あり予測）vs will（単純な意志・推量）"] },
  { id: "g1360", diff: "lv3", axis: "form", tags: ["eiken2", "subjunctive_past_perfect_wish"], stem: "I wish I ___ more carefully before signing the contract.", ja: "契約書にサインする前にもっと慎重に確認すればよかった。", answer: "had checked", choices: ["had checked", "checked", "have checked", "would check", "could check"], expl: "wish + 過去完了（仮定法過去完了）：過去の事実に反する後悔・願望を表す。「サインする前に確認すればよかった（実際はしなかった）」→ wish + had + 過去分詞。wish + 過去形は現在の願望（仮定法過去）、wish + had done は過去の願望（仮定法過去完了）。", rule: "wish + had + 過去分詞：〜すればよかった（過去への後悔・仮定法過去完了）", kp: ["wish I had checked = 確認すればよかった（過去の後悔）", "wish + 過去形（現在の願望）vs wish + 過去完了（過去の後悔）"] },
  { id: "g1361", diff: "lv2", axis: "logic", tags: ["eiken3", "not_A_but_B"], stem: "He went to London ___ for vacation but for work.", ja: "彼は休暇のためではなく、仕事のためにロンドンへ行った。", answer: "not", choices: ["not", "no", "neither", "never", "none"], expl: "not A but B = AではなくB（対比の表現）。not for vacation but for work = 「休暇のためではなく仕事のために」。neither A nor B = AもBも〜ない（二重否定）。not A but B は B を強調する対比的表現で、A と B は同じ品詞・構造のものが来る（並列）。", rule: "not A but B：AではなくB（対比・修正の表現）", kp: ["not for vacation but for work = 休暇のためではなく仕事のために（not A but B）", "not A but B（〜ではなくB）vs neither A nor B（AもBも〜ない）"] },
  { id: "g1362", diff: "lv3", axis: "form", tags: ["eiken2", "conditional_should_inversion"], stem: "___ you need any help, please don't hesitate to call me.", ja: "もし何か助けが必要でしたら、遠慮なく電話してください。", answer: "Should", choices: ["Should", "Would", "Could", "If", "Were"], expl: "仮定法の倒置（if を省略）：Should + S + 動詞原形 = もし〜なら（丁寧・フォーマルな条件表現）。Should you need = 「もし必要でしたら」（If you should need の if を省略して倒置）。Were + S + to do、Had + S + 過去分詞 も同様の倒置パターン。", rule: "Should + S + 動詞原形：もし〜なら（if を省略した仮定法倒置・丁寧表現）", kp: ["Should you need = もし必要でしたら（仮定法倒置・フォーマル）", "Should S V（現在仮定）/ Were S to V（現在反事実）/ Had S pp（過去反事実）の倒置"] },
  { id: "g1363", diff: "lv2", axis: "tense", tags: ["eiken3", "future_perfect"], stem: "By the time you arrive, I ___ finished cooking.", ja: "あなたが着く頃には、私は料理を終えているでしょう。", answer: "will have", choices: ["will have", "will be", "have", "had", "am going to have"], expl: "未来完了形：will have + 過去分詞 = 〜するころには〜し終えているだろう。「あなたが着く（未来）頃には料理が完了している」という未来の時点での完了を表す。By the time + 現在形（未来を表す）, will have + 過去分詞 というパターン。", rule: "will have + 過去分詞：〜するころには〜し終えているだろう（未来完了形）", kp: ["will have finished = 終えているでしょう（未来完了）", "by the time S + 現在形, will have pp（未来完了・その時点での完了）"] },
  { id: "g1364", diff: "lv3", axis: "logic", tags: ["eiken2", "participial_simultaneous"], stem: "She sat at her desk, ___ her chin on her hands.", ja: "彼女は手に顎をのせて、机に座っていた。", answer: "resting", choices: ["resting", "rested", "to rest", "rest", "having rested"], expl: "付帯状況の分詞構文：主節の動作と同時に起きている状況を表す。She sat at her desk, resting her chin = 「顎をのせながら座っていた」（同時の状況）。having rested は完了分詞構文（主節より先の動作）。resting her chin は能動的・継続的な状態を示す。", rule: "-ing（分詞構文）：〜しながら（主節と同時の付帯状況）", kp: ["resting her chin = 顎をのせながら（付帯状況の分詞構文）", "分詞構文 -ing（同時進行）vs having pp（先行完了）vs 過去分詞（受動・完了）"] },
  { id: "g1365", diff: "lv2", axis: "form", tags: ["eiken3", "too_for_to"], stem: "The box was ___ heavy for me to lift.", ja: "その箱は重すぎて私には持ち上げられなかった。", answer: "too", choices: ["too", "so", "very", "quite", "enough"], expl: "too + 形容詞/副詞 + to + 動詞原形 = 〜すぎて〜できない（否定の結果）。too heavy for me to lift = 「私が持ち上げるには重すぎる」。so heavy that I couldn't lift it も同義だが、for me を入れる場合は too 構文が自然。enough to（〜するのに十分）とは反対の意味。", rule: "too + 形容詞 + for O + to do：〜すぎてOには〜できない", kp: ["too heavy for me to lift = 私が持ち上げるには重すぎる（too-to構文）", "too A to do（否定の結果）vs adjective enough to do（肯定の結果）"] },
  { id: "g1366", diff: "lv3", axis: "tense", tags: ["eiken2", "mixed_conditional"], stem: "If I ___ your advice yesterday, I wouldn't be in trouble now.", ja: "昨日あなたの助言に従っていれば、今頃困っていないのに。", answer: "had followed", choices: ["had followed", "followed", "would follow", "have followed", "was following"], expl: "混合仮定法：過去の条件（if + 過去完了）→ 現在の結果（would + 動詞原形）。「昨日従っていれば（過去の非現実）→ 今頃困っていないのに（現在の結果）」。純粋な仮定法過去完了は過去の条件と過去の結果を両方過去完了で処理するが、混合仮定法は時制が異なる。", rule: "混合仮定法：if + 過去完了（過去の条件）→ would + 原形（現在の結果）", kp: ["had followed（過去の条件）→ wouldn't be（現在の結果）= 混合仮定法", "純粋仮定法過去完了（過去→過去）vs 混合仮定法（過去の条件→現在の結果）"] },
  { id: "g1367", diff: "lv2", axis: "logic", tags: ["eiken3", "by_the_time_deadline"], stem: "Please finish your homework ___ dinner is ready.", ja: "夕食の準備ができるまでに宿題を終わらせてください。", answer: "by the time", choices: ["by the time", "until", "when", "as soon as", "while"], expl: "by the time = 〜するまでに（期限・その時点までに完了）。「夕食の準備ができる時点までに終わらせる」→ by the time dinner is ready。until = 〜するまでずっと（継続・動作の終了点）。as soon as = 〜するとすぐに（即時）。by the time は完了の期限を示す。", rule: "by the time + S + V：〜するまでに（期限・その時点での完了を示す）", kp: ["by the time dinner is ready = 夕食の準備ができるまでに（期限）", "by the time（期限・完了）vs until（継続の終点）vs as soon as（即時）"] },
);
DATA.push(
  { id: "g1368", diff: "lv2", axis: "tense", tags: ["eiken3", "present_perfect_experience"], stem: "Have you ever ___ sushi before?", ja: "以前に寿司を食べたことがありますか？", answer: "eaten", choices: ["eaten", "ate", "eat", "eating", "had eaten"], expl: "現在完了形（経験）：Have you ever + 過去分詞 = 〜したことがありますか？。ever は疑問文で「今までに」の意味を強調する。「食べたことがある」は have eaten（eat の過去分詞）。ate は単純過去形で ever/before と組み合わせる現在完了用法には使えない。", rule: "Have you ever + 過去分詞：〜したことがありますか？（現在完了・経験の疑問文）", kp: ["Have you ever eaten = 食べたことがありますか？（経験の現在完了）", "ever（強調）は経験の現在完了疑問文でよく使う"] },
  { id: "g1369", diff: "lv2", axis: "logic", tags: ["eiken3", "in_order_to"], stem: "She studied hard ___ pass the entrance exam.", ja: "彼女は入試に合格するために一生懸命勉強した。", answer: "in order to", choices: ["in order to", "so as", "for to", "in order for", "so that"], expl: "in order to + 動詞原形 = 〜するために（目的）。to 不定詞の副詞的用法と同じ意味だが、in order to はより明確に目的を示す。so as to も同義（フォーマル）。for to は非標準。so that + S + can/could は節が続く（in order to + 動詞原形 とは構造が異なる）。", rule: "in order to + 動詞原形：〜するために（目的を明示する不定詞）", kp: ["studied hard in order to pass = 合格するために勉強した（目的）", "in order to（目的）= to（目的）= so as to（フォーマル）"] },
  { id: "g1370", diff: "lv3", axis: "form", tags: ["eiken2", "passive_present_perfect"], stem: "The old bridge ___ by the city council last year.", ja: "その古い橋は昨年市議会によって修復された。", answer: "was restored", choices: ["was restored", "has been restored", "is restored", "had been restored", "restored"], expl: "過去を表す時間表現（last year）があるため、単純過去の受動態 was + 過去分詞 を使う。has been restored は現在完了受動態（過去の特定時点を示す last year とは共起できない）。had been restored は過去完了受動態（さらに過去の時点が必要）。", rule: "was + 過去分詞：〜された（過去の受動態）", kp: ["was restored last year = 昨年修復された（過去受動態）", "過去特定時点（last year）→ 過去受動態 was pp / 現在完了 has been pp は使えない"] },
  { id: "g1371", diff: "lv2", axis: "logic", tags: ["eiken3", "preposition_at_emotion"], stem: "She was surprised ___ the sudden announcement.", ja: "彼女は突然の発表に驚いた。", answer: "at", choices: ["at", "by", "with", "for", "about"], expl: "be surprised at = 〜に驚く（感情の対象を表す前置詞 at）。at は感情を引き起こす直接の原因・対象に使う。be surprised by は受動態で「〜によって驚かされた」（動作主）。be amazed at / be shocked at も同様のパターン。", rule: "be surprised at + 名詞：〜に驚く（感情の前置詞 at）", kp: ["surprised at the announcement = 発表に驚いた（at = 感情の対象）", "be surprised at（感情の対象）vs be surprised by（動作主・受動態）"] },
  { id: "g1372", diff: "lv3", axis: "form", tags: ["eiken2", "subjunctive_suggest_present"], stem: "The doctor suggested that he ___ more rest.", ja: "医者は彼がもっと休むべきだと提案した。", answer: "get", choices: ["get", "gets", "got", "should get", "would get"], expl: "提案・要求・命令を表す動詞（suggest / recommend / insist / demand）の後の that 節では仮定法現在（動詞の原形）を使う。that he get = 「彼が休むべきだ」（原形）。gets は三単現で文法的には使えない（仮定法現在は人称・数に関わらず原形）。", rule: "suggest/recommend + that + S + 動詞原形：〜すべきだと提案する（仮定法現在）", kp: ["suggested that he get = 彼が休むよう提案した（仮定法現在・原形）", "suggest/recommend/insist + that S + 原形（仮定法現在：三単現のsなし）"] },
  { id: "g1373", diff: "lv3", axis: "tense", tags: ["eiken2", "sequence_of_tenses"], stem: "I thought the meeting ___ at nine, but it started at ten.", ja: "会議は9時に始まると思っていたが、10時に始まった。", answer: "started", choices: ["started", "starts", "had started", "would start", "was starting"], expl: "時制の一致：主節が過去形（thought）のとき、従属節も過去形にシフトする。「9時に始まる」という内容は「思っていた」時点での現在的な認識なので、starts（現在）→ started（過去）に一致させる。would start は未来の時制の一致（〜するだろうと思っていた）なので意味が異なる。", rule: "時制の一致：主節が過去形 → 従属節も過去形（現在→過去）", kp: ["thought (that) the meeting started = 〜が始まると思っていた（時制の一致）", "thought（過去）→ 従属節 starts→started（時制の一致）"] },
  { id: "g1374", diff: "lv2", axis: "form", tags: ["eiken3", "gerund_avoid"], stem: "He managed to avoid ___ a mistake on the final report.", ja: "彼はなんとか最終報告書のミスを避けることができた。", answer: "making", choices: ["making", "to make", "make", "made", "to making"], expl: "avoid は動名詞（-ing）を目的語にとる動詞。avoid making = 「作ることを避ける」。to make（不定詞）は使えない。動名詞を取る動詞: avoid / stop / enjoy / mind / finish / consider など。不定詞を取る動詞: want / hope / decide / promise など。", rule: "avoid + 動名詞（-ing）：〜することを避ける", kp: ["avoid making = ミスを避ける（avoid + 動名詞）", "動名詞 only: avoid/stop/enjoy/mind/finish vs 不定詞 only: want/hope/decide"] },
  { id: "g1375", diff: "lv3", axis: "form", tags: ["eiken2", "relative_clause_whose"], stem: "I know a girl ___ father is a famous actor.", ja: "私は父親が有名な俳優である少女を知っている。", answer: "whose", choices: ["whose", "who", "which", "that", "whom"], expl: "所有格の関係代名詞 whose = 〜の（人・物の所有を示す）。a girl whose father = 「その少女の父親が」（所有格）。who は主格・目的格（〜が・〜を）。which は物・動物（〜が）。whose は人にも物にも使え、後ろに名詞が続く（whose + 名詞）。", rule: "whose + 名詞：〜の〜（所有格の関係代名詞）", kp: ["a girl whose father = その少女の父親（所有格 whose）", "whose + 名詞（所有格）vs who + V（主格）vs whom + S + V（目的格）"] },
  { id: "g1376", diff: "lv2", axis: "logic", tags: ["eiken3", "while_contrast"], stem: "___ I enjoy classical music, my brother prefers rock.", ja: "私はクラシック音楽が好きだが、弟はロックを好む。", answer: "While", choices: ["While", "Whenever", "Because", "Since", "If"], expl: "while = 〜の一方で・〜に対して（対比の接続詞）。While I enjoy classical music = 「私はクラシックが好きな一方で」（対比）。although も「〜だけれども」と逆接に使えるが、while は2つの対照的な事実を並列するのに最適。because/since は理由、if は条件を表す。", rule: "while + S + V：〜の一方で（対比の接続詞）", kp: ["While I enjoy classical music = クラシックが好きな一方で（対比）", "while（対比・〜に対して）vs although（逆接・〜だが）の使い分け"] },
  { id: "g1377", diff: "lv3", axis: "form", tags: ["eiken2", "causative_make_passive_v2"], stem: "The children were ___ to clean the classroom.", ja: "子どもたちは教室を掃除させられた。", answer: "made", choices: ["made", "let", "had", "allowed", "forced"], expl: "make の受動態：be made to + 動詞原形 = 〜させられる。「掃除させられた」は were made to clean。let の受動態は be let do（to なし）だが通常 be allowed to do を使う。had の受動態（be had to do）は非標準。forced も「強制させられた」の意味だが、文は be made の形を求めている。", rule: "be made to + 動詞原形：〜させられる（make の受動態）", kp: ["were made to clean = 掃除させられた（make受動態）", "make O do（能動）→ be made to do（受動）：to が必要"] },
  { id: "g1378", diff: "lv2", axis: "logic", tags: ["eiken3", "worth_gerund"], stem: "This book is well ___ reading.", ja: "この本は読む価値が十分にある。", answer: "worth", choices: ["worth", "worthy", "worthwhile", "deserving", "valued"], expl: "be worth + 動名詞（-ing）= 〜する価値がある。well worth reading = 「読む価値が十分ある」。worthy は be worthy of + 名詞/動名詞（〜に値する）。worthwhile は It is worthwhile + to do / doing の形。worth は直後に動名詞が来る（worth reading = 読む価値がある）。", rule: "be worth + 動名詞：〜する価値がある", kp: ["well worth reading = 読む価値が十分ある（worth + 動名詞）", "worth doing（価値あり）vs worthy of doing（〜に値する）vs worthwhile to do（しがいある）"] },
  { id: "g1379", diff: "lv3", axis: "form", tags: ["eiken2", "cleft_sentence"], stem: "___ Mary who first noticed the mistake, not John.", ja: "最初にミスに気づいたのはメアリーで、ジョンではなかった。", answer: "It was", choices: ["It was", "She was", "There was", "It is", "What was"], expl: "強調構文：It is/was + 強調したい語句 + that/who + 残りの文。It was Mary who = 「（最初にミスに気づいたのは）メアリーだった」（Mary を強調）。現在の話ではなく過去の出来事なので It was を使う。not John で対比を強調。She was では強調構文にならない（that/who 以下で再度主語が来る構造）。", rule: "It was + 強調語句 + who/that：〜したのは〜だった（強調構文）", kp: ["It was Mary who noticed = 気づいたのはメアリーだった（強調構文）", "It is/was + 強調部分 + that/who（強調構文：主語・目的語・副詞を強調）"] },
  { id: "g1380", diff: "lv2", axis: "tense", tags: ["eiken3", "present_perfect_for_since"], stem: "I have lived in this city ___ I was a child.", ja: "私は子どものときからずっとこの街に住んでいる。", answer: "since", choices: ["since", "for", "during", "from", "while"], expl: "現在完了形の継続用法：since + 過去の時点（〜のとき以来）、for + 期間（〜の間）。since I was a child = 「子どものときから（ずっと）」（過去の起点）。for + 数年間・数ヶ月（期間を示す名詞）。during は特定の期間中（during summer）。since の後には過去の時点または過去形の節が来る。", rule: "現在完了 + since + 過去の時点：〜のときからずっと（継続の起点）", kp: ["since I was a child = 子どものときから（since + 過去時点）", "since（過去の起点）vs for（期間の長さ）vs during（特定期間中）"] },
  { id: "g1381", diff: "lv3", axis: "form", tags: ["eiken2", "prefer_a_to_b"], stem: "She ___ tea to coffee.", ja: "彼女はコーヒーよりも紅茶を好む。", answer: "prefers", choices: ["prefers", "prefer", "would prefer", "is preferring", "has preferred"], expl: "prefer A to B = AをBより好む（比較の好み）。She prefers tea to coffee = 「彼女は紅茶の方がコーヒーより好き」。prefer は状態動詞で通常進行形にしない（is preferring は不自然）。三単現なので prefers。would prefer は「〜の方が好きだ（今この瞬間の希望）」と意味がやや異なる。", rule: "prefer A to B：BよりAを好む（比較の好み）", kp: ["prefers tea to coffee = コーヒーより紅茶が好き（prefer A to B）", "prefer A to B（比較の好み）vs prefer to do（〜する方を好む）"] },
  { id: "g1382", diff: "lv3", axis: "form", tags: ["eiken2", "hardly_inversion"], stem: "___ had she sat down when the phone rang.", ja: "彼女が座るやいなや電話が鳴った。", answer: "Hardly", choices: ["Hardly", "Soon", "No sooner", "Almost", "Never"], expl: "否定副詞倒置：Hardly/Scarcely + had + S + 過去分詞 + when + S + 過去形 = 〜するやいなや。Hardly had she sat down when = 「座るやいなや電話が鳴った」。No sooner は No sooner had S pp than S V のパターン（when でなく than）。Scarcely も同じパターンだが when と共起する。", rule: "Hardly had + S + 過去分詞 + when + S + 過去形：〜するやいなや（否定副詞倒置）", kp: ["Hardly had she sat down when = 座るやいなや（否定副詞倒置）", "Hardly/Scarcely + had S pp + when（〜するやいなや）/ No sooner + had S pp + than"] },
  { id: "g1383", diff: "lv2", axis: "form", tags: ["eiken3", "unless_condition"], stem: "You won't succeed ___ you try harder.", ja: "もっと努力しない限り、成功しないだろう。", answer: "unless", choices: ["unless", "if", "although", "when", "until"], expl: "unless = 〜しない限り（否定条件）。unless you try harder = 「もっと努力しない限り」（努力しなければ成功しない）。if not とほぼ同じ意味。although は逆接（〜だが）。until は継続（〜するまで）。unless は「その条件を満たさなければ」という例外条件を表す。", rule: "unless + S + V：〜しない限り（否定条件の接続詞）", kp: ["unless you try harder = もっと努力しない限り（否定条件）", "unless（〜しない限り）≈ if ... not（〜でなければ）"] },
  { id: "g1384", diff: "lv3", axis: "form", tags: ["eiken2", "reported_speech_how"], stem: "She asked me ___ I had finished the project.", ja: "彼女は私がプロジェクトを終えたかどうか尋ねた。", answer: "whether", choices: ["whether", "that", "what", "how", "if whether"], expl: "間接疑問（whether / if）：asked whether = 「〜かどうか尋ねた」。whether と if はどちらも「〜かどうか」の意味だが、whether の方がフォーマルで、whether or not の形も使える。that は同格節（said that = 〜と言った）。how は方法・程度を問う疑問詞（how I did it など）。", rule: "ask whether/if + S + V：〜かどうか尋ねる（間接疑問・whether/if）", kp: ["asked whether I had finished = 終えたかどうか尋ねた（間接疑問）", "whether（かどうか・フォーマル）= if（かどうか・カジュアル）"] },
  { id: "g1385", diff: "lv2", axis: "logic", tags: ["eiken3", "so_that_purpose"], stem: "He spoke slowly ___ everyone could understand him.", ja: "みんなに理解してもらえるように、彼はゆっくり話した。", answer: "so that", choices: ["so that", "so as", "in order", "such that", "for that"], expl: "so that + S + can/could + 動詞原形 = 〜するように・〜のために（目的）。so that everyone could understand = 「みんなが理解できるように」。so as to は後ろに動詞原形（so as to be understood など）。in order that も同義だがフォーマル。such that は結果を表す（so great that など）。", rule: "so that + S + can/could：〜できるように（目的を表す副詞節）", kp: ["so that everyone could understand = 理解できるように（目的の so that）", "so that S can（目的）vs so ... that S（結果）の区別"] },
  { id: "g1386", diff: "lv3", axis: "form", tags: ["eiken2", "it_takes_time"], stem: "It ___ me two hours to finish the essay.", ja: "そのエッセイを書き終えるのに2時間かかった。", answer: "took", choices: ["took", "spent", "needed", "required", "costed"], expl: "It takes + 人 + 時間 + to do = 〜するのに（人が）〜かかる。過去の話なので It took = 「かかった」。spend は S + spend + 時間 + on/doing（主語が人）。It took me two hours to finish = 「終えるのに2時間かかった」。require / need は人を間接目的語にとる構文では使わない（It required me... は不自然）。", rule: "It takes + O + 時間 + to do：〜するのに〜かかる（時間の所要）", kp: ["It took me two hours to finish = 終えるのに2時間かかった（It takes構文）", "It takes 人 時間 to do（所要時間）vs S spend 時間 on/doing（人が〜に費やす）"] },
  { id: "g1387", diff: "lv3", axis: "form", tags: ["eiken2", "inversion_negative_adverb_never"], stem: "___ had I seen such a beautiful sunset before.", ja: "それほど美しい夕焼けを以前に見たことがなかった。", answer: "Never", choices: ["Never", "Seldom", "Rarely", "Hardly", "No"], expl: "否定副詞を文頭に置く倒置：Never + had + S + 過去分詞 + such ... = 「それほど〜を見たことがなかった」（否定副詞倒置）。Never had I seen = 「私は一度も見たことがなかった」。Seldom/Rarely + 助動詞 + S + 動詞原形の倒置（現在時制）とは異なる。Hardly は Hardly had S pp when と組み合わせる（〜するやいなや）。", rule: "Never had + S + 過去分詞：〜を一度もしたことがなかった（否定副詞倒置・現在完了）", kp: ["Never had I seen = 一度も見たことがなかった（Never倒置・過去完了）", "否定副詞倒置: Never/Seldom/Rarely/Hardly + 助動詞/had + S + 動詞（疑問文語順）"] },
  { id: "g1388", diff: "lv2", axis: "logic", tags: ["eiken3", "relative_adverb_when"], stem: "I remember the day ___ we first met.", ja: "私たちが初めて会ったあの日のことを覚えている。", answer: "when", choices: ["when", "which", "that", "where", "who"], expl: "関係副詞 when = 〜したとき（時を表す先行詞に続く）。the day when we first met = 「私たちが初めて会った日」。which は関係代名詞（物・物事）で後に名詞が欠ける節が続く。where は場所の関係副詞。when は先行詞が time / day / moment / year などの時間名詞のとき使う。", rule: "関係副詞 when：時を表す先行詞 + when + S + V", kp: ["the day when we met = 私たちが会った日（関係副詞when）", "when（時間）/ where（場所）/ why（理由）/ how（方法）の関係副詞"] },
  { id: "g1389", diff: "lv3", axis: "form", tags: ["eiken2", "with_absolute_construction"], stem: "She sat at her desk, ___ her eyes closed.", ja: "彼女は目を閉じたまま机に座っていた。", answer: "with", choices: ["with", "while", "having", "by", "as"], expl: "付帯状況の with：with + O + 形容詞/過去分詞/現在分詞 = 〜の状態で・〜しながら。with her eyes closed = 「目が閉じた状態で」（closed は目の状態を表す過去分詞）。while は接続詞で節が続く（while her eyes were closed）。having は分詞構文の完了形（having done）。", rule: "with + O + 過去分詞/形容詞：〜の状態で（付帯状況）", kp: ["with her eyes closed = 目を閉じた状態で（付帯状況のwith）", "with O pp（状態）/ with O -ing（動作進行中）の使い分け"] },
  { id: "g1390", diff: "lv3", axis: "form", tags: ["eiken2", "mixed_conditional"], stem: "If I ___ harder at school, I would have a better job now.", ja: "学校でもっと頑張っていたら、今頃もっと良い仕事に就いているだろう。", answer: "had studied", choices: ["had studied", "studied", "would study", "would have studied", "have studied"], expl: "混合仮定法：if 節に過去完了（仮定法過去完了）、主節に would + 動詞原形（仮定法過去）。「過去の条件が現在に影響する」パターン。If I had studied harder（過去の非現実）→ I would have a better job now（現在の非現実）。if 節が would have studied なら非標準。", rule: "混合仮定法：If S had pp（過去条件）+ S would + V（現在の結果）", kp: ["If I had studied harder ... would have now = 混合仮定法（過去条件→現在結果）", "if節：had pp（過去完了仮定法）/ 主節：would + 原形（現在仮定法）"] },
  { id: "g1391", diff: "lv3", axis: "form", tags: ["eiken2", "perfect_infinitive_seem"], stem: "She seems ___ the answer before the exam.", ja: "彼女は試験前に答えを知っていたようだ。", answer: "to have known", choices: ["to have known", "to know", "knowing", "to be knowing", "having known"], expl: "完了不定詞（to have + 過去分詞）：現在の述語動詞（seems）より前の時点の出来事を表す。She seems to have known = 「彼女は（以前に）知っていたようだ」。to know なら現在と同時点（今知っているようだ）。to have known = 主節より過去の出来事の推量に使う。", rule: "seem to have pp：〜したようだ（完了不定詞で過去の推量）", kp: ["seems to have known = 以前に知っていたようだ（完了不定詞）", "to V（主節と同時）vs to have pp（主節より前の時点）"] },
  { id: "g1392", diff: "lv3", axis: "form", tags: ["eiken2", "proportional_comparison"], stem: "___ you practice, ___ you will become.", ja: "練習すればするほど、上手くなる。", answer: "The more / the better", choices: ["The more / the better", "More / more", "The more / more", "More / the better", "As more / so better"], expl: "比例比較：The + 比較級 ..., the + 比較級 ... = 〜すればするほど〜。The more you practice, the better you will become = 「練習すればするほど上手くなる」。両方に the が必要。More / more や The more / more は不完全な形。", rule: "The + 比較級 ..., the + 比較級 ...：〜すればするほど〜（比例）", kp: ["The more you practice, the better = 練習すればするほど上手くなる", "両方に the が必要（The 比較級, the 比較級）"] },
  { id: "g1393", diff: "lv3", axis: "form", tags: ["eiken2", "formal_object_it"], stem: "I found ___ difficult to understand his explanation.", ja: "彼の説明を理解するのは難しいと感じた。", answer: "it", choices: ["it", "that", "this", "them", "one"], expl: "形式目的語 it：find / make / think + it + 形容詞 + to do / that節。I found it difficult to understand = 「理解するのが難しいと感じた」。it は後の to understand his explanation を指す形式目的語（仮目的語）。that を使う場合は I found that ... の形（形式目的語なし）。", rule: "find it + 形容詞 + to do：〜することが〜だとわかる（形式目的語 it）", kp: ["found it difficult to understand = 理解するのが難しいとわかった（形式目的語it）", "find/make/think + it + 形容詞 + to do（形式目的語itパターン）"] },
  { id: "g1394", diff: "lv3", axis: "form", tags: ["eiken2", "regret_gerund_infinitive"], stem: "I regret ___ him the bad news so abruptly.", ja: "彼にそんなに急に悪い知らせを告げたことを後悔している。", answer: "telling", choices: ["telling", "to tell", "tell", "having tell", "told"], expl: "regret + 動名詞 = 〜したことを後悔する（過去の行為を悔やむ）。regret + to不定詞 = 残念ながら〜する（これからすることへの残念な気持ち）。I regret telling him = 「彼に言ってしまったことを後悔する」（過去の行為への後悔）。I regret to tell you = 「残念ながらお知らせします」（これから言うことへの遺憾）。", rule: "regret + 動名詞：〜したことを後悔する（過去）/ regret + to do：残念ながら〜する（未来）", kp: ["regret telling = 言ってしまったことを後悔（動名詞→過去の行為）", "regret to tell = 残念ながらお知らせする（不定詞→これからの行為）"] },
  { id: "g1395", diff: "lv3", axis: "logic", tags: ["eiken2", "whatever_complex_relative"], stem: "___ happens, stay calm and focused.", ja: "何が起きても、落ち着いて集中し続けなさい。", answer: "Whatever", choices: ["Whatever", "Whoever", "Whenever", "However", "Whichever"], expl: "複合関係代名詞 whatever = 何が〜しても（no matter what + S + V の強調表現）。Whatever happens = 「何が起きても」（条件・譲歩の副詞節）。Whoever は「誰が〜しても」、Whenever は「いつ〜しても」、However は「どんなに〜しても」（後に形容詞/副詞が続く）。", rule: "whatever + V：何が〜しても（複合関係代名詞・譲歩）", kp: ["Whatever happens = 何が起きても（複合関係代名詞・譲歩）", "whatever（何でも）/ whoever（誰でも）/ whenever（いつでも）/ however（どんなに）"] },
  { id: "g1396", diff: "lv3", axis: "logic", tags: ["eiken2", "no_matter_how"], stem: "___ tired you are, you should not give up.", ja: "どんなに疲れていても、諦めるべきではない。", answer: "No matter how", choices: ["No matter how", "Although", "No matter what", "Despite how", "Even if how"], expl: "No matter how + 形容詞/副詞 + S + V = どんなに〜でも（譲歩の副詞節）。No matter how tired = 「どんなに疲れていても」。however も同義（However tired you are...）。No matter what は「何が〜しても」で後に名詞/動詞が続く（形容詞は続かない）。despite は前置詞で節は続かない（despite + 名詞/動名詞）。", rule: "No matter how + 形容詞/副詞：どんなに〜でも（譲歩の副詞節）", kp: ["No matter how tired = どんなに疲れていても（譲歩）", "No matter how（どんなに）= however / No matter what（何でも）= whatever"] },
  { id: "g1397", diff: "lv2", axis: "form", tags: ["eiken3", "be_fond_of_gerund"], stem: "She is very fond ___ listening to jazz music.", ja: "彼女はジャズを聴くのがとても好きだ。", answer: "of", choices: ["of", "for", "in", "at", "with"], expl: "be fond of + 名詞/動名詞 = 〜が好きである。fond of listening = 「聴くことが好きな」。of は fond と結びつく前置詞（形容詞 fond は of を伴う）。for は fond には使わない（be known for / be famous for など）。be fond of の後は名詞または動名詞（-ing）が来る。", rule: "be fond of + 名詞/動名詞：〜が好きである（形容詞 fond の前置詞）", kp: ["fond of listening = 聴くことが好き（be fond of + 動名詞）", "fond of / proud of / afraid of / tired of（形容詞 + of のパターン）"] },
  { id: "g1398", diff: "lv2", axis: "logic", tags: ["eiken3", "indirect_question_where"], stem: "Can you tell me ___ the post office is?", ja: "郵便局がどこにあるか教えてもらえますか？", answer: "where", choices: ["where", "that", "what", "how", "which"], expl: "間接疑問文：疑問詞 + S + V の語順（直接疑問文の倒置を戻す）。tell me where the post office is = 「郵便局がどこにあるか教えて」（where + S + V）。直接疑問文なら「Where is the post office?」だが、間接疑問では倒置しない（where is → where S is）。what / how は他の疑問詞で文脈に合わない。", rule: "間接疑問：疑問詞 + S + V（倒置しない）", kp: ["where the post office is = 郵便局がどこか（間接疑問・倒置なし）", "直接疑問 Where is it? → 間接疑問 where it is（語順変化なし）"] },
  { id: "g1399", diff: "lv3", axis: "form", tags: ["eiken2", "passive_progressive"], stem: "The road ___ by workers when the accident occurred.", ja: "事故が起きたとき、道路は作業員によって修理されていた。", answer: "was being repaired", choices: ["was being repaired", "was repaired", "had been repaired", "is being repaired", "was repairing"], expl: "過去進行受動態（was/were + being + 過去分詞）：過去のある時点で進行中だった受動の動作。when the accident occurred（事故発生時）に進行中だった工事 = was being repaired。was repaired は単純な過去受動態（完了した動作）。is being repaired は現在進行受動態。", rule: "was/were being + 過去分詞：〜されていた（過去進行受動態）", kp: ["was being repaired = 修理されていた（過去進行受動態）", "be + being + pp（進行受動態）：was being done vs was done（完了受動）"] },
  { id: "g1400", diff: "lv4", axis: "form", tags: ["eiken1", "inversion_were_it_not_for"], stem: "___ your help, I could not finish the project.", ja: "あなたの助けがなければ、そのプロジェクトを終えられないだろう。", answer: "Were it not for", choices: ["Were it not for", "If it was not for", "Unless it was for", "Had it not been", "Without it for"], expl: "Were it not for = 〜がなければ（if it were not for の倒置形）。仮定法過去の if it were not for ... を倒置した形（if を省略して were を前置）。I could not have finished は仮定法過去完了（主節）で「終えられなかっただろう」。Had it not been for は同様の倒置だが過去完了仮定法（if it had not been for）。文脈は現在の仮定なので Were it not for が正解。", rule: "Were it not for + 名詞：〜がなければ（if it were not for の倒置・仮定法過去）", kp: ["Were it not for your help = あなたの助けがなければ（仮定法倒置）", "Were it not for（現在仮定）vs Had it not been for（過去仮定）"] },
  { id: "g1401", diff: "lv2", axis: "form", tags: ["eiken3", "emphatic_do"], stem: "I ___ enjoy classical music, but only in small doses.", ja: "私はクラシック音楽を確かに楽しむが、少しずつだけだ。", answer: "do", choices: ["do", "really", "very", "so", "indeed"], expl: "強調の助動詞 do/does/did：動詞の前に置いて「確かに〜する」と強調する。I do enjoy = 「確かに楽しむ」（強調）。この do は疑問文・否定文の助動詞とは異なり、肯定文で動詞を強調する用法。really は副詞で do のように動詞の直前に置いて強調できるが、選択肢の中で文法的に自然な強調助動詞は do。", rule: "do/does/did + 動詞原形：確かに〜する（強調の助動詞）", kp: ["I do enjoy = 確かに楽しむ（強調の do）", "強調の do/does/did + 動詞原形（否定・疑問文の助動詞とは別用法）"] },
  { id: "g1402", diff: "lv2", axis: "form", tags: ["eiken3", "tag_question_there"], stem: "There is still some milk in the fridge, ___ there?", ja: "冷蔵庫にまだ牛乳が少しありますよね？", answer: "isn't", choices: ["isn't", "is", "aren't", "doesn't", "has"], expl: "There is/are 構文の付加疑問文：There is ... → isn't there?（否定形・倒置）。some milk（単数扱い）→ there is → 付加疑問は isn't there?。aren't there はthere are（複数）の付加疑問。付加疑問の主語は there（元の文の there を繰り返す）。", rule: "There is ... + isn't there?：〜がありますよね（There is構文の付加疑問）", kp: ["There is ... isn't there? = あますよね（付加疑問）", "There is → isn't there / There are → aren't there（主語はthereのまま）"] },
  { id: "g1403", diff: "lv2", axis: "form", tags: ["eiken3", "adjective_enough_to"], stem: "She is ___ enough to lift that heavy box.", ja: "彼女はあの重い箱を持ち上げられるくらい力強い。", answer: "strong", choices: ["strong", "strongly", "strength", "stronger", "strongest"], expl: "enough to 構文：形容詞/副詞 + enough + to do = 〜するのに十分なほど〜。strong enough to lift = 「持ち上げられるくらい力強い」。enough は形容詞・副詞の後に置く（前には置かない）。strongly（副詞）は be 動詞の補語にならない。strength は名詞で be strong と使い分ける。", rule: "形容詞 + enough + to do：〜するのに十分〜（enough to 構文）", kp: ["strong enough to lift = 持ち上げられるくらい力強い（形容詞 + enough to）", "enough は形容詞の後（strong enough）・名詞の前（enough time）"] },
  { id: "g1404", diff: "lv3", axis: "form", tags: ["eiken2", "as_though_subjunctive"], stem: "The child cried as though he ___ seriously hurt.", ja: "その子は本当に深刻に怪我をしたかのように泣いた。", answer: "were", choices: ["were", "was", "is", "had been", "would be"], expl: "as though + 仮定法過去（be動詞は were）：現在の非現実的な比較。The child cried as though he were hurt = 「怪我したかのように泣いた」（実際は怪我していない）。as though の後の仮定法では be動詞はすべて were（主語が何であっても）。had been は過去完了仮定法（as though he had been hurt = 過去にされた非現実）。", rule: "as though + 仮定法過去（were）：まるで〜かのように（非現実の比較）", kp: ["as though he were hurt = 怪我したかのように（仮定法過去）", "as though + were（be動詞は全人称 were）/ had pp（過去完了仮定法）"] },
  { id: "g1405", diff: "lv3", axis: "form", tags: ["eiken2", "should_have_pp"], stem: "You should ___ the doctor earlier.", ja: "もっと早く医者に行くべきだったのに。", answer: "have seen", choices: ["have seen", "see", "have been seeing", "had seen", "to have seen"], expl: "should have + 過去分詞 = 〜すべきだったのに（しなかった後悔・批判）。should have seen = 「診てもらうべきだったのに（実際は行かなかった）」。should see は現在・未来に対するアドバイス（診てもらうべきだ）。had seen は過去完了（時制の関係を示す）。", rule: "should have + 過去分詞：〜すべきだったのに（過去の後悔・批判）", kp: ["should have seen = 診てもらうべきだった（後悔）", "should have pp（過去の後悔）vs should V（現在のアドバイス）"] },
  { id: "g1406", diff: "lv3", axis: "form", tags: ["eiken2", "neither_nor"], stem: "___ Tom ___ his brother was at home when I called.", ja: "私が電話したとき、トムも彼の兄も家にいなかった。", answer: "Neither / nor", choices: ["Neither / nor", "Either / or", "Both / and", "Not only / but also", "Whether / or"], expl: "Neither A nor B = AもBも〜ない（2つとも否定）。Neither Tom nor his brother = 「トムも彼の兄も（どちらも）〜ない」。動詞は B（his brother）に一致させる（his brother was）。Either A or B は「AかBか」（どちらか一方）。Both A and B は「AもBも」（肯定）。", rule: "Neither A nor B + V：AもBも〜ない（二重否定の相関接続詞）", kp: ["Neither Tom nor his brother = どちらも〜ない（neither A nor B）", "Neither A nor B → 動詞は B に一致（近接一致の原則）"] },
  { id: "g1407", diff: "lv3", axis: "logic", tags: ["eiken2", "whichever"], stem: "You may take ___ seat you prefer.", ja: "好きな席をどれでも取ってよい。", answer: "whichever", choices: ["whichever", "whatever", "whoever", "whenever", "however"], expl: "複合関係形容詞 whichever + 名詞 = どの〜でも（限られた選択肢の中から）。whichever seat you prefer = 「あなたが好むどの席でも」（複数の席の中から選ぶ）。whatever も「どんな〜でも」だが、選択肢が限定されていない場合に使う（whatever you want など）。whichever は「複数の限られた選択肢のうちのどれでも」というニュアンス。", rule: "whichever + 名詞：どの〜でも（複合関係形容詞・限定選択）", kp: ["whichever seat you prefer = 好きな席をどれでも（複合関係形容詞）", "whichever（限られた選択肢から）vs whatever（制限なし）の使い分け"] },
  { id: "g1408", diff: "lv2", axis: "tense", tags: ["eiken3", "have_been_to_experience"], stem: "Have you ever ___ to New York?", ja: "ニューヨークに行ったことがありますか？", answer: "been", choices: ["been", "gone", "went", "go", "going"], expl: "have been to + 場所 = 〜に行ったことがある（経験の現在完了）。have gone to は「（今）〜に行ってしまった（いない）」の意味（出発・不在）で、経験の意味には使えない。Have you ever been to ...? = 「〜に行ったことがありますか？」（経験を問う）。", rule: "have been to + 場所：〜に行ったことがある（経験の現在完了）", kp: ["have been to New York = ニューヨークに行ったことがある（経験）", "have been to（経験）vs have gone to（出発・不在）の使い分け"] },
  { id: "g1409", diff: "lv3", axis: "form", tags: ["eiken2", "not_until_emphasis"], stem: "___ the sun set ___ the children came home.", ja: "日が沈んで初めて、子供たちは帰宅した。", answer: "Not until / did", choices: ["Not until / did", "Until / did", "Not until / that", "Only if / then", "Unless / did"], expl: "否定副詞倒置：Not until + 時間表現 + 助動詞 + S + V = 〜して初めて〜した。Not until the sun set did the children come home = 「日が沈んで初めて帰宅した」（not until を文頭に置き、主節を倒置）。It was not until ... that S V の強調構文も同義。", rule: "Not until ... + 助動詞 + S + V：〜して初めて〜した（否定副詞倒置）", kp: ["Not until the sun set did they come home = 日が沈んで初めて（倒置）", "Not until + 時/条件 → 主節を倒置（did/was/had + S + V）"] },
  { id: "g1410", diff: "lv2", axis: "form", tags: ["eiken3", "without_gerund"], stem: "He left the room ___ saying goodbye.", ja: "彼はさよならも言わずに部屋を出た。", answer: "without", choices: ["without", "instead of", "before", "despite", "by"], expl: "without + 動名詞 = 〜せずに（否定的な付帯状況・方法）。without saying goodbye = 「さよならを言わずに」。instead of は「〜の代わりに」、before は「〜する前に」（接続詞または前置詞として使う）。without は「〜なしに・〜せずに」という欠如・否定を表す前置詞。", rule: "without + 動名詞：〜せずに・〜なしに（否定的付帯状況）", kp: ["without saying goodbye = さよならを言わずに（without + 動名詞）", "without + V-ing（〜せずに）vs by + V-ing（〜することで）"] },
  { id: "g1411", diff: "lv2", axis: "form", tags: ["eiken3", "be_used_to_gerund"], stem: "She is used to ___ up early every morning.", ja: "彼女は毎朝早起きすることに慣れている。", answer: "getting", choices: ["getting", "get", "got", "have gotten", "being gotten"], expl: "be used to + 動名詞 = 〜することに慣れている。used to + 動詞原形（過去の習慣）とは異なる。be used to の to は前置詞なので後には動名詞（-ing形）が続く。She is used to getting up early = 「早起きに慣れている」（現在の習慣的状態）。", rule: "be used to + 動名詞：〜することに慣れている（toは前置詞）", kp: ["is used to getting up = 早起きに慣れている（be used to + 動名詞）", "be used to V-ing（慣れている）vs used to V（過去の習慣）の区別"] },
  { id: "g1412", diff: "lv3", axis: "form", tags: ["eiken2", "whose_relative"], stem: "I know a scientist ___ research changed the world.", ja: "私は世界を変えた研究をした科学者を知っている。", answer: "whose", choices: ["whose", "who", "which", "that", "whom"], expl: "関係代名詞 whose = 所有格（〜の）。先行詞（a scientist）の所有格として使う。whose research = 「その科学者の研究」（所有関係）。who は主格（〜が〜する）、whom は目的格（〜を）。which は物・事に使う関係代名詞。whose は人・物どちらの先行詞にも使える。", rule: "関係代名詞 whose + 名詞：〜の（所有格の関係代名詞）", kp: ["whose research changed = その人の研究が変えた（所有格関係代名詞）", "whose = of whom/of which の所有関係（人・物どちらにも使える）"] },
  { id: "g1413", diff: "lv3", axis: "form", tags: ["eiken2", "insist_subjunctive"], stem: "The doctor insisted that the patient ___ more rest.", ja: "医師は患者がもっと休養を取るべきだと主張した。", answer: "take", choices: ["take", "takes", "took", "should takes", "taking"], expl: "insist that + S + 動詞原形（仮定法現在）：〜すべきだと主張する（要求・提案の動詞 + that 節 → 仮定法現在 = 動詞原形）。demand / suggest / recommend / require / insist + that + S + 原形。主語が三単現でも原形のまま（takes ではなく take）。", rule: "insist that + S + 動詞原形（仮定法現在）：〜すべきだと主張する", kp: ["insisted that the patient take = 患者が休むべきと主張（仮定法現在）", "insist/demand/suggest + that + S + 原形（三単現sなし）"] },
  { id: "g1414", diff: "lv3", axis: "form", tags: ["eiken2", "in_spite_of"], stem: "___ the bad weather, the game was not cancelled.", ja: "悪天候にもかかわらず、試合は中止されなかった。", answer: "In spite of", choices: ["In spite of", "Although", "Despite of", "Even though", "Because of"], expl: "in spite of + 名詞/動名詞 = 〜にもかかわらず（前置詞句）。Despite も同義だが despite of とは言わない（despite の後に直接名詞が続く）。although/even though は接続詞で後に節（S + V）が続く。in spite of the bad weather = 「悪天候にもかかわらず」。", rule: "in spite of + 名詞：〜にもかかわらず（前置詞句）", kp: ["In spite of the bad weather = 悪天候にもかかわらず（前置詞句）", "in spite of（前置詞 + 名詞）vs although（接続詞 + 節）/ despite（前置詞・of不要）"] },
  { id: "g1415", diff: "lv3", axis: "form", tags: ["eiken2", "much_comparative"], stem: "Her new apartment is ___ bigger than her old one.", ja: "彼女の新しいアパートは以前のものよりずっと広い。", answer: "much", choices: ["much", "very", "so", "too", "quite"], expl: "比較級の強調：much / far / even / still / a lot + 比較級 = ずっと〜。much bigger = 「ずっと大きい」。very は原級の強調（very big）で比較級には使えない（× very bigger）。too は「〜すぎる」で否定的ニュアンス。so / quite も比較級強調には使わない。", rule: "much/far/even + 比較級：ずっと〜（比較級の強調語）", kp: ["much bigger = ずっと大きい（much + 比較級の強調）", "比較級強調: much/far/even/still/a lot（very は不可）"] },
  { id: "g1416", diff: "lv3", axis: "tense", tags: ["eiken2", "by_the_time_past_perfect"], stem: "By the time we arrived at the station, the train ___.", ja: "私たちが駅に着いた時には、電車はもう出てしまっていた。", answer: "had already left", choices: ["had already left", "already left", "has already left", "was already leaving", "would leave"], expl: "by the time + 過去形の節 → 主節に過去完了（had + 過去分詞）：〜する前にすでに〜していた。By the time we arrived = 「私たちが着いた時点では」（過去の基準時点）→ その前に完了した出来事 = had left（過去完了）。現在完了（has left）は現在が基準なので不可。", rule: "by the time S + 過去形 → had + 過去分詞：〜したときにはすでに〜していた（過去完了）", kp: ["By the time we arrived, had already left = 着いた時にはもう発車（過去完了）", "by the time（過去節）→ 過去完了（had pp）で完了済みを表す"] },
  { id: "g1417", diff: "lv3", axis: "form", tags: ["eiken2", "keep_from_gerund"], stem: "The heavy rain ___ us from going on the picnic.", ja: "大雨のせいで、私たちはピクニックに行けなかった。", answer: "kept", choices: ["kept", "prevented", "stopped", "banned", "held"], expl: "keep O from V-ing = O が〜するのを妨げる・防ぐ。The heavy rain kept us from going = 「大雨が私たちのピクニックを妨げた」。prevent O from V-ing も同義。stop O from V-ing も可。banned はより法的・公式な禁止。held back from に近いが held alone では構文が合わない。keep / prevent / stop + O + from + V-ing のセットで覚える。", rule: "keep O from V-ing：OがVするのを妨げる（prevent / stop も同義）", kp: ["kept us from going = 行くのを妨げた（keep O from V-ing）", "keep/prevent/stop + O + from + V-ing（妨げる構文のセット）"] },
  { id: "g1418", diff: "lv2", axis: "form", tags: ["eiken3", "exhausted_exhausting"], stem: "After the marathon, all the runners felt completely ___.", ja: "マラソンの後、すべてのランナーは完全に疲れ果てていた。", answer: "exhausted", choices: ["exhausted", "exhausting", "exhaust", "to exhaust", "exhaustion"], expl: "感情・状態を表す分詞形容詞：-ed形 = 〜している（人・経験者の感情）、-ing形 = 〜させる（物事の性質）。felt exhausted = 「疲れ果てた（と感じた）」（ランナー自身の状態）。The marathon was exhausting = 「マラソンは疲れさせるもの」（物事が〜させる）。主語が人・生き物のとき → -ed形。", rule: "-ed形（〜している・疲れた）vs -ing形（〜させる）：分詞形容詞の使い分け", kp: ["felt exhausted = 疲れ果てた（-ed形：人の感情・状態）", "exhausted（人が疲れた）vs exhausting（物事が疲れさせる）"] },
  { id: "g1419", diff: "lv3", axis: "logic", tags: ["eiken2", "a_number_of_vs_the_number_of"], stem: "___ students in the class have passed the exam.", ja: "クラスのかなりの数の生徒が試験に合格した。", answer: "A number of", choices: ["A number of", "The number of", "A lot the", "Numbers of", "Much"], expl: "a number of + 複数名詞 = かなりの数の〜（複数扱い・動詞は複数形）。the number of + 複数名詞 = 〜の数（単数扱い・動詞は単数形）。A number of students have passed（複数）vs The number of students has increased（単数）。a number of ≒ many / several。", rule: "a number of + 複数名詞（複数扱い）vs the number of（単数扱い）", kp: ["A number of students have = かなりの数の生徒が（複数扱い）", "a number of（多くの・複数扱い）vs the number of（〜の数・単数扱い）"] },
  { id: "g1420", diff: "lv2", axis: "form", tags: ["eiken3", "gerund_subject_singular"], stem: "___ regular exercise is essential for good health.", ja: "定期的な運動をすることは健康に不可欠だ。", answer: "Taking", choices: ["Taking", "Take", "To take", "Taken", "Takes"], expl: "動名詞（V-ing）または不定詞（to + 動詞原形）は文の主語になれる。Taking regular exercise = 「定期的な運動をすること」。動名詞主語は三単現扱い（is essential）。To take も主語になれるが、文頭の主語には動名詞の方が自然（英語では to 不定詞主語は堅め）。", rule: "動名詞（V-ing）を主語に：〜することは〜だ（三単現扱い）", kp: ["Taking exercise is essential = 運動することは不可欠（動名詞主語）", "動名詞主語 + is/was（三単現扱い）/ to V も可だが動名詞の方が口語的"] },
  { id: "g1421", diff: "lv3", axis: "form", tags: ["eiken2", "as_well_as"], stem: "The manager, ___ the team members, attended the meeting.", ja: "マネージャーは、チームメンバーとともに会議に出席した。", answer: "as well as", choices: ["as well as", "as much as", "as long as", "rather than", "not only"], expl: "as well as = 〜だけでなく〜も（接続表現）。The manager, as well as the team members, attended = 「チームメンバーだけでなくマネージャーも出席した」。動詞は先に来る主語（The manager）に一致（三単現 = attended）。as much as は程度（〜と同じくらい）。as long as は条件（〜する限り）。", rule: "A, as well as B, + V（Aに一致）：BだけでなくAも〜（追加の接続）", kp: ["as well as the team members = チームと共に（追加の意味）", "as well as：動詞はas well asより前の主語に一致する（not Bに一致）"] },
  { id: "g1422", diff: "lv3", axis: "form", tags: ["eiken2", "whom_objective_relative"], stem: "The professor ___ I admire most retired last year.", ja: "私が最も尊敬している教授は昨年退職した。", answer: "whom", choices: ["whom", "who", "which", "that", "whose"], expl: "目的格の関係代名詞 whom：先行詞（The professor）が関係詞節内で目的語の役割。I admire + whom（the professor）= 「私が尊敬している教授」。形式的な書き言葉では whom が正しいが、口語では who や that も使われる。whom の後に S + V が続き、節内で目的語が欠けている。", rule: "目的格関係代名詞 whom：〜を（先行詞が節内の目的語）", kp: ["The professor whom I admire = 私が尊敬している教授（目的格whom）", "whom（目的格・フォーマル）≒ who/that（口語）/ whose（所有格）"] },
  { id: "g1423", diff: "lv4", axis: "form", tags: ["eiken1", "were_to_subjunctive"], stem: "If the president ___ to resign, what would happen?", ja: "もし大統領が辞任するとしたら、何が起こるだろうか？", answer: "were", choices: ["were", "was", "is", "would", "had"], expl: "仮定法過去・were to 構文：If S were to + 動詞原形 = もし〜するとしたら（実現の可能性が低いまたは仮想の事態）。were to resign = 「辞任するとしたら」（実際にはそうではない仮定）。主語が三単現でも were to を使う（was to は非標準）。Should S + V 原形（If S should V の倒置）も類似表現。", rule: "If S were to + 動詞原形：もし〜するとしたら（仮定法過去・低可能性の仮定）", kp: ["If the president were to resign = 辞任するとしたら（were to構文）", "were to V（低可能性の仮定）/ should V（万が一）/ had pp（過去完了仮定法）"] },
  { id: "g1424", diff: "lv2", axis: "form", tags: ["eiken3", "present_perfect_passive"], stem: "The new library ___ recently.", ja: "新しい図書館は最近建設された。", answer: "has been built", choices: ["has been built", "has built", "was built", "is built", "had been built"], expl: "現在完了受動態：have/has + been + 過去分詞 = 〜されてきた（現在完了の受動）。has been built = 「建てられた（最近・現在との関連）」。was built は単純過去受動態（過去のある時点）。recently（最近）は現在完了と相性が良い（過去から現在へ続く状況の影響）。", rule: "has/have + been + 過去分詞：〜されてきた・〜された（現在完了受動態）", kp: ["has been built recently = 最近建てられた（現在完了受動態）", "現在完了受動態: have/has + been + pp（過去受動 was pp と区別）"] },
  { id: "g1425", diff: "lv4", axis: "form", tags: ["eiken1", "let_alone"], stem: "He can't speak French, ___ write it.", ja: "彼はフランス語を話すことすらできない。ましてや書くことなどもってのほかだ。", answer: "let alone", choices: ["let alone", "not to mention", "much less", "still less", "even if"], expl: "let alone = まして〜（さらに困難なことはいうまでもなく）。否定文 + let alone + さらに困難なこと。He can't speak French, let alone write it = 「フランス語を話せないのに、まして書けるはずがない」。much less / still less も同義（フォーマル）。not to mention は肯定文でも使える（〜は言うまでもなく）。", rule: "否定文 + let alone + V：まして〜なんてできない（さらに困難なことの否定）", kp: ["can't speak, let alone write = 話せないのにまして書けない（let alone）", "let alone（まして）= much less / still less（フォーマル）"] },
  { id: "g1426", diff: "lv3", axis: "form", tags: ["eiken2", "absolute_participle_construction"], stem: "___ from the top of the hill, the whole city looks beautiful.", ja: "丘の頂上から見ると、街全体が美しく見える。", answer: "Seen", choices: ["Seen", "Seeing", "To see", "Having seen", "Being seen"], expl: "独立分詞構文（意味上主語が主節と異なる場合）：Seen from the top of the hill = 「丘の頂上から見ると」（受動の分詞構文）。主節の主語は the whole city だが、「見られる」のは city 側なので過去分詞（受動）を使う。Seeing なら「丘から見ながら」（能動・人が見る）の意味になる。", rule: "過去分詞から始まる分詞構文（受動）：〜されると・〜から見ると", kp: ["Seen from the hill = 丘から見ると（受動の分詞構文）", "受動分詞構文: pp（過去分詞）で始まる / 能動: V-ing（現在分詞）で始まる"] },
  { id: "g1427", diff: "lv2", axis: "tense", tags: ["eiken3", "since_vs_for_present_perfect"], stem: "We have known each other ___ ten years.", ja: "私たちは10年間お互いを知っている（知り合いである）。", answer: "for", choices: ["for", "since", "during", "from", "while"], expl: "現在完了の継続：for + 期間（〜の間）、since + 過去の起点（〜のとき以来）。for ten years = 「10年間」（期間の長さを表す）。since 2014 = 「2014年以来」（時点を表す）。「10年間」は期間なので for。since の後は過去時点（since 2014 / since I was a child）または現在完了開始点が来る。", rule: "現在完了 + for + 期間（〜の間）vs since + 過去の起点（〜以来）", kp: ["for ten years = 10年間（期間の長さ）", "for（期間: for two hours/years）vs since（起点: since 2010/since I was young）"] },
  { id: "g1428", diff: "lv2", axis: "form", tags: ["eiken3", "present_participle_adjective"], stem: "The ___ child was taken to the hospital immediately.", ja: "その泣いている子供はすぐに病院に連れて行かれた。", answer: "crying", choices: ["crying", "cried", "cry", "to cry", "cries"], expl: "現在分詞の形容詞的用法：V-ing が名詞を修飾（能動・進行の意味）。crying child = 「泣いている子供」（子供が泣いている → 能動）。過去分詞（cried）は受動の意味（〜された）で使うが、cry は自動詞なので受動態にならない。動詞 cry の形容詞的用法は現在分詞 crying のみ。", rule: "現在分詞（V-ing）の形容詞的用法：名詞の前後で「〜している」（能動・進行）", kp: ["crying child = 泣いている子供（現在分詞が名詞を修飾）", "能動・進行 → V-ing / 受動・完了 → 過去分詞（pp）"] },
  { id: "g1429", diff: "lv3", axis: "tense", tags: ["eiken2", "past_perfect_sequence"], stem: "By the time she arrived, the meeting ___ already.", ja: "彼女が到着した頃には、会議はすでに始まっていた。", answer: "had already started", choices: ["had already started", "has already started", "already started", "was already starting", "would already start"], expl: "過去完了：had + 過去分詞 = 過去のある時点よりさらに前に起きた出来事。By the time she arrived（過去）→ その前に会議が始まった → had started。had already started = 「すでに始まっていた」（過去完了）。現在完了（has started）は過去の基準点と共起できない。", rule: "had + 過去分詞：過去の時点よりさらに前の出来事（過去完了）", kp: ["had already started = すでに始まっていた（過去完了）", "By the time S past-V, S had pp（過去完了：さらに前の出来事）"] },
  { id: "g1430", diff: "lv4", axis: "form", tags: ["eiken1", "cleft_sentence_it_was_that"], stem: "___ in 1969 that humans first landed on the moon.", ja: "人類が初めて月面に着陸したのは1969年のことだった。", answer: "It was", choices: ["It was", "There was", "It is", "That was", "What was"], expl: "強調構文：It is/was + 強調する要素 + that ... = 〜したのは…だ。It was in 1969 that ... = 「〜したのは1969年のことだった」（1969年を強調）。It is...that は現在、It was...that は過去の強調。There was は「〜があった」（存在）。That was は強調構文にならない。", rule: "It was + 強調要素 + that ~：〜したのは…だった（強調構文・過去）", kp: ["It was in 1969 that ~ = 〜したのは1969年だった（強調構文）", "It is/was + 強調要素 + that：人・物・時・場所・理由を強調できる"] },
  { id: "g1431", diff: "lv2", axis: "form", tags: ["eiken3", "comparative_more_than"], stem: "This problem is ___ difficult than I expected.", ja: "この問題は私が予想していたよりも難しい。", answer: "more", choices: ["more", "much", "most", "very", "too"], expl: "比較級の作り方：2音節以上の形容詞には more + 形容詞 + than を使う。difficult（3音節）→ more difficult than。much は比較級の強調（much more difficult）。most は最上級（the most difficult）。very は原級の強調（very difficult）。too は「〜すぎる」（too difficult to V）。", rule: "more + 形容詞（2音節以上）+ than：〜よりも…だ（比較級）", kp: ["more difficult than expected = 予想より難しい（more + 多音節形容詞）", "1音節: -er（harder）/ 2音節以上: more（more beautiful）"] },
  { id: "g1432", diff: "lv3", axis: "form", tags: ["eiken2", "sequence_of_tenses_reported_speech"], stem: "She told me that she ___ tired after the long journey.", ja: "彼女は長旅の後に疲れていると私に言った。", answer: "was", choices: ["was", "is", "has been", "will be", "had been"], expl: "時制の一致：主節が過去形（told）→ 従属節の動詞も過去形に後退。is → was（現在→過去）。She told me that she was tired = 「疲れていると言った」（時制の一致）。she is tired（直接話法の内容）→ 間接話法では she was tired。has been は完了（さらに前）、will be は未来（would be に後退）。", rule: "時制の一致：主節が過去形 → 従属節は一段階過去形に後退（is → was）", kp: ["told + that + was（時制の一致：is→was）", "主節過去 → 従属節: is→was, will→would, can→could, have→had"] },
  { id: "g1433", diff: "lv2", axis: "logic", tags: ["eiken3", "although_concession"], stem: "___ it was raining heavily, they continued the outdoor event.", ja: "激しく雨が降っていたにもかかわらず、彼らは屋外イベントを続けた。", answer: "Although", choices: ["Although", "Because", "Since", "Unless", "If"], expl: "逆接の接続詞：Although / Though / Even though = 〜にもかかわらず（逆接）。Although it was raining, they continued = 「雨にもかかわらず続けた」。Because / Since は理由・原因（〜なので）。Unless = 〜しない限り（条件）。If = もし〜なら（条件）。逆接は予想外の結果を示す。", rule: "Although/Though + S + V, S + V：〜にもかかわらず（逆接）", kp: ["Although it was raining, they continued = 雨でも続けた（逆接）", "逆接: although/though/even though / 理由: because/since"] },
  { id: "g1434", diff: "lv3", axis: "form", tags: ["eiken2", "too_to_infinitive"], stem: "The box was ___ heavy for me to carry alone.", ja: "その箱は重すぎて私一人では運べなかった。", answer: "too", choices: ["too", "so", "very", "such", "enough"], expl: "too...to 構文：too + 形容詞/副詞 + (for O) + to 不定詞 = 〜すぎて…できない（否定の意味を含む）。too heavy for me to carry = 「私には重すぎて運べない」。so...that は「とても〜なので〜だ」（結果節に that 節）。enough は十分（形容詞 + enough + to V = 〜するのに十分〜）。", rule: "too + 形容詞 + (for O) + to V：〜すぎて…できない（否定含意）", kp: ["too heavy for me to carry = 私には重すぎて運べない（too...to）", "too（〜すぎて）vs enough（十分に）/ too-to = so-that構文と意味対応"] },
  { id: "g1435", diff: "lv3", axis: "form", tags: ["eiken2", "participial_clause_active"], stem: "___ the instructions carefully, he assembled the furniture.", ja: "説明書をよく読んで、彼は家具を組み立てた。", answer: "Reading", choices: ["Reading", "Read", "Having read", "To read", "Being read"], expl: "分詞構文（能動・同時進行）：主節と同じ主語で、動詞を V-ing にする。Reading the instructions = 「説明書を読みながら」（主節と同時または直前の動作）。Having read は「読んでしまってから」（完了を強調）。過去分詞（Read）は受動の分詞構文（〜された状態で）。To read は目的（〜するために）。", rule: "V-ing で始まる分詞構文（能動）：〜しながら・〜して（時・理由・付帯状況）", kp: ["Reading the instructions, he assembled = 読んで組み立てた（分詞構文・能動）", "V-ing（能動・進行）/ Having pp（完了）/ pp（受動）/ Being pp（受動進行）"] },
  { id: "g1436", diff: "lv3", axis: "form", tags: ["eiken2", "past_subjunctive_if"], stem: "If I ___ more time, I would learn a new language.", ja: "もし時間がもっとあれば、新しい言語を学ぶのに。", answer: "had", choices: ["had", "have", "have had", "would have", "could have"], expl: "仮定法過去：If S + 過去形, S + would/could/might + 動詞原形 = 現在の事実に反する仮定。If I had more time = 「もし（今）時間があれば」（実際はない）。have は直説法（現実の条件）。have had は現在完了（現実）。would have + pp は仮定法過去完了の帰結節。仮定法では I/he でも were を使うことができる。", rule: "If S + 過去形, S + would V：現在の事実に反する仮定（仮定法過去）", kp: ["If I had more time = もし時間があれば（仮定法過去・現実にはない）", "仮定法過去: If S past-V, S would/could/might + V原形"] },
  { id: "g1437", diff: "lv2", axis: "form", tags: ["eiken3", "get_passive"], stem: "He ___ fined for parking illegally.", ja: "彼は違法駐車で罰金を科された。", answer: "got", choices: ["got", "was", "had", "became", "made"], expl: "get 受動態：get + 過去分詞 = 〜された（be 受動態と同義だが、動的・突発的な出来事に使われることが多い）。got fined = 「罰金を科された」（was fined と同義）。get 受動態は口語的・非公式な文体で頻出。became は自動詞（〜になった）。made + O + pp は使役（〜させた）。", rule: "get + 過去分詞：〜された（口語的な受動態・動的・突発的な出来事）", kp: ["got fined = 罰金を科された（get受動態）", "get pp（口語・動的）= be pp（標準・書き言葉）"] },
  { id: "g1438", diff: "lv2", axis: "logic", tags: ["eiken3", "between_vs_among"], stem: "The secret was shared only ___ the three of us.", ja: "その秘密は私たち3人の間だけで共有された。", answer: "among", choices: ["among", "between", "within", "with", "around"], expl: "between vs among：between は2者間（between A and B）、among は3者以上のグループ内（among the members）。the three of us = 3人なので among を使う。between は「2つの間」（between you and me）。within は「〜の範囲内」（within the company）。around は「〜の周り」（around the table）。", rule: "between（2者間）vs among（3者以上のグループ内）", kp: ["among the three of us = 私たち3人の間で（3者以上→among）", "between A and B（2者）vs among + 複数名詞/グループ（3者以上）"] },
  { id: "g1439", diff: "lv2", axis: "form", tags: ["eiken3", "definite_article_superlative"], stem: "She is ___ most talented singer in the competition.", ja: "彼女はそのコンテストで最も才能のある歌手だ。", answer: "the", choices: ["the", "a", "an", "most", "very"], expl: "最上級には定冠詞 the が必要：the + 最上級 + 名詞（+ in/of 句）。the most talented singer = 「最も才能のある歌手」（唯一性を表す the）。a は不定冠詞（特定しない）。very は原級強調（very talented）。最上級の前は必ず the（固有名詞・所有格のときは不要）。", rule: "the + 最上級 + 名詞：〜の中で最も…な（最上級には定冠詞 the が必要）", kp: ["the most talented singer = 最も才能ある歌手（最上級 + the）", "最上級 = the + 形容詞 -est / the most + 多音節形容詞"] },
  { id: "g1440", diff: "lv3", axis: "form", tags: ["eiken2", "relative_adverb_how"], stem: "Nobody knows ___ she managed to finish the project on time.", ja: "彼女がどうやってプロジェクトを期限内に終わらせたのか誰も知らない。", answer: "how", choices: ["how", "what", "which", "that", "where"], expl: "関係副詞・間接疑問詞 how：how + S + V = 「どのように〜したか」（方法・手段）。Nobody knows how she managed = 「どうやって終わらせたか誰も知らない」。what は物・こと（what she did）。which は選択（which one）。that は内容（that she finished）。where は場所（where she went）。", rule: "how + S + V：どのように〜するか（方法・手段の間接疑問）", kp: ["nobody knows how she managed = どうやったか知らない（how間接疑問）", "how（方法）/ what（物・こと）/ where（場所）/ when（時）/ why（理由）"] },
  { id: "g1441", diff: "lv2", axis: "logic", tags: ["eiken3", "must_obligation"], stem: "You ___ wear a seatbelt while driving. It's the law.", ja: "運転中はシートベルトを着用しなければならない。法律で定められている。", answer: "must", choices: ["must", "should", "may", "might", "would"], expl: "義務を表す助動詞：must = 話し手の強い義務・命令（主観的）。have to = 外部からの義務・規則（客観的）。It's the law（外部規則）とあっても must は強い義務・禁止に使われる。should は弱い義務・アドバイス（〜すべき）。may は許可（〜してよい）。might は弱い推量（〜かもしれない）。", rule: "must：話し手の強い義務・必要性（〜しなければならない）", kp: ["must wear = 着用しなければならない（強い義務）", "must（話し手の強制・義務）vs should（アドバイス）vs may（許可）"] },
  { id: "g1442", diff: "lv2", axis: "logic", tags: ["eiken3", "because_vs_because_of"], stem: "The flight was delayed ___ the heavy snowfall.", ja: "フライトは大雪のために遅延した。", answer: "because of", choices: ["because of", "because", "due", "since", "as"], expl: "because vs because of：because は接続詞（because + S + V）、because of は前置詞句（because of + 名詞）。the heavy snowfall は名詞句なので because of が正解。because the heavy snowfall は文法的に不可（because の後に節が必要）。due to も「〜のために」（due to + 名詞）。since / as は理由の接続詞（節が続く）。", rule: "because of + 名詞：〜のために（前置詞句）/ because + S + V（接続詞）", kp: ["because of the snowfall = 大雪のために（because of + 名詞）", "because（接続詞: + S+V）vs because of（前置詞: + 名詞）"] },
  { id: "g1443", diff: "lv3", axis: "form", tags: ["eiken2", "remember_gerund_vs_infinitive"], stem: "I remember ___ her at the conference last year.", ja: "昨年の会議で彼女に会ったことを覚えている。", answer: "meeting", choices: ["meeting", "to meet", "met", "to have met", "having met"], expl: "remember + 動名詞 vs 不定詞：remember + V-ing = 過去に〜したことを覚えている。remember + to V = 〜することを忘れずに覚えている（未来の行為）。last year（過去）の出来事を「覚えている」 → remember meeting（過去の記憶）。remember to meet = 「会うことを忘れずに覚えている」（これから会う）。having met も可だが meeting の方が一般的。", rule: "remember + V-ing：〜したことを覚えている（過去の記憶）vs remember + to V：〜することを忘れずに覚えている", kp: ["remember meeting her = 会ったことを覚えている（動名詞→過去の記憶）", "remember V-ing（過去経験の記憶）vs remember to V（これからすることを忘れない）"] },
  { id: "g1444", diff: "lv4", axis: "form", tags: ["eiken1", "proportional_comparison_the_more"], stem: "___ you practice, the better you become.", ja: "練習すればするほど、うまくなる。", answer: "The more", choices: ["The more", "More", "The most", "As more", "The much"], expl: "比例比較（the 比較級, the 比較級）：The more S V, the better S become = 「〜すればするほど、より…になる」。The more you practice = 「より多く練習するほど」（原因）。the better you become = 「よりうまくなる」（結果）。定冠詞 the が比較級の前に必要。More（定冠詞なし）は不可。as more は非文。", rule: "The + 比較級 S V, the + 比較級 S V：〜すればするほど、より…になる（比例比較）", kp: ["The more you practice, the better = 練習するほどうまくなる（比例比較）", "The 比較級, the 比較級：前節が原因・条件、後節が結果"] },
  { id: "g1445", diff: "lv3", axis: "form", tags: ["eiken2", "even_with_comparative"], stem: "This version is ___ better than the original.", ja: "このバージョンはオリジナルよりもさらに良い。", answer: "even", choices: ["even", "very", "so", "too", "much"], expl: "比較級の強調：even / much / far / still / a lot + 比較級 = さらに〜（比較級を強調）。even better = 「さらに良い」（予想を超えた比較）。very は原級の強調（very good）で比較級には使えない（× very better）。so は原級強調（so good）。too は「〜すぎる」（too good）。much better も可（much は比較級強調）。", rule: "even/much/far + 比較級：さらに〜（比較級の強調）", kp: ["even better than = さらに良い（even + 比較級で強調）", "比較級強調: even/much/far/still/a lot + 比較級 / very は原級のみ"] },
  { id: "g1446", diff: "lv3", axis: "logic", tags: ["eiken2", "not_until_cleft"], stem: "___ midnight that the party finally ended.", ja: "パーティーがようやく終わったのは深夜のことだった。", answer: "It was not until", choices: ["It was not until", "Not until", "It was until", "Until not", "Only when"], expl: "not until 強調構文：It was not until + 時間表現 + that S + V = 〜して初めて…した。It was not until midnight that the party ended = 「深夜になって初めてパーティーが終わった」。not until の倒置形（Not until midnight did the party end）も可。It was until は非文（notが必要）。Only when も可だが構文が異なる。", rule: "It was not until + 時間 + that S + V：〜して初めて…した（not untilの強調構文）", kp: ["It was not until midnight that ~ = 深夜になって初めて〜（not until強調）", "not until（〜して初めて）の強調: It was not until ~ that / 倒置: Not until ~ did S V"] },
  { id: "g1447", diff: "lv2", axis: "tense", tags: ["eiken3", "future_continuous"], stem: "This time tomorrow, I ___ on a plane to London.", ja: "明日の今頃、私はロンドンへの飛行機の中にいるだろう。", answer: "will be sitting", choices: ["will be sitting", "will sit", "am sitting", "will have sat", "would be sitting"], expl: "未来進行形：will + be + V-ing = 未来のある時点で〜している最中（未来の時点での進行中の動作）。This time tomorrow（明日の今頃）→ その時点で飛行機に乗っている最中 → will be sitting。will sit は単純未来（〜するだろう・意志）。will have sat は未来完了（その時点までに〜し終えているだろう）。", rule: "will be + V-ing：〜しているだろう（未来進行形・未来の時点での進行中の動作）", kp: ["will be sitting on a plane = 飛行機に乗っているだろう（未来進行形）", "未来進行形: will be V-ing（未来の時点での進行）/ 未来完了: will have pp"] },
  { id: "g1448", diff: "lv3", axis: "form", tags: ["eiken2", "passive_infinitive"], stem: "The report needs ___ before the deadline.", ja: "その報告書は締め切り前に提出される必要がある。", answer: "to be submitted", choices: ["to be submitted", "to submit", "submitting", "being submitted", "to have submitted"], expl: "need + 受動態不定詞：need to be + 過去分詞 = 〜される必要がある。The report needs to be submitted = 「報告書が提出される必要がある」（受動関係）。need to submit は主語が自ら提出する場合（能動）。need + V-ing（口語）も同義だが、to be submitted が標準的。", rule: "need to be + 過去分詞：〜される必要がある（受動態不定詞）", kp: ["needs to be submitted = 提出される必要がある（受動態不定詞）", "need to be pp（受動）vs need to V（能動）"] },
  { id: "g1449", diff: "lv2", axis: "logic", tags: ["eiken3", "between_vs_among"], stem: "The secret was kept ___ the three friends.", ja: "その秘密は3人の友人の間で守られた。", answer: "among", choices: ["among", "between", "within", "amid", "in"], expl: "between vs among：between = 2者間（between A and B）。among = 3者以上の集合の中（among + 複数名詞）。the three friends（3人）→ among を使う。between the three friends は非標準（3者以上はamong）。amid は「〜の最中に」（混乱・状況の中）。", rule: "among + 複数名詞：〜の間で（3者以上）vs between + 2者：2者間", kp: ["among the three friends = 3人の間で（among = 3者以上）", "between（2者）vs among（3者以上）"] },
  { id: "g1450", diff: "lv4", axis: "form", tags: ["eiken1", "cleft_sentence_what"], stem: "___ made the situation worse was his silence.", ja: "状況を悪化させたのは彼の沈黙だった。", answer: "What", choices: ["What", "That", "Which", "It", "How"], expl: "関係代名詞 what による名詞節：What + S + V = 〜するもの・こと。What made the situation worse = 「状況を悪化させたもの（こと）」が主語。was his silence = 「彼の沈黙だった」（補語）。That は接続詞・関係代名詞だが、先行詞なしで主語節は作れない。Which には先行詞が必要。", rule: "What + S + V + be + 名詞：〜するのは…だ（what節主語・強調）", kp: ["What made it worse = 悪化させたもの（what = 関係代名詞・名詞節）", "what節主語: What S V was/is + 補語"] },
  { id: "g1451", diff: "lv3", axis: "tense", tags: ["eiken2", "past_perfect_by_the_time"], stem: "By the time she arrived, he ___ already left.", ja: "彼女が到着した時には、彼はすでに出発していた。", answer: "had", choices: ["had", "has", "have", "was", "did"], expl: "過去完了（had + 過去分詞）：by the time + 過去形の節 → 主節は過去完了。By the time she arrived（過去）→ 到着前にすでに起きていた「出発」 → had already left。has は現在完了（現在との関連が必要）。was left は受動態。過去完了 = 過去の時点よりさらに前の出来事を示す。", rule: "by the time + 過去形, S + had + 過去分詞：〜した時にはすでに…していた（過去完了）", kp: ["by the time she arrived, he had left = 到着時にはすでに出発済み（過去完了）", "by the time（〜する頃には）+ 過去形 → 主節: had pp（過去完了）"] },
  { id: "g1452", diff: "lv2", axis: "logic", tags: ["eiken3", "so_adj_that"], stem: "The movie was ___ boring that I fell asleep.", ja: "その映画はとても退屈だったので私は眠ってしまった。", answer: "so", choices: ["so", "such", "too", "very", "quite"], expl: "so + 形容詞 + that = 非常に〜なので…（結果のso-that構文）。so boring that = 「非常に退屈なので」。such + a(n) + 形容詞 + 名詞 + that = 「非常に〜な…なので」（such a boring movie that）。too は「〜すぎて…できない」（too boring to enjoy）。very は結果節を伴わない単純強調。", rule: "so + 形容詞 + that S + V：非常に〜なので…（結果のso-that構文）", kp: ["so boring that I fell asleep = とても退屈で眠った（so + 形容詞 + that）", "so + adj + that（形容詞）vs such + a + adj + 名詞 + that（名詞句）"] },
  { id: "g1453", diff: "lv4", axis: "form", tags: ["eiken1", "inversion_negative_adverb_never"], stem: "___ had I seen such a beautiful sunset before.", ja: "それほど美しい夕焼けを私はそれまで一度も見たことがなかった。", answer: "Never", choices: ["Never", "Not", "Hardly", "Seldom", "No"], expl: "否定副詞倒置：Never / Hardly / Seldom などの否定副詞が文頭に来ると、主語と助動詞が倒置する。Never had I seen = 「私はそれまで一度も見たことがなかった」（過去完了の倒置）。通常語順: I had never seen such...。Hardly も倒置を引き起こすが、Hardly had I seen = 「〜するとすぐに」の意味になり文脈に合わない。", rule: "Never + had + S + 過去分詞：〜したことが一度もなかった（否定副詞による倒置）", kp: ["Never had I seen = 私は一度も見たことがなかった（Never + 助動詞倒置）", "否定副詞倒置: Never/Hardly/Seldom + 助動詞 + S + V"] },
  { id: "g1454", diff: "lv3", axis: "form", tags: ["eiken2", "gerund_after_preposition"], stem: "She succeeded in ___ the project on time.", ja: "彼女はプロジェクトを時間通りに完成させることに成功した。", answer: "completing", choices: ["completing", "complete", "to complete", "completed", "completion"], expl: "前置詞 + 動名詞：前置詞（in, at, for, on, by など）の後には動名詞（V-ing）が続く。succeed in + V-ing = 〜することに成功する。in completing = 「完成させることに」。in + to complete は不可（前置詞+不定詞は使えない）。succeed to = 「〜を引き継ぐ」（別の意味）。", rule: "succeed in + V-ing：〜することに成功する（前置詞 + 動名詞）", kp: ["succeeded in completing = 完成させることに成功した（in + 動名詞）", "前置詞 + V-ing（動名詞）/ 前置詞 + to V（不定詞）は不可"] },
  { id: "g1455", diff: "lv3", axis: "logic", tags: ["eiken2", "wish_past_regret"], stem: "I wish I ___ harder when I was young.", ja: "若い頃もっと一生懸命勉強しておけばよかった。", answer: "had studied", choices: ["had studied", "studied", "would study", "have studied", "study"], expl: "wish + 過去完了（仮定法過去完了）：過去の事実に反する後悔・願望を表す。I wish I had studied harder = 「もっと勉強しておけばよかった」（実際はしなかった→後悔）。wish + 過去形（仮定法過去）= 現在の事実に反する願望（I wish I were rich = 今お金持ちだったらなあ）。", rule: "I wish + S + had + 過去分詞：〜しておけばよかった（過去の後悔・仮定法過去完了）", kp: ["wish I had studied = 勉強しておけばよかった（仮定法過去完了・過去の後悔）", "wish + 過去完了（過去の後悔）vs wish + 過去形（現在の願望）"] },
  { id: "g1456", diff: "lv2", axis: "form", tags: ["eiken3", "modal_should_obligation"], stem: "You ___ return the book to the library by Friday.", ja: "あなたは金曜日までに図書館に本を返却すべきだ。", answer: "should", choices: ["should", "shall", "would", "could", "might"], expl: "should = 〜すべきだ（義務・助言）。You should return = 「あなたは返却すべきだ」（義務・推奨）。shall は1人称の未来や申し出（Shall I help?）。would は過去の習慣や仮定（would go = よく行ったものだ）。could は可能性・能力（could do = できる）。must も義務だが、should より強い义务感。", rule: "should + 動詞原形：〜すべきだ（義務・助言・推奨）", kp: ["should return = 返却すべきだ（義務・助言）", "should（義務・助言）vs must（強い義務）vs could（可能性）"] },
  { id: "g1457", diff: "lv4", axis: "form", tags: ["eiken1", "subjunctive_as_if"], stem: "He talks as if he ___ everything about the universe.", ja: "彼はまるで宇宙のことを何でも知っているかのように話す。", answer: "knew", choices: ["knew", "knows", "had known", "would know", "know"], expl: "as if + 仮定法過去：as if + 過去形 = 現在の事実に反する様子（〜であるかのように）。He talks（現在）→ as if he knew everything = 「まるで全てを知っているかのように」（実際は知らない）。as if + 過去完了 = 過去の事実に反する様子（as if he had known = 知っていたかのように）。knows（直説法）は「実際に知っている」の意味になる。", rule: "as if + 過去形：まるで〜であるかのように（仮定法過去・現在の非現実）", kp: ["as if he knew = まるで知っているかのように（仮定法過去）", "as if + 過去形（現在の非現実）vs as if + 過去完了（過去の非現実）"] },
  { id: "g1458", diff: "lv3", axis: "logic", tags: ["eiken2", "look_forward_to_gerund"], stem: "We are looking forward to ___ you at the conference.", ja: "会議でお会いできることを楽しみにしています。", answer: "seeing", choices: ["seeing", "see", "have seen", "be seen", "seen"], expl: "look forward to + 動名詞：look forward to の to は前置詞であり、不定詞の to ではない。to の後には動名詞（V-ing）が続く。look forward to seeing = 「会えることを楽しみにしている」。to see は不定詞のように見えるが、この to は前置詞なので不可。慣用表現として丸ごと覚える。", rule: "look forward to + V-ing：〜することを楽しみにする（to は前置詞）", kp: ["look forward to seeing = 会えることを楽しみに（to = 前置詞 → 動名詞）", "to の後: 前置詞 to → V-ing / 不定詞 to → 動詞原形"] },
  { id: "g1459", diff: "lv3", axis: "form", tags: ["eiken2", "have_difficulty_gerund"], stem: "She had difficulty ___ the complicated instructions.", ja: "彼女はその複雑な説明を理解するのに苦労した。", answer: "understanding", choices: ["understanding", "to understand", "understood", "understand", "in understanding"], expl: "have difficulty + V-ing：have difficulty（in）doing = 〜するのに苦労する。difficulty の後に動名詞が続く（in は省略可）。have difficulty understanding = 「理解するのに苦労する」。to understand は不定詞で不可（have difficulty to V は非標準）。have trouble / have a hard time も同様に動名詞を続ける。", rule: "have difficulty + V-ing：〜するのに苦労する（difficulty + 動名詞）", kp: ["had difficulty understanding = 理解するのに苦労した（difficulty + V-ing）", "have difficulty/trouble/a hard time + V-ing（苦労する表現）"] },
  { id: "g1460", diff: "lv2", axis: "logic", tags: ["eiken3", "preposition_on_day"], stem: "The meeting is scheduled ___ Monday morning.", ja: "会議は月曜日の朝に予定されている。", answer: "on", choices: ["on", "in", "at", "by", "for"], expl: "時間の前置詞：on = 特定の日・曜日・日付（on Monday, on March 5th）。in = 月・年・季節・時間帯（in April, in 2024, in the morning）。at = 時刻・特定の時点（at 9 o'clock, at noon）。on Monday morning = 「月曜日の朝に」（曜日+時間帯の組み合わせでも on を使う）。", rule: "on + 曜日/日付：〜曜日に（特定の日を示す前置詞 on）", kp: ["on Monday morning = 月曜日の朝に（on + 曜日）", "on（特定の日・曜日）/ in（月・年・季節）/ at（時刻）"] },
  { id: "g1461", diff: "lv3", axis: "form", tags: ["eiken2", "it_takes_time"], stem: "It ___ me three hours to finish the assignment.", ja: "その課題を終えるのに3時間かかった。", answer: "took", choices: ["took", "take", "has taken", "was taking", "takes"], expl: "It takes + 人 + 時間 + to V：〜するのに（人が）…の時間がかかる。過去の出来事 → 過去形 took。It took me three hours to finish = 「終えるのに3時間かかった」。takes は現在形（習慣・一般事実）。has taken は現在完了（過去から現在への継続）。過去の特定の出来事 → 単純過去 took。", rule: "It took + 人 + 時間 + to V：〜するのに（人が）…かかった（過去形）", kp: ["It took me three hours to finish = 終えるのに3時間かかった（It takes の過去形）", "It takes/took + 人 + 時間 + to V（時間がかかる表現）"] },
  { id: "g1462", diff: "lv4", axis: "form", tags: ["eiken1", "inversion_only_after"], stem: "Only after the meeting ended ___ he realize his mistake.", ja: "会議が終わった後でようやく彼は自分の間違いに気づいた。", answer: "did", choices: ["did", "has", "had", "was", "do"], expl: "Only after 倒置：Only + 副詞表現が文頭に来ると、主節で主語と助動詞が倒置する。Only after the meeting ended + 助動詞倒置 = did he realize（通常語順: he realized）。過去の出来事 → did + 動詞原形（do 倒置）。Only then, Only when, Only after, Only by など only + 副詞表現は倒置を引き起こす。", rule: "Only after + 節, did + S + V：〜した後でようやく…した（only + 副詞倒置）", kp: ["Only after... did he realize = ようやく気づいた（Only after 倒置）", "Only + 副詞表現 → 助動詞倒置: did/has/had + S + V"] },
  { id: "g1463", diff: "lv2", axis: "logic", tags: ["eiken3", "despite_contrast"], stem: "___ the heavy rain, they continued the outdoor event.", ja: "激しい雨にもかかわらず、彼らはアウトドアイベントを続けた。", answer: "Despite", choices: ["Despite", "Although", "However", "Because of", "Even so"], expl: "Despite（前置詞）vs Although（接続詞）：despite / in spite of + 名詞（句）= 〜にもかかわらず（前置詞）。although + S + V = 〜だけれども（接続詞・節が続く）。Despite the heavy rain（名詞句）→ despite が適切。Although the rain was heavy（節）→ although。However は副詞（文頭で「しかしながら」）。", rule: "Despite + 名詞（句）：〜にもかかわらず（前置詞・逆接）", kp: ["Despite the heavy rain = 激しい雨にもかかわらず（Despite + 名詞）", "despite/in spite of + 名詞（前置詞）vs although + S + V（接続詞）"] },
  { id: "g1464", diff: "lv3", axis: "form", tags: ["eiken2", "recommend_subjunctive"], stem: "The doctor recommended that he ___ more rest.", ja: "医師は彼がもっと休息をとるよう勧めた。", answer: "take", choices: ["take", "takes", "took", "should take", "would take"], expl: "提案・要求動詞 + that節（仮定法現在）：recommend / suggest / insist / demand + that + S + 動詞原形（仮定法現在）。recommended that he take = 「彼が休息をとるよう勧めた」（should take も可）。takes（三人称単数現在形）は不可（仮定法現在では原形を使う）。took（過去形）は不可。", rule: "recommend that + S + 動詞原形：〜するよう勧める（仮定法現在・提案動詞）", kp: ["recommended that he take = 休息をとるよう勧めた（仮定法現在・原形）", "recommend/suggest/insist/demand + that + S + 動詞原形（仮定法現在）"] },
  { id: "g1465", diff: "lv3", axis: "logic", tags: ["eiken2", "used_to_past_habit"], stem: "My grandfather ___ walk five miles to school every day.", ja: "私の祖父は毎日5マイル歩いて学校に通ったものだ。", answer: "used to", choices: ["used to", "is used to", "was used to", "would used to", "use to"], expl: "used to + 動詞原形：過去の習慣・状態（現在はもうしない）。My grandfather used to walk = 「祖父はかつて歩いて通ったものだ（今はしない）」。is used to + V-ing = 「〜することに慣れている」（現在の習慣・状態）。was used to + V-ing = 「〜することに慣れていた」（過去の習慣・状態）。would も過去の習慣を表すが、状態動詞には使えない。", rule: "used to + 動詞原形：かつて〜したものだ（過去の習慣・現在はしない）", kp: ["used to walk = かつて歩いて通ったものだ（過去の習慣）", "used to + 動詞原形（過去習慣）vs be used to + V-ing（〜に慣れている）"] },
  { id: "g1466", diff: "lv4", axis: "form", tags: ["eiken1", "complex_sentence_provided_that"], stem: "___ you meet the requirements, you will be considered for the position.", ja: "条件を満たしさえすれば、あなたはその職のご考慮の対象となります。", answer: "Provided that", choices: ["Provided that", "Despite", "Given that", "In case", "Even though"], expl: "Provided that = 〜という条件で・〜さえすれば（条件の接続詞）。Provided that you meet the requirements = 「条件を満たしさえすれば」（ifよりも形式的・法律・契約文書で多用）。Providing も同義で口語的。Given that = 「〜を考慮すると」（別の意味）。In case = 「〜に備えて」（予防）。Supposing = 「もし〜なら」（仮定）。", rule: "Provided that + S + V：〜という条件で・〜さえすれば（条件の接続詞・形式的）", kp: ["Provided that you meet = 条件を満たしさえすれば（Provided that = 条件）", "Provided that（形式的条件）≒ If / Providing（口語）/ Given that（〜を考慮すると）"] },
  { id: "g1467", diff: "lv3", axis: "form", tags: ["eiken2", "present_perfect_since"], stem: "He has lived in Tokyo ___ he was born.", ja: "彼は生まれてからずっと東京に住んでいる。", answer: "since", choices: ["since", "for", "during", "while", "until"], expl: "since vs for：since + 過去の時点・出来事 = 〜から（ずっと）。for + 期間 = 〜の間。He has lived since he was born = 「生まれて以来ずっと住んでいる」（since + 節）。for ten years = 「10年間」（for + 期間）。during は「〜の間に」（during + 名詞）。while は「〜している間」（while + S + V）。", rule: "since + 過去の時点：〜から（ずっと）（現在完了と共起）", kp: ["since he was born = 生まれてから（since + 節・出来事）", "since（〜から・過去の時点）vs for（〜の間・期間）"] },
);
DATA.push(
  { id: "g1488", diff: "lv2", axis: "tense", tags: ["eiken3", "present_perfect_yet"], stem: "Have you finished your homework ___?", ja: "もう宿題は終わりましたか？", answer: "yet", choices: ["yet", "already", "just", "still", "ever"], expl: "現在完了の疑問文・否定文では yet を使う。Have you finished ... yet? = 「もう終わりましたか？」（期待を込めた疑問）。already は肯定文に使う（I have already finished）。just は「ちょうど〜したばかり」（I have just finished）。still は継続（I still haven't finished）。ever は「かつて〜したことがあるか」（Have you ever been to...?）。", rule: "Have + S + pp + yet?：もう〜しましたか？（現在完了疑問文）", kp: ["yet = 疑問文・否定文（もう／まだ）", "already = 肯定文（もう・すでに）/ just = したばかり"] },
  { id: "g1489", diff: "lv2", axis: "form", tags: ["eiken3", "passive_voice_past"], stem: "This novel ___ by a famous Japanese author.", ja: "この小説は有名な日本人作家によって書かれた。", answer: "was written", choices: ["was written", "wrote", "has written", "is writing", "were written"], expl: "受動態の基本形：be動詞 + 過去分詞（+ by 行為者）。This novel（単数・過去）→ was written（was + 過去分詞）。wrote は能動態（The author wrote...）。has written は現在完了能動態。is writing は現在進行能動態。were written は複数主語（These novels were written）。", rule: "be動詞 + 過去分詞（+ by ...）：〜された（受動態・過去）", kp: ["was written = 書かれた（過去受動態：was + pp）", "能動態: S + wrote / 受動態: S + was written + by agent"] },
  { id: "g1490", diff: "lv3", axis: "form", tags: ["eiken2", "non_restrictive_which"], stem: "She passed the exam, ___ surprised everyone.", ja: "彼女は試験に合格した。それはみんなを驚かせた。", answer: "which", choices: ["which", "that", "what", "it", "this"], expl: "非制限用法（コンマ付き関係詞）：, which = 前の節全体や名詞を受けて補足情報を加える。She passed the exam, which surprised everyone = 「合格した。それがみんなを驚かせた」。非制限用法では that は使えない（, that は不可）。what は先行詞なしで節を作る。it・this は関係詞でないため節を繋げない。", rule: ", which + V：非制限用法（前の節全体を受けて補足情報を追加）", kp: [", which surprised everyone = それがみんなを驚かせた（非制限用法）", "非制限用法：, which（可）/ , that（不可）"] },
  { id: "g1491", diff: "lv3", axis: "form", tags: ["eiken2", "participial_clause_reason"], stem: "___ tired after the long flight, he went straight to bed.", ja: "長いフライトで疲れていたので、彼はすぐに寝た。", answer: "Feeling", choices: ["Feeling", "Felt", "Being felt", "Having felt", "To feel"], expl: "分詞構文（理由）：V-ing で始まる分詞構文は主節の主語と同じ主語を持ち、理由・同時動作を表す。Feeling tired = 「疲れていたので」（理由の分詞構文）。Felt は過去分詞で受動分詞構文の形。Being felt は意味が不自然。Having felt は完了分詞構文（主節より前の動作を強調）。To feel は目的の不定詞。", rule: "V-ing（分詞構文・理由）：〜なので（主節の主語と一致）", kp: ["Feeling tired = 疲れていたので（現在分詞・理由の分詞構文）", "As he felt tired → Feeling tired（接続詞省略の分詞構文）"] },
  { id: "g1492", diff: "lv3", axis: "form", tags: ["eiken2", "subjunctive_past_if"], stem: "If I ___ more time, I would learn another language.", ja: "もし時間がもっとあれば、もう一つ言語を学ぶのだが。", answer: "had", choices: ["had", "have", "would have", "will have", "had had"], expl: "仮定法過去：If S + 過去形, S + would + 原形（現在の事実に反する仮定）。If I had more time = 「もし時間があれば」（実際には時間がない）。have（直説法）は実際に時間がある場合。would have は帰結節で使う（would have + pp は仮定法過去完了の帰結）。had had は仮定法過去完了のif節（過去の反仮定）。", rule: "If S + 過去形, S + would + 原形：〜なら…するのに（仮定法過去）", kp: ["If I had more time = もし時間があれば（仮定法過去・現在反仮定）", "仮定法過去：If + 過去形 / 帰結：would + 原形"] },
  { id: "g1493", diff: "lv3", axis: "form", tags: ["eiken2", "seem_to_have_pp"], stem: "He ___ to have forgotten our appointment.", ja: "彼は私たちの約束を忘れてしまったようだ。", answer: "seems", choices: ["seems", "seemed", "is seeming", "looks", "appears"], expl: "seem to have + 過去分詞：現在から見た過去への推量。He seems to have forgotten = 「忘れてしまったようだ」（現在形 seems + 完了不定詞 to have pp）。seemed は過去形（過去の時点での推量）。is seeming は不可（seem は状態動詞・進行形にできない）。looks は look + 形容詞（looks tired）。appears も可だが seems が最も自然。", rule: "seem to have + pp：〜してしまったようだ（現在から見た過去の推量）", kp: ["seems to have forgotten = 忘れてしまったようだ（seem to have pp）", "seem to + 原形（現在推量）/ seem to have pp（過去の出来事推量）"] },
  { id: "g1494", diff: "lv3", axis: "logic", tags: ["eiken2", "despite_vs_although"], stem: "___ his lack of experience, he performed exceptionally well.", ja: "経験不足にもかかわらず、彼は非常によく活躍した。", answer: "Despite", choices: ["Despite", "Although", "Even though", "However", "Nevertheless"], expl: "despite + 名詞句（前置詞）vs although + S + V（接続詞）。his lack of experience は名詞句 → despite が適切。Although his lack of experience は文法的に誤り（although の後には S + V が必要）。However・Nevertheless は副詞で後に名詞句は取れない。Even though も接続詞なので後に名詞句は不可。", rule: "despite + 名詞(句)：〜にもかかわらず（前置詞・後に名詞句）", kp: ["Despite his lack of experience = 経験不足にもかかわらず（despite + 名詞句）", "despite + 名詞句（前置詞）/ although + S + V（接続詞）"] },
  { id: "g1495", diff: "lv3", axis: "modal", tags: ["eiken2", "should_have_done"], stem: "You ___ told me about the change in schedule earlier.", ja: "スケジュール変更についてもっと早く教えてくれればよかったのに。", answer: "should have", choices: ["should have", "must have", "could have", "would have", "ought to"], expl: "should have + 過去分詞：〜すべきだったのに（過去への後悔・非難）。You should have told me = 「教えてくれればよかったのに」（実際には教えてくれなかった）。must have pp = 〜したに違いない（過去の強い推量）。could have pp = 〜できたのに（過去の可能性）。would have pp = 〜しただろう（仮定法帰結）。ought to は現在の義務（ought to have pp なら should have pp と同義）。", rule: "should have + pp：〜すべきだったのに（過去の後悔・非難）", kp: ["should have told = 教えてくれればよかった（後悔・非難）", "should have pp（後悔）/ must have pp（過去推量）/ could have pp（過去の可能性）"] },
  { id: "g1496", diff: "lv2", axis: "form", tags: ["eiken3", "not_as_as_comparison"], stem: "This bag is not ___ that one.", ja: "このバッグはあのバッグほど高くない。", answer: "as expensive as", choices: ["as expensive as", "more expensive than", "so expensive that", "expensive as", "the most expensive"], expl: "否定の同等比較：not as + 形容詞 + as = 〜ほど…ない。This bag is not as expensive as that one = 「このバッグはあのバッグほど高くない」。more expensive than = 「〜より高い」（比較級・肯定）。so expensive that = 「とても高いので〜」（結果のso-that構文）。expensive as は不完全（as が1つ足りない）。the most expensive は最上級。", rule: "not as + 形容詞 + as：〜ほど…ない（否定の同等比較）", kp: ["not as expensive as = 〜ほど高くない（否定の同等比較）", "A is as 形容詞 as B（同等）/ A is not as 形容詞 as B（BのほうがA以上）"] },
  { id: "g1497", diff: "lv2", axis: "logic", tags: ["eiken3", "on_time_vs_in_time"], stem: "The train arrived ___ despite the heavy snow.", ja: "大雪にもかかわらず、電車は時間通りに到着した。", answer: "on time", choices: ["on time", "in time", "at time", "by time", "for time"], expl: "on time vs in time：on time = 時間通りに（予定・スケジュール通り）。in time = 間に合って（締め切り・期限に遅れずに）。The train arrived on time = 「電車が時間通りに到着した」（予定時刻通り）。in time は「ギリギリ間に合った」のニュアンスが強い。at time・by time・for time は慣用句として成立しない。", rule: "on time：時間通りに（予定・スケジュール通り）", kp: ["on time = 時間通り（スケジュール通り）", "in time = 間に合って（期限・締め切りに遅れずに）"] },
  { id: "g1498", diff: "lv3", axis: "form", tags: ["eiken2", "worth_doing"], stem: "This book is well ___ reading.", ja: "この本はぜひ読む価値がある。", answer: "worth", choices: ["worth", "worthy", "worthwhile", "deserving", "valuable"], expl: "be worth + 動名詞：〜する価値がある。This book is well worth reading = 「ぜひ読む価値がある」（worth + 動名詞・動名詞の意味上の目的語 = 主語 this book）。worthy は worthy of + 名詞・動名詞（worthy of reading）。worthwhile は it is worthwhile to V / worthwhile V-ing（形式主語構文が必要）。deserving は deserving of で使う。valuable = 価値がある（形容詞）は be 動詞+形容詞で使う。", rule: "be worth + 動名詞：〜する価値がある（動名詞の意味上目的語 = 主語）", kp: ["worth reading = 読む価値がある（worth + 動名詞）", "This book is worth reading = この本は読まれる価値がある（主語＝意味上の目的語）"] },
  { id: "g1499", diff: "lv4", axis: "form", tags: ["eiken1", "inversion_never_had"], stem: "___ I seen such a breathtaking view in my entire life.", ja: "生涯でこれほど息をのむような眺めを見たことがなかった。", answer: "Never had", choices: ["Never had", "Never have", "Had never", "Have never", "Not had"], expl: "否定副詞倒置（過去完了）：Never 等の否定副詞が文頭に来ると疑問文語順（倒置）になる。Never had I seen...（過去完了の倒置）。Never have I seen は現在完了の倒置（I have never seen → Never have I seen）。Had never・Have never は倒置なしの通常語順。Not had は否定副詞倒置の構造をなさない。", rule: "Never had + S + pp：〜したことがなかった（過去完了の否定副詞倒置）", kp: ["Never had I seen = 見たことがなかった（過去完了倒置）", "否定副詞倒置：Never + 助動詞 + S + V（疑問文語順）"] },
  { id: "g1500", diff: "lv3", axis: "form", tags: ["eiken2", "relative_adverb_where"], stem: "This is the town ___ I grew up.", ja: "ここは私が育った町だ。", answer: "where", choices: ["where", "which", "that", "when", "why"], expl: "関係副詞 where：場所を表す先行詞の後で使う。the town where I grew up = 「私が育った町」。which は関係代名詞（the town which I grew up では grew up の目的語が欠けて不完全）。in which も可だが選択肢にない。when は時の関係副詞（the day when...）。why は理由（the reason why...）。", rule: "場所の先行詞 + where + S + V：〜する場所（関係副詞）", kp: ["the town where I grew up = 私が育った町（関係副詞 where）", "where = in which（場所）/ when = at/on which（時）/ why = for which（理由）"] },
  { id: "g1501", diff: "lv3", axis: "form", tags: ["eiken2", "causative_get_pp"], stem: "I need to ___ my car repaired before the trip.", ja: "旅行の前に車を修理してもらう必要がある。", answer: "get", choices: ["get", "make", "let", "force", "do"], expl: "get + O + 過去分詞：〜してもらう（依頼・手配して実現）。get my car repaired = 「車を修理してもらう」。have + O + pp も同義（have my car repaired）。make + O + 原形は強制使役（make O do）。let + O + 原形は許可。force + O + to V は強制。do + O + pp は文法的に成立しない。", rule: "get + O + pp：〜してもらう（使役受動・依頼・手配）", kp: ["get my car repaired = 車を修理してもらう（get + O + 過去分詞）", "get + O + pp（努力して依頼）≈ have + O + pp（手配・指示）"] },
  { id: "g1502", diff: "lv3", axis: "form", tags: ["eiken2", "perception_verb_bare_infinitive"], stem: "I heard someone ___ my name in the crowd.", ja: "群衆の中で誰かが私の名前を呼ぶのが聞こえた。", answer: "call", choices: ["call", "to call", "called", "to calling", "calling"], expl: "知覚動詞 + O + 原形不定詞：hear・see・feel + O + 原形（動作全体を知覚）。I heard someone call = 「誰かが呼ぶのが聞こえた」（動作全体）。calling（現在分詞）も可だが「呼んでいる最中が聞こえた（進行中）」のニュアンス。to call は知覚動詞には使えない（to不定詞は目的・意図）。called は受動（someone called = 誰かが呼ばれた）。to calling は文法的に誤り。", rule: "hear + O + 原形：〜が…するのが聞こえた（知覚動詞 + O + 原形）", kp: ["heard someone call = 誰かが呼ぶのが聞こえた（hear + O + 原形）", "知覚動詞 + O + 原形（動作全体）/ + O + V-ing（進行中）"] },
  { id: "g1503", diff: "lv4", axis: "form", tags: ["eiken1", "subjunctive_past_perfect"], stem: "If they ___ earlier, they would have caught the last train.", ja: "もっと早く出発していれば、終電に乗れていたのに。", answer: "had left", choices: ["had left", "left", "would leave", "have left", "would have left"], expl: "仮定法過去完了：If S + had + pp, S + would have + pp（過去の事実に反する仮定）。If they had left earlier = 「もっと早く出発していれば」（実際には早く出発しなかった）。left（過去形）は仮定法過去のif節（現在反仮定）に使う。would leave は帰結節の仮定法過去形。have left は現在完了直説法。would have left は帰結節（would have pp）に使う。", rule: "If S + had + pp, S + would have + pp：〜していれば…できたのに（仮定法過去完了）", kp: ["If they had left = もっと早く出発していれば（仮定法過去完了・if節）", "仮定法過去完了：had + pp（if節）/ would have + pp（帰結節）"] },
  { id: "g1504", diff: "lv3", axis: "form", tags: ["eiken2", "superlative_ever"], stem: "This is the most delicious meal I have ___ tasted.", ja: "これは私が今まで食べた中で最もおいしい食事だ。", answer: "ever", choices: ["ever", "never", "already", "still", "yet"], expl: "最上級 + ever：the most ... + S + have ever + pp = 「今まで〜した中で最も…」。the most delicious meal I have ever tasted = 「今まで食べた中で最もおいしい食事」。never は否定（I have never tasted such a delicious meal）。already は肯定文の「もう・すでに」。yet は疑問文・否定文で使う。still は「まだ」（継続）。", rule: "the + 最上級 + S + have ever + pp：今まで〜した中で最も…", kp: ["the most delicious I have ever tasted = 今まで食べた中で最もおいしい", "最上級 + ever：経験の中での最高・最低を強調"] },
  { id: "g1505", diff: "lv3", axis: "logic", tags: ["eiken2", "not_only_but_also"], stem: "She is ___ talented but also hardworking.", ja: "彼女は才能があるだけでなく、勤勉でもある。", answer: "not only", choices: ["not only", "not just", "both", "either", "neither"], expl: "not only A but also B：AだけでなくBも（相関接続詞）。She is not only talented but also hardworking = 「才能があるだけでなく勤勉でもある」。not just は口語では使うが、公式の相関接続詞は not only...but also。both A and B は「AもBも」（but also とセットにならない）。either A or B は「AかBのどちらか」。neither A nor B は「AもBも〜ない」（否定）。", rule: "not only A but also B：AだけでなくBも（相関接続詞・追加強調）", kp: ["not only talented but also hardworking = 才能があるだけでなく勤勉でもある", "not only A but also B（追加強調）/ neither A nor B（二重否定）"] },
  { id: "g1506", diff: "lv4", axis: "logic", tags: ["eiken1", "by_means_of"], stem: "The expedition team crossed the desert ___ camels.", ja: "探検隊はラクダを使って砂漠を横断した。", answer: "by means of", choices: ["by means of", "by way of", "in terms of", "on behalf of", "in spite of"], expl: "by means of = 〜を使って・〜によって（手段）。by means of camels = 「ラクダを使って」。by way of = 〜を経由して（経路・方法）。in terms of = 〜の観点から（評価・分析の基準）。on behalf of = 〜の代わりに・〜を代表して。in spite of = 〜にもかかわらず（逆接）。", rule: "by means of + 名詞：〜を使って・〜によって（手段・方法）", kp: ["by means of camels = ラクダを使って（手段の by means of）", "by means of（手段）/ by way of（経路）/ in terms of（観点）"] },
  { id: "g1507", diff: "lv4", axis: "form", tags: ["eiken1", "perfect_participle_having_pp"], stem: "___ all the evidence, the detective announced his conclusion.", ja: "すべての証拠を調べ終えてから、探偵は結論を発表した。", answer: "Having examined", choices: ["Having examined", "Examining", "After examined", "Examined", "Being examined"], expl: "完了分詞構文：Having + pp = 主節の動作よりも前に完了した動作を表す。Having examined all the evidence = 「すべての証拠を調べ終えてから」（主節の announced より前に完了）。Examining は現在分詞（同時進行・理由）。After examined は誤り（after の後に過去分詞は不可）。Examined は受動分詞構文（Examined by...）。Being examined は受動進行分詞（調べられながら）。", rule: "Having + pp（完了分詞構文）：〜し終えてから（主節より前の完了動作）", kp: ["Having examined = 調べ終えてから（完了分詞構文：主節より前の動作）", "完了分詞構文：Having pp / 受動完了：Having been pp"] }
);
